    func test_customProviderAccessProfile_isStoredOnBootstrap() throws {
        let profile = ProviderAccessProfile.googleEntitled(membershipTier: .pro)
        let bootstrap = AppBootstrap(providerAccessProfile: profile)

        XCTAssertEqual(bootstrap.providerAccessProfile, profile)
        XCTAssertEqual(bootstrap.providerAccessProfile.preferredProvider, .googleMaps)
        XCTAssertEqual(
            bootstrap.providerAccessProfile.meteredProviderEntitlements,
            [.googleMaps]
        )
        XCTAssertEqual(bootstrap.providerQuotaSnapshot.allowedProviderFamilies, [.appleLocal, .cache])
        XCTAssertEqual(bootstrap.providerQuotaSnapshot.entitledProviderFamilies, [.googleMaps])
        XCTAssertTrue(bootstrap.providerQuotaSnapshot.meteredEligibleProviderFamilies.isEmpty)
        XCTAssertFalse(
            bootstrap.providerQuotaSnapshot.allowedProviderFamilies.contains(.googleMaps)
        )
    }

    func test_customProviderQuotaSnapshot_isStoredExactlyAndWinsOverProfileDefault() throws {
        let profile = ProviderAccessProfile.freeLocalDefault
        let quota = ServerProviderQuotaSnapshot(
            providerAccessProfile: ProviderAccessProfile.googleEntitled(membershipTier: .pro),
            allowedProviderFamilies: [.googleMaps],
            meteredEligibleProviderFamilies: [.googleMaps],
            disabledProviderFamilies: [.cache]
        )
        let bootstrap = AppBootstrap(
            providerAccessProfile: profile,
            providerQuotaSnapshot: quota
        )

        XCTAssertEqual(bootstrap.providerAccessProfile, profile)
        XCTAssertEqual(bootstrap.providerQuotaSnapshot, quota)
        XCTAssertEqual(bootstrap.providerQuotaSnapshot.allowedProviderFamilies, [.googleMaps])
        XCTAssertEqual(bootstrap.providerQuotaSnapshot.entitledProviderFamilies, [.googleMaps])
        XCTAssertEqual(bootstrap.providerQuotaSnapshot.meteredEligibleProviderFamilies, [.googleMaps])
        XCTAssertEqual(bootstrap.providerQuotaSnapshot.disabledProviderFamilies, [.cache])
    }

    func test_providerAccessProfile_survivesAlongsideOtherBootstrapInjection() throws {
        let profile = ProviderAccessProfile(
            membershipTier: .developerInternal,
            defaultRegion: .china,
            preferredProvider: .searchAPI,
            meteredProviderEntitlements: [.searchAPI],
            enabledExperimentalProviders: [.crawler]
        )
        let quota = ServerProviderQuotaSnapshot(
            providerAccessProfile: profile,
            allowedProviderFamilies: [.searchAPI],
            meteredEligibleProviderFamilies: [.searchAPI]
        )
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [RecommendationFixtures.routeBay]
        )
        let statusProvider = SpyProviderStatusProviderForBootstrap()
        let registry = CapabilityRegistry()
        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            capabilityRegistry: registry,
            providerAccessProfile: profile,
            providerQuotaSnapshot: quota,
            providerStatusProvider: statusProvider
        )

        XCTAssertEqual(bootstrap.providerAccessProfile, profile)
        XCTAssertEqual(bootstrap.providerQuotaSnapshot, quota)
        XCTAssertTrue(
            bootstrap.recommendationProvider as? SpyRecommendationProviderForBootstrap
                === recommendationProvider
        )
        XCTAssertTrue(bootstrap.capabilityRegistry === registry)
        XCTAssertTrue(
            bootstrap.providerStatusProvider as? SpyProviderStatusProviderForBootstrap
                === statusProvider
        )
    }

