    func test_directProviderStatusSourcePreservesIdentityWhenSourcesAreAlsoPassed() throws {
        let direct = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                RecommendationFixtures.placeRoute.id: providerStatusPresentation(
                    for: RecommendationFixtures.placeRoute.id,
                    statusLine: "Direct provider status source selected."
                ),
            ]
        )
        let fallback = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                RecommendationFixtures.placeRoute.id: providerStatusPresentation(
                    for: RecommendationFixtures.placeRoute.id,
                    statusLine: "Fallback provider status source selected."
                ),
            ]
        )
        let bootstrap = AppBootstrap(
            providerStatusProvider: direct,
            providerStatusSources: [fallback]
        )

        XCTAssertTrue(
            bootstrap.providerStatusProvider as? SpyProviderStatusProviderForBootstrap === direct
        )
        XCTAssertTrue(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: RecommendationFixtures.placeRoute.id)?
                .statusLine
                .contains("Direct provider status source") == true
        )
    }

    func test_providerStatusSources_composeFirstSourceWins() throws {
        let recommendationID = RecommendationFixtures.placeRoute.id
        let first = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                recommendationID: providerStatusPresentation(
                    for: recommendationID,
                    statusLine: "First app-root status source selected.",
                    cardHint: .warning
                ),
            ]
        )
        let second = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                recommendationID: providerStatusPresentation(
                    for: recommendationID,
                    statusLine: "Second app-root status source selected.",
                    cardHint: .disabled
                ),
            ]
        )
        let bootstrap = AppBootstrap(providerStatusSources: [first, second])

        let presentation = try XCTUnwrap(
            bootstrap.providerStatusProvider?.providerStatusPresentation(for: recommendationID)
        )

        XCTAssertEqual(presentation.cardHint, .warning)
        XCTAssertTrue(presentation.statusLine.contains("First app-root status source"))
        XCTAssertFalse(presentation.statusLine.contains("Second app-root status source"))
    }

    func test_providerStatusSources_fallBackWhenEarlierSourceMisses() throws {
        let recommendationID = RecommendationFixtures.placeRoute.id
        let empty = SpyProviderStatusProviderForBootstrap()
        let fallback = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                recommendationID: providerStatusPresentation(
                    for: recommendationID,
                    statusLine: "Fallback app-root status source selected.",
                    cardHint: .disabled
                ),
            ]
        )
        let bootstrap = AppBootstrap(providerStatusSources: [empty, fallback])

        let presentation = try XCTUnwrap(
            bootstrap.providerStatusProvider?.providerStatusPresentation(for: recommendationID)
        )

        XCTAssertEqual(presentation.cardHint, .disabled)
        XCTAssertTrue(presentation.statusLine.contains("Fallback app-root status source"))
    }

    func test_providerStatusSources_acceptPrecomputedPipelineReceiptStore() throws {
        let recommendationID = RecommendationFixtures.placeRoute.id
        let receiptStore = RuntimeReceiptProviderStatusStore(
            receiptsByRecommendationID: [
                recommendationID: pipelineSearchReceipt(
                    traceID: "bootstrap-pipeline-status"
                ),
            ]
        )
        let bootstrap = AppBootstrap(providerStatusSources: [receiptStore])

        let presentation = try XCTUnwrap(
            bootstrap.providerStatusProvider?.providerStatusPresentation(for: recommendationID)
        )

        XCTAssertEqual(presentation.recommendationID, recommendationID)
        XCTAssertEqual(presentation.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: presentation)?.tone, .neutral)
