    func test_compositionRoot_chatStoreReadsProducerBuiltRuntimeStatusForRenderedRecommendationOnly() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let hiddenRecommendationID = "producer-built-runtime-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let producer = ServerProviderRuntimeStatusSourceProducer()
        let producerBuiltSource = producer.statusSource(
            readinessDecisions: [
                .init(
                    recommendationID: renderedObject.id,
                    readinessDecision: runtimeSearchReadinessDecision(
                        traceID: "producer-built-runtime-rendered",
                        sourceHost: "producer-runtime-rendered.example.com"
                    )
                ),
                .init(
                    recommendationID: hiddenRecommendationID,
                    readinessDecision: runtimeSearchReadinessDecision(
                        traceID: "producer-built-runtime-hidden",
                        sourceHost: "producer-runtime-hidden.example.com"
                    )
                ),
            ],
            adapterSet: ServerProviderRuntimeAdapterSet(
                adapters: [
                    SourceMarkingServerProviderRuntimeAdapterForBootstrap(
                        providerFamily: .searchAPI,
                        marker: "producer-runtime-injected.example.com"
                    ),
                ]
            )
        )
        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [producerBuiltSource]
        )

        let bootstrapRendered = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let bootstrapHidden = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )

        // Mirror what `ChatHomeView.init(bootstrap:)` does.
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let rendered = try XCTUnwrap(
            store.providerStatusPresentation(for: renderedObject.id)
        )
        let text = ([rendered.statusLine] + rendered.badges.map(\.label))
            .joined(separator: "\n")
            .lowercased()

        XCTAssertEqual(store.recommendedMatches, [renderedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(bootstrapRendered.recommendationID, renderedObject.id)
        XCTAssertEqual(bootstrapHidden.recommendationID, hiddenRecommendationID)
        XCTAssertEqual(rendered.recommendationID, renderedObject.id)
        XCTAssertEqual(rendered.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: rendered)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: rendered)?.tone, .neutral)
        XCTAssertTrue(rendered.statusLine.contains("Runtime receipt"))
        XCTAssertTrue(rendered.statusLine.contains("producer-runtime-injected.example.com"))
        XCTAssertFalse(rendered.statusLine.contains("producer-runtime-rendered.example.com"))
        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "producer-built-runtime-missing"))
        XCTAssertTrue(text.contains("no provider runtime has run"))
        for forbidden in [
            "completed",
            "complete",
            "done",
            "called",
            "contacted",
            "fetched",
            "invoked",
            "booked",
            "booking",
            "ordered",
            "ordering",
            "paid",
            "payment",
            "purchased",
            "crawled",
            "crawling",
        ] {
            XCTAssertFalse(text.contains(forbidden), "Unexpected wording: \(forbidden)")
        }
    }

    func test_compositionRoot_producerBuiltRuntimeStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
