                    cardHint: .disabled
                ),
            ]
        )
        let producerFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [producerBuiltSource, fallback]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
