        XCTAssertTrue(rendered.statusLine.contains("guarded-runtime-injected.example.com"))
        XCTAssertFalse(rendered.statusLine.contains("guarded-runtime-rendered.example.com"))
        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "guarded-runtime-missing"))
        XCTAssertTrue(text.contains("runtime receipt"))
        XCTAssertTrue(text.contains("no provider runtime has run"))
        for forbidden in [
            "completed",
            "complete",
            "done",
            "called",
            "contacted",
            "fetched",
            "invoked",
            "booked",
            "booking",
            "ordered",
            "ordering",
            "paid",
            "payment",
            "purchased",
            "crawled",
            "crawling",
        ] {
            XCTAssertFalse(text.contains(forbidden), "Unexpected wording: \(forbidden)")
        }
    }

