    func test_compositionRoot_authorizedGuardedRuntimeStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let producer = ServerProviderRuntimeStatusSourceProducer()
        let producerBuiltSource = producer.statusSource(
            readinessDecisions: [
                .init(
                    recommendationID: renderedObject.id,
                    readinessDecision: runtimeSearchReadinessDecision(
                        traceID: "authorized-guarded-runtime-source-order",
                        sourceHost: "authorized-runtime-source-order.example.com"
                    )
                ),
            ],
            adapterSet: ServerProviderRuntimeAdapterSet(
                adapters: [
                    SourceMarkingServerProviderRuntimeAdapterForBootstrap(
                        providerFamily: .searchAPI,
                        marker: "authorized-runtime-source-order-injected.example.com"
                    ),
                ]
            ),
            validation: adapterSetValidation(
                state: .accepted,
                registered: [.searchAPI],
                accepted: [.searchAPI]
            )
        )
        let guardedSource = ServerProviderRenderedRuntimeStatusSource(
            source: producerBuiltSource,
            renderedRecommendationIDs: [renderedObject.id]
        )
        let fallback = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    statusLine: "Fallback app-root status source selected.",
                    cardHint: .disabled
                ),
            ]
        )
        let guardedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [guardedSource, fallback]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallback, guardedSource]
        )

        let guardedFirstStore = ChatStore(
            recommendationProvider: guardedFirst.recommendationProvider,
            providerStatusProvider: guardedFirst.providerStatusProvider,
            feedbackRuntime: guardedFirst.feedbackRuntime,
            completedRecommendationHandoff: guardedFirst.completedRecommendationHandoff,
            telemetryEmitter: guardedFirst.telemetryEmitter,
            capabilityRegistry: guardedFirst.capabilityRegistry
        )
        let fallbackFirstStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let guardedFirstStatus = try XCTUnwrap(
            guardedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackFirstStatus = try XCTUnwrap(
            fallbackFirstStore.providerStatusPresentation(for: renderedObject.id)
        )

        XCTAssertEqual(guardedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(guardedFirstStatus.cardHint, .warning)
        XCTAssertTrue(guardedFirstStatus.statusLine.contains("Runtime receipt"))
        XCTAssertTrue(
            guardedFirstStatus.statusLine
                .contains("authorized-runtime-source-order-injected.example.com")
        )
        XCTAssertFalse(guardedFirstStatus.statusLine.contains("Fallback app-root"))
        XCTAssertEqual(fallbackFirstStatus.cardHint, .disabled)
        XCTAssertTrue(fallbackFirstStatus.statusLine.contains("Fallback app-root"))
        XCTAssertFalse(fallbackFirstStatus.statusLine.contains("Runtime receipt"))
    }

