    func test_compositionRoot_chatStoreReadsConnectorReceiptStatusForRenderedRecommendationOnly() throws {
        let selectedObject = RecommendationFixtures.placeRoute
        let rejectedObject = RecommendationFixtures.searchResult
        let hiddenRecommendationID = "connector-receipt-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [selectedObject, rejectedObject]
        )
        let producer = ServerProviderRuntimeConnectorStatusSourceProducer()
        let connectorSource = producer.statusSource(
            receipts: [
                .init(
                    recommendationID: selectedObject.id,
                    receipt: connectorAcceptedReceipt(
                        providerFamily: .searchAPI,
                        capability: .webSearch,
                        costClass: .meteredPremium,
                        freshness: .liveRequired
                    )
                ),
                .init(
                    recommendationID: rejectedObject.id,
                    receipt: connectorRejectedReceipt(
                        invocationRejection: .connectorRejected,
                        connectorRejection: .connectorProviderFamilyMismatch,
                        connectorProviderFamily: .googleMaps
                    )
                ),
                .init(
                    recommendationID: hiddenRecommendationID,
                    receipt: connectorAcceptedReceipt(
                        providerFamily: .gaode,
                        capability: .localServiceSearch,
                        costClass: .includedQuota,
                        freshness: .livePreferred
                    )
                ),
            ],
            renderedRecommendationIDs: [selectedObject.id, rejectedObject.id]
        )
        let preBootstrapSelected = try XCTUnwrap(
            connectorSource.providerStatusPresentation(for: selectedObject.id)
        )
        let preBootstrapRejected = try XCTUnwrap(
            connectorSource.providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(connectorSource.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(connectorSource.providerStatusPresentation(for: "connector-receipt-missing"))

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [connectorSource]
        )
        let bootstrapSelected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: selectedObject.id)
        )
        let bootstrapRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let selected = try XCTUnwrap(
            store.providerStatusPresentation(for: selectedObject.id)
        )
        let rejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )

        XCTAssertEqual(
            connectorSource.renderedRecommendationIDs,
            [selectedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertEqual(store.recommendedMatches, [selectedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapSelected.recommendationID, selectedObject.id)
        XCTAssertEqual(preBootstrapRejected.recommendationID, rejectedObject.id)
        XCTAssertEqual(bootstrapSelected.recommendationID, selectedObject.id)
        XCTAssertEqual(bootstrapRejected.recommendationID, rejectedObject.id)
        XCTAssertEqual(selected.recommendationID, selectedObject.id)
        XCTAssertEqual(selected.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: selected)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: selected)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: selected)?.tone, .positive)
        XCTAssertTrue(selected.statusLine.contains("Connector receipt"))
        XCTAssertTrue(selected.statusLine.contains("Provider family: searchAPI"))
        XCTAssertTrue(selected.statusLine.contains("Cost: meteredPremium"))
        XCTAssertTrue(selected.statusLine.contains("Freshness: liveRequired"))
        XCTAssertTrue(selected.statusLine.contains("No provider runtime has run"))
        XCTAssertEqual(rejected.recommendationID, rejectedObject.id)
        XCTAssertEqual(rejected.cardHint, .disabled)
        XCTAssertEqual(badge(.unavailable, in: rejected)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: rejected))
        XCTAssertTrue(rejected.statusLine.contains("Connector receipt is unavailable"))
        XCTAssertTrue(rejected.statusLine.contains("connectorProviderFamilyMismatch"))
        XCTAssertFalse(rejected.statusLine.localizedCaseInsensitiveContains("googlemaps"))
        XCTAssertFalse(rejected.statusLine.localizedCaseInsensitiveContains("manifest"))
        XCTAssertFalse(rejected.statusLine.localizedCaseInsensitiveContains("authorization"))
        XCTAssertFalse(rejected.statusLine.localizedCaseInsensitiveContains("trace"))
        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "connector-receipt-missing"))
    }

