        )
        XCTAssertNil(connectorSource.providerStatusPresentation(for: hiddenRecommendationID))

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [connectorSource]
        )
        let bootstrapSelected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: selectedObject.id)
        )
        let bootstrapRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(
