            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let text = [
            preBootstrapSelected,
            preBootstrapRejected,
            bootstrapSelected,
            bootstrapRejected,
            storeSelected,
            storeRejected,
        ]
            .flatMap { [$0.statusLine] + $0.badges.map(\.label) }
            .joined(separator: "\n")
            .lowercased()

        XCTAssertEqual(store.recommendedMatches, [selectedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertTrue(text.contains("metadata only"))
        XCTAssertTrue(text.contains("no provider runtime has run"))
        XCTAssertTrue(text.contains("planningrejected"))
        for forbidden in connectorStatusForbiddenFragments() + runtimeAdvisoryForbiddenFragments() {
            XCTAssertFalse(text.contains(forbidden), "Unexpected connector status wording: \(forbidden)")
        }
    }

    func test_compositionRoot_chatStoreReadsSearchAPIAdapterStatusForRenderedRecommendationOnly() throws {
