            traceID: "a88-search-api-rejected-result",
            sourceHost: "citation.example.com"
        )
        let adapterSource = SearchAPIAdapterProviderStatusStore(
            values: [
                (recommendationID: preparedObject.id, value: .requestDecision(preparedDecision)),
                (recommendationID: normalizedObject.id, value: .resultReceipt(normalizedReceipt)),
                (
                    recommendationID: rejectedRequestObject.id,
                    value: .requestDecision(rejectedRequestDecision)
                ),
                (
                    recommendationID: rejectedResultObject.id,
                    value: .resultReceipt(rejectedResultReceipt)
                ),
            ]
