        )
        let hiddenDecision = try searchAPIAdapterPreparedRequestDecision(
            traceID: "a90-search-api-hidden",
            sourceHost: "producer-hidden.example.com"
        )
        let producerSource = ServerProviderSearchAPIAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .requestDecision(
                        .init(
                            recommendationID: preparedObject.id,
                            decision: preparedDecision
                        )
                    ),
                    .resultReceipt(
                        .init(
                            recommendationID: normalizedObject.id,
                            receipt: normalizedReceipt
                        )
                    ),
                    .requestDecision(
                        .init(
                            recommendationID: rejectedRequestObject.id,
                            decision: rejectedRequestDecision
                        )
                    ),
                    .resultReceipt(
                        .init(
                            recommendationID: rejectedResultObject.id,
                            receipt: rejectedResultReceipt
                        )
                    ),
                    .requestDecision(
                        .init(
                            recommendationID: hiddenRecommendationID,
                            decision: hiddenDecision
                        )
                    ),
                ],
                renderedRecommendationIDs: [
                    preparedObject.id,
                    normalizedObject.id,
                    rejectedRequestObject.id,
                    rejectedResultObject.id,
                ]
            )

        XCTAssertEqual(rejectedRequestDecision.state, .rejected)
        XCTAssertEqual(rejectedRequestDecision.rejection, .privacyBlocked)
        XCTAssertNil(producerSource.providerStatusPresentation(for: hiddenRecommendationID))
        let preBootstrapPrepared = try XCTUnwrap(
            producerSource.providerStatusPresentation(for: preparedObject.id)
        )
        let preBootstrapNormalized = try XCTUnwrap(
            producerSource.providerStatusPresentation(for: normalizedObject.id)
        )
        let preBootstrapRejectedRequest = try XCTUnwrap(
            producerSource.providerStatusPresentation(for: rejectedRequestObject.id)
        )
        let preBootstrapRejectedResult = try XCTUnwrap(
            producerSource.providerStatusPresentation(for: rejectedResultObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [producerSource]
        )
        let bootstrapPrepared = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: preparedObject.id)
        )
        let bootstrapNormalized = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: normalizedObject.id)
        )
        let bootstrapRejectedRequest = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedRequestObject.id)
        )
        let bootstrapRejectedResult = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedResultObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storePrepared = try XCTUnwrap(
            store.providerStatusPresentation(for: preparedObject.id)
        )
        let storeNormalized = try XCTUnwrap(
            store.providerStatusPresentation(for: normalizedObject.id)
        )
        let storeRejectedRequest = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedRequestObject.id)
        )
        let storeRejectedResult = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedResultObject.id)
        )
        let statusText = [
            preBootstrapPrepared,
            preBootstrapNormalized,
            preBootstrapRejectedRequest,
            preBootstrapRejectedResult,
            bootstrapPrepared,
            bootstrapNormalized,
            bootstrapRejectedRequest,
            bootstrapRejectedResult,
            storePrepared,
            storeNormalized,
            storeRejectedRequest,
            storeRejectedResult,
        ]
            .flatMap { [$0.statusLine] + $0.badges.map(\.label) }
            .joined(separator: "\n")
            .lowercased()

        XCTAssertEqual(
            producerSource.renderedRecommendationIDs,
            [
                normalizedObject.id,
                preparedObject.id,
                rejectedRequestObject.id,
                rejectedResultObject.id,
            ].sorted()
        )
        XCTAssertEqual(
            store.recommendedMatches,
            [preparedObject, normalizedObject, rejectedRequestObject, rejectedResultObject]
        )
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapPrepared.recommendationID, preparedObject.id)
        XCTAssertEqual(bootstrapPrepared.recommendationID, preparedObject.id)
        XCTAssertEqual(storePrepared.recommendationID, preparedObject.id)
        XCTAssertEqual(storePrepared.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storePrepared)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storePrepared)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storePrepared)?.tone, .positive)
        XCTAssertTrue(storePrepared.statusLine.contains("Search API adapter request"))
        XCTAssertTrue(storePrepared.statusLine.contains("producer-prepared.example.com"))

        XCTAssertEqual(preBootstrapNormalized.recommendationID, normalizedObject.id)
        XCTAssertEqual(bootstrapNormalized.recommendationID, normalizedObject.id)
        XCTAssertEqual(storeNormalized.recommendationID, normalizedObject.id)
        XCTAssertEqual(storeNormalized.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeNormalized)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeNormalized)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeNormalized)?.tone, .positive)
        XCTAssertTrue(storeNormalized.statusLine.contains("normalized from cited metadata"))
        XCTAssertTrue(storeNormalized.statusLine.contains("producer-normalized.example.com"))

        XCTAssertEqual(preBootstrapRejectedRequest.recommendationID, rejectedRequestObject.id)
        XCTAssertEqual(bootstrapRejectedRequest.recommendationID, rejectedRequestObject.id)
        XCTAssertEqual(storeRejectedRequest.recommendationID, rejectedRequestObject.id)
        XCTAssertEqual(storeRejectedRequest.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storeRejectedRequest)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeRejectedRequest))
        XCTAssertNil(badge(.meteredPremium, in: storeRejectedRequest))
        XCTAssertTrue(storeRejectedRequest.statusLine.contains("privacyBlocked"))

        XCTAssertEqual(preBootstrapRejectedResult.recommendationID, rejectedResultObject.id)
        XCTAssertEqual(bootstrapRejectedResult.recommendationID, rejectedResultObject.id)
        XCTAssertEqual(storeRejectedResult.recommendationID, rejectedResultObject.id)
        XCTAssertEqual(storeRejectedResult.cardHint, .disabled)
        XCTAssertEqual(badge(.termsBlocked, in: storeRejectedResult)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeRejectedResult))
        XCTAssertNil(badge(.meteredPremium, in: storeRejectedResult))
        XCTAssertTrue(storeRejectedResult.statusLine.contains("resultCitationMissing"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "producer-search-api-adapter-missing"))
        XCTAssertTrue(statusText.contains("metadata only"))
        XCTAssertTrue(statusText.contains("no provider runtime has run"))
        for forbidden in searchAPIAdapterStatusForbiddenFragments() {
            XCTAssertFalse(forbidden.isEmpty)
            XCTAssertFalse(
                statusText.contains(forbidden),
                "Unexpected Search API adapter producer status wording: \(forbidden)"
            )
        }
    }

    func test_compositionRoot_producerBuiltSearchAPIAdapterStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let producerSource = ServerProviderSearchAPIAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .requestDecision(
                        .init(
                            recommendationID: renderedObject.id,
                            decision: try searchAPIAdapterPreparedRequestDecision(
                                traceID: "a90-search-api-source-order",
                                sourceHost: "producer-source-order.example.com",
                                costClass: .includedQuota,
                                freshness: .cachedOK
                            )
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallback = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    statusLine: "Fallback app-root status source selected.",
                    cardHint: .disabled
                ),
            ]
        )
        let producerFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [producerSource, fallback]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallback, producerSource]
        )

        let producerFirstStore = ChatStore(
            recommendationProvider: producerFirst.recommendationProvider,
            providerStatusProvider: producerFirst.providerStatusProvider,
            feedbackRuntime: producerFirst.feedbackRuntime,
            completedRecommendationHandoff: producerFirst.completedRecommendationHandoff,
            telemetryEmitter: producerFirst.telemetryEmitter,
            capabilityRegistry: producerFirst.capabilityRegistry
        )
        let fallbackFirstStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let producerFirstStatus = try XCTUnwrap(
            producerFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackFirstStatus = try XCTUnwrap(
            fallbackFirstStore.providerStatusPresentation(for: renderedObject.id)
        )

        XCTAssertEqual(producerFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(producerFirstStatus.cardHint, .normal)
        XCTAssertEqual(badge(.includedQuota, in: producerFirstStatus)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: producerFirstStatus))
        XCTAssertTrue(producerFirstStatus.statusLine.contains("Search API adapter request"))
        XCTAssertTrue(
            producerFirstStatus.statusLine.contains("producer-source-order.example.com")
        )
        XCTAssertFalse(producerFirstStatus.statusLine.contains("Fallback app-root"))
        XCTAssertEqual(fallbackFirstStatus.cardHint, .disabled)
        XCTAssertTrue(fallbackFirstStatus.statusLine.contains("Fallback app-root"))
        XCTAssertFalse(fallbackFirstStatus.statusLine.contains("Search API adapter request"))
    }

    func test_compositionRoot_chatStoreReadsSearchAPIVendorPolicyStatusForRenderedRecommendationOnly() throws {
        let acceptedObject = RecommendationFixtures.placeRoute
        let rejectedObject = RecommendationFixtures.searchResult
        let hiddenRecommendationID = "search-api-vendor-policy-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [acceptedObject, rejectedObject]
        )
        let acceptedDecision = searchAPIVendorPolicyAcceptedDecision(
            vendorID: "a107-accepted-vendor"
        )
        let rejectedDecision = searchAPIVendorPolicyRejectedDecision(
            vendorID: "a107-private-vendor",
            context: searchAPIVendorPolicyContext(privacyClass: .private),
            vendor: searchAPIVendorPolicyDescriptor(id: "a107-private-vendor")
        )
        let hiddenDecision = searchAPIVendorPolicyAcceptedDecision(
            vendorID: "a107-hidden-vendor"
        )
        let vendorPolicySource = ServerProviderSearchAPIVendorPolicyStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: acceptedObject.id,
                        decision: acceptedDecision
                    ),
                    .init(
                        recommendationID: rejectedObject.id,
                        decision: rejectedDecision
                    ),
                    .init(
                        recommendationID: hiddenRecommendationID,
                        decision: hiddenDecision
                    ),
                ],
                renderedRecommendationIDs: [
                    acceptedObject.id,
                    rejectedObject.id,
                ]
            )

        XCTAssertEqual(acceptedDecision.state, .accepted)
        XCTAssertEqual(rejectedDecision.state, .rejected)
        XCTAssertEqual(rejectedDecision.rejection, .privacyBlocked)
        XCTAssertEqual(
            vendorPolicySource.renderedRecommendationIDs,
            [acceptedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertNil(vendorPolicySource.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(vendorPolicySource.providerStatusPresentation(for: "vendor-policy-missing"))
        let preBootstrapAccepted = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: acceptedObject.id)
        )
        let preBootstrapRejected = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: rejectedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [vendorPolicySource]
        )
        let bootstrapAccepted = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: acceptedObject.id)
        )
        let bootstrapRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeAccepted = try XCTUnwrap(
            store.providerStatusPresentation(for: acceptedObject.id)
        )
        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let statusText = [
            preBootstrapAccepted,
            preBootstrapRejected,
            bootstrapAccepted,
            bootstrapRejected,
            storeAccepted,
            storeRejected,
        ]
            .flatMap { [$0.statusLine] + $0.badges.map(\.label) }
            .joined(separator: "\n")
            .lowercased()

        XCTAssertEqual(store.recommendedMatches, [acceptedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapAccepted, bootstrapAccepted)
        XCTAssertEqual(bootstrapAccepted, storeAccepted)
        XCTAssertEqual(preBootstrapRejected, bootstrapRejected)
        XCTAssertEqual(bootstrapRejected, storeRejected)

        XCTAssertEqual(storeAccepted.recommendationID, acceptedObject.id)
        XCTAssertEqual(storeAccepted.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeAccepted)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeAccepted)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeAccepted)?.tone, .positive)
        XCTAssertTrue(storeAccepted.statusLine.contains("Search API vendor policy"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a107-accepted-vendor"))
        XCTAssertTrue(storeAccepted.statusLine.contains("webSearch"))
        XCTAssertTrue(storeAccepted.statusLine.contains("organicLinks"))
        XCTAssertTrue(storeAccepted.statusLine.contains("No provider runtime has run"))

        XCTAssertEqual(storeRejected.recommendationID, rejectedObject.id)
        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storeRejected)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeRejected))
        XCTAssertNil(badge(.meteredPremium, in: storeRejected))
        XCTAssertTrue(storeRejected.statusLine.contains("blocked by metadata policy"))
        XCTAssertTrue(storeRejected.statusLine.contains("privacyBlocked"))
        XCTAssertTrue(storeRejected.statusLine.contains("a107-private-vendor"))
        XCTAssertTrue(storeRejected.statusLine.contains("No provider runtime has run"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "vendor-policy-missing"))
        XCTAssertTrue(statusText.contains("metadata"))
        XCTAssertTrue(statusText.contains("no provider runtime has run"))
        for forbidden in searchAPIVendorPolicyStatusForbiddenFragments() {
            XCTAssertFalse(forbidden.isEmpty)
            XCTAssertFalse(
                statusText.contains(forbidden),
                "Unexpected Search API vendor policy status wording: \(forbidden)"
            )
        }
    }

