    func test_compositionRoot_chatStoreReadsSearchAPIVendorDispatchAuthorizationStatusForRenderedRecommendationOnly() throws {
        let authorizedObject = RecommendationFixtures.placeRoute
        let dispatchBlockedObject = RecommendationFixtures.searchResult
        let vendorBlockedObject = RecommendationFixtures.routeBay
        let hiddenRecommendationID = "search-api-vendor-dispatch-auth-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [authorizedObject, dispatchBlockedObject, vendorBlockedObject]
        )
        let authorized = try searchAPIVendorDispatchAuthorizationAccepted(
            traceID: "a110-authorized",
            vendorID: "a110-authorized-vendor"
        )
        let dispatchBlocked = try searchAPIVendorDispatchAuthorizationDispatchBlocked(
            traceID: "a110-dispatch-blocked",
            vendorID: "a110-dispatch-blocked-vendor"
        )
        let vendorBlocked = try searchAPIVendorDispatchAuthorizationVendorBlocked(
            traceID: "a110-vendor-blocked",
            vendorID: "a110-private-vendor"
