            .statusSource(
                inputs: [
                    .init(recommendationID: authorizedObject.id, authorization: authorized),
                    .init(
                        recommendationID: dispatchBlockedObject.id,
                        authorization: dispatchBlocked
                    ),
                    .init(
                        recommendationID: vendorBlockedObject.id,
                        authorization: vendorBlocked
                    ),
                    .init(recommendationID: hiddenRecommendationID, authorization: hidden),
