        )
        let preBootstrapDispatchBlocked = try XCTUnwrap(
            source.providerStatusPresentation(for: dispatchBlockedObject.id)
        )
        let preBootstrapVendorBlocked = try XCTUnwrap(
            source.providerStatusPresentation(for: vendorBlockedObject.id)
        )
        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootAuthorized = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: authorizedObject.id)
        )
        let rootDispatchBlocked = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: dispatchBlockedObject.id)
        )
        let rootVendorBlocked = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: vendorBlockedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: "vendor-dispatch-auth-missing")
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeAuthorized = try XCTUnwrap(
            store.providerStatusPresentation(for: authorizedObject.id)
        )
        let storeDispatchBlocked = try XCTUnwrap(
            store.providerStatusPresentation(for: dispatchBlockedObject.id)
        )
        let storeVendorBlocked = try XCTUnwrap(
            store.providerStatusPresentation(for: vendorBlockedObject.id)
        )
        let statusText = [
            preBootstrapAuthorized,
            preBootstrapDispatchBlocked,
            preBootstrapVendorBlocked,
            rootAuthorized,
            rootDispatchBlocked,
            rootVendorBlocked,
            storeAuthorized,
            storeDispatchBlocked,
            storeVendorBlocked,
