        XCTAssertEqual(rootAuthorized, storeAuthorized)
        XCTAssertEqual(preBootstrapDispatchBlocked, rootDispatchBlocked)
        XCTAssertEqual(rootDispatchBlocked, storeDispatchBlocked)
        XCTAssertEqual(preBootstrapVendorBlocked, rootVendorBlocked)
        XCTAssertEqual(rootVendorBlocked, storeVendorBlocked)

        XCTAssertEqual(storeAuthorized.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeAuthorized)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeAuthorized)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeAuthorized)?.tone, .positive)
