        XCTAssertEqual(storeDispatchBlocked.cardHint, .disabled)
        XCTAssertEqual(badge(.unavailable, in: storeDispatchBlocked)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeDispatchBlocked))
        XCTAssertTrue(storeDispatchBlocked.statusLine.contains("dispatchNotEligible"))
        XCTAssertTrue(storeDispatchBlocked.statusLine.contains("payloadDecisionRejected"))
        XCTAssertTrue(storeDispatchBlocked.statusLine.contains("a110-dispatch-blocked-vendor"))

        XCTAssertEqual(storeVendorBlocked.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storeVendorBlocked)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeVendorBlocked))
        XCTAssertTrue(storeVendorBlocked.statusLine.contains("vendorPolicyNotAccepted"))
        XCTAssertTrue(storeVendorBlocked.statusLine.contains("privacyBlocked"))
        XCTAssertTrue(storeVendorBlocked.statusLine.contains("a110-private-vendor"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "vendor-dispatch-auth-missing"))
        XCTAssertTrue(statusText.contains("metadata"))
        XCTAssertTrue(statusText.contains("no transport or provider runtime has run"))
        XCTAssertFalse(statusText.contains("public coffee"))
        XCTAssertFalse(statusText.contains("a110-hidden-vendor"))
        for forbidden in searchAPIVendorDispatchAuthorizationStatusForbiddenFragments() {
            XCTAssertFalse(forbidden.isEmpty)
            XCTAssertFalse(
                statusText.contains(forbidden),
                "Unexpected Search API vendor dispatch authorization status wording: \(forbidden)"
            )
        }
    }

