    func test_compositionRoot_chatStoreReadsSearchAPIAdapterPayloadDispatchStatusForRenderedRecommendationOnly() throws {
        let eligibleObject = RecommendationFixtures.placeRoute
        let blockedObject = RecommendationFixtures.searchResult
        let hiddenRecommendationID = "search-api-payload-dispatch-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [eligibleObject, blockedObject]
        )
        let eligibleReceipt = try searchAPIAdapterPayloadDispatchEligibleReceipt(
            traceID: "a94-search-api-dispatch-eligible",
            sourceHost: "dispatch-rendered.example.com"
        )
        let blockedReceipt = try searchAPIAdapterPayloadDispatchBlockedReceipt(
            traceID: "a94-search-api-dispatch-blocked"
        )
        let hiddenReceipt = try searchAPIAdapterPayloadDispatchEligibleReceipt(
            traceID: "a94-search-api-dispatch-hidden",
            sourceHost: "dispatch-hidden.example.com"
        )
        let dispatchSource = ServerProviderSearchAPIAdapterPayloadDispatchStatusSourceProducer()
            .statusSource(
                receipts: [
                    .init(
                        recommendationID: eligibleObject.id,
                        receipt: eligibleReceipt
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        receipt: blockedReceipt
                    ),
                    .init(
                        recommendationID: hiddenRecommendationID,
                        receipt: hiddenReceipt
                    ),
                ],
                renderedRecommendationIDs: [
                    eligibleObject.id,
                    blockedObject.id,
                ]
            )

        XCTAssertEqual(eligibleReceipt.state, .dispatchEligible)
        XCTAssertEqual(blockedReceipt.state, .blocked)
        XCTAssertEqual(blockedReceipt.rejection, .payloadDecisionRejected)
        XCTAssertEqual(blockedReceipt.payloadDecisionRejection, .requestDecisionRejected)
        XCTAssertEqual(blockedReceipt.requestDecisionRejection, .privacyBlocked)
        XCTAssertNil(dispatchSource.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(dispatchSource.providerStatusPresentation(for: "search-api-dispatch-missing"))
        let preBootstrapEligible = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: eligibleObject.id)
        )
        let preBootstrapBlocked = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: blockedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [dispatchSource]
        )
        let bootstrapEligible = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: eligibleObject.id)
        )
        let bootstrapBlocked = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeEligible = try XCTUnwrap(
            store.providerStatusPresentation(for: eligibleObject.id)
        )
        let storeBlocked = try XCTUnwrap(
            store.providerStatusPresentation(for: blockedObject.id)
        )
        let statusText = [
            preBootstrapEligible,
            preBootstrapBlocked,
            bootstrapEligible,
            bootstrapBlocked,
            storeEligible,
            storeBlocked,
        ]
            .flatMap { [$0.statusLine] + $0.badges.map(\.label) }
            .joined(separator: "\n")
            .lowercased()

        XCTAssertEqual(
            dispatchSource.renderedRecommendationIDs,
            [blockedObject.id, eligibleObject.id].sorted()
        )
        XCTAssertEqual(store.recommendedMatches, [eligibleObject, blockedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapEligible.recommendationID, eligibleObject.id)
        XCTAssertEqual(bootstrapEligible.recommendationID, eligibleObject.id)
        XCTAssertEqual(storeEligible.recommendationID, eligibleObject.id)
        XCTAssertEqual(storeEligible.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeEligible)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeEligible)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeEligible)?.tone, .positive)
        XCTAssertTrue(storeEligible.statusLine.contains("dispatch-ready metadata"))
        XCTAssertTrue(storeEligible.statusLine.contains("dispatch-rendered.example.com"))
        XCTAssertTrue(storeEligible.statusLine.contains("No transport or provider runtime has run"))

        XCTAssertEqual(preBootstrapBlocked.recommendationID, blockedObject.id)
        XCTAssertEqual(bootstrapBlocked.recommendationID, blockedObject.id)
        XCTAssertEqual(storeBlocked.recommendationID, blockedObject.id)
        XCTAssertEqual(storeBlocked.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storeBlocked)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeBlocked))
        XCTAssertNil(badge(.meteredPremium, in: storeBlocked))
        XCTAssertTrue(storeBlocked.statusLine.contains("payloadDecisionRejected"))
        XCTAssertTrue(storeBlocked.statusLine.contains("requestDecisionRejected"))
        XCTAssertTrue(storeBlocked.statusLine.contains("privacyBlocked"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "search-api-dispatch-missing"))
        XCTAssertTrue(statusText.contains("metadata"))
        XCTAssertTrue(statusText.contains("no transport or provider runtime has run"))
        XCTAssertFalse(statusText.contains("public coffee"))
        for forbidden in searchAPIAdapterPayloadDispatchStatusForbiddenFragments() {
            XCTAssertFalse(forbidden.isEmpty)
            XCTAssertFalse(
                statusText.contains(forbidden),
                "Unexpected Search API adapter dispatch status wording: \(forbidden)"
            )
        }
    }

