    func test_compositionRoot_searchAPIVendorDispatchCrossStageStatusSourcesComposeFirstWins() throws {
        let readyObject = RecommendationFixtures.placeRoute
        let blockedObject = RecommendationFixtures.searchResult
        let vendorHiddenID = "a111-vendor-hidden"
        let dispatchHiddenID = "a111-dispatch-hidden"
        let authorizationHiddenID = "a111-authorization-hidden"
        let missingID = "a111-cross-stage-missing"
        let renderedIDs = [readyObject.id, blockedObject.id]
        let hiddenIDs = [vendorHiddenID, dispatchHiddenID, authorizationHiddenID, missingID]
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [readyObject, blockedObject]
        )
        let vendorPolicySource = ServerProviderSearchAPIVendorPolicyStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: searchAPIVendorPolicyAcceptedDecision(
                            vendorID: "a111-vendor-first-vendor"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        decision: searchAPIVendorPolicyRejectedDecision(
                            vendorID: "a111-vendor-private-vendor",
                            context: searchAPIVendorPolicyContext(privacyClass: .private),
                            vendor: searchAPIVendorPolicyDescriptor(
                                id: "a111-vendor-private-vendor"
                            )
                        )
                    ),
                    .init(
                        recommendationID: vendorHiddenID,
                        decision: searchAPIVendorPolicyAcceptedDecision(
                            vendorID: "a111-vendor-hidden-vendor"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let dispatchSource = ServerProviderSearchAPIAdapterPayloadDispatchStatusSourceProducer()
            .statusSource(
                receipts: [
                    .init(
                        recommendationID: readyObject.id,
                        receipt: try searchAPIAdapterPayloadDispatchEligibleReceipt(
                            traceID: "a111-dispatch-ready",
                            sourceHost: "a111-dispatch-ready.example.com"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        receipt: try searchAPIAdapterPayloadDispatchBlockedReceipt(
                            traceID: "a111-dispatch-blocked"
                        )
                    ),
                    .init(
                        recommendationID: dispatchHiddenID,
                        receipt: try searchAPIAdapterPayloadDispatchEligibleReceipt(
                            traceID: "a111-dispatch-hidden",
                            sourceHost: "a111-dispatch-hidden.example.com"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let authorizationSource = ServerProviderSearchAPIVendorPolicyDispatchAuthorizationStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        authorization: try searchAPIVendorDispatchAuthorizationAccepted(
                            traceID: "a111-authorization-ready",
                            vendorID: "a111-authorization-vendor"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        authorization: try searchAPIVendorDispatchAuthorizationVendorBlocked(
                            traceID: "a111-authorization-blocked",
                            vendorID: "a111-authorization-private-vendor"
                        )
                    ),
                    .init(
                        recommendationID: authorizationHiddenID,
                        authorization: try searchAPIVendorDispatchAuthorizationAccepted(
                            traceID: "a111-authorization-hidden",
                            vendorID: "a111-authorization-hidden-vendor"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )

        XCTAssertEqual(vendorPolicySource.renderedRecommendationIDs, renderedIDs.sorted())
        XCTAssertEqual(dispatchSource.renderedRecommendationIDs, renderedIDs.sorted())
        XCTAssertEqual(authorizationSource.renderedRecommendationIDs, renderedIDs.sorted())
        for hiddenID in hiddenIDs {
            XCTAssertNil(vendorPolicySource.providerStatusPresentation(for: hiddenID))
            XCTAssertNil(dispatchSource.providerStatusPresentation(for: hiddenID))
            XCTAssertNil(authorizationSource.providerStatusPresentation(for: hiddenID))
        }

        let vendorReady = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: readyObject.id)
        )
        let vendorBlocked = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: blockedObject.id)
        )
        let dispatchReady = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: readyObject.id)
        )
        let dispatchBlocked = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: blockedObject.id)
        )
        let authorizationReady = try XCTUnwrap(
            authorizationSource.providerStatusPresentation(for: readyObject.id)
        )
        let authorizationBlocked = try XCTUnwrap(
            authorizationSource.providerStatusPresentation(for: blockedObject.id)
        )
        let vendorFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [vendorPolicySource, dispatchSource, authorizationSource]
        )
        let dispatchFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [dispatchSource, authorizationSource, vendorPolicySource]
        )
        let authorizationFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [authorizationSource, vendorPolicySource, dispatchSource]
        )

        let vendorFirstStore = ChatStore(
            recommendationProvider: vendorFirst.recommendationProvider,
            providerStatusProvider: vendorFirst.providerStatusProvider,
            feedbackRuntime: vendorFirst.feedbackRuntime,
            completedRecommendationHandoff: vendorFirst.completedRecommendationHandoff,
            telemetryEmitter: vendorFirst.telemetryEmitter,
            capabilityRegistry: vendorFirst.capabilityRegistry
        )
        let dispatchFirstStore = ChatStore(
            recommendationProvider: dispatchFirst.recommendationProvider,
