            capabilityRegistry: dispatchFirst.capabilityRegistry
        )
        let authorizationFirstStore = ChatStore(
            recommendationProvider: authorizationFirst.recommendationProvider,
            providerStatusProvider: authorizationFirst.providerStatusProvider,
            feedbackRuntime: authorizationFirst.feedbackRuntime,
            completedRecommendationHandoff: authorizationFirst.completedRecommendationHandoff,
            telemetryEmitter: authorizationFirst.telemetryEmitter,
            capabilityRegistry: authorizationFirst.capabilityRegistry
        )

        for hiddenID in hiddenIDs {
            XCTAssertNil(
                vendorFirst.providerStatusProvider?
                    .providerStatusPresentation(for: hiddenID)
            )
            XCTAssertNil(
                dispatchFirst.providerStatusProvider?
                    .providerStatusPresentation(for: hiddenID)
            )
            XCTAssertNil(
                authorizationFirst.providerStatusProvider?
                    .providerStatusPresentation(for: hiddenID)
            )
            XCTAssertNil(vendorFirstStore.providerStatusPresentation(for: hiddenID))
            XCTAssertNil(dispatchFirstStore.providerStatusPresentation(for: hiddenID))
            XCTAssertNil(authorizationFirstStore.providerStatusPresentation(for: hiddenID))
        }

        let vendorFirstReadyRoot = try XCTUnwrap(
            vendorFirst.providerStatusProvider?
                .providerStatusPresentation(for: readyObject.id)
        )
        let vendorFirstBlockedRoot = try XCTUnwrap(
            vendorFirst.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        let dispatchFirstReadyRoot = try XCTUnwrap(
            dispatchFirst.providerStatusProvider?
                .providerStatusPresentation(for: readyObject.id)
        )
        let dispatchFirstBlockedRoot = try XCTUnwrap(
            dispatchFirst.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        let authorizationFirstReadyRoot = try XCTUnwrap(
            authorizationFirst.providerStatusProvider?
                .providerStatusPresentation(for: readyObject.id)
        )
        let authorizationFirstBlockedRoot = try XCTUnwrap(
            authorizationFirst.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        let vendorFirstReadyStore = try XCTUnwrap(
            vendorFirstStore.providerStatusPresentation(for: readyObject.id)
        )
        let vendorFirstBlockedStore = try XCTUnwrap(
