        XCTAssertEqual(authorizationFirstStore.recommendedMatches, [readyObject, blockedObject])
        XCTAssertEqual(vendorFirstStore.session.messages.count, 0)
        XCTAssertEqual(dispatchFirstStore.session.messages.count, 0)
        XCTAssertEqual(authorizationFirstStore.session.messages.count, 0)

        XCTAssertEqual(vendorReady, vendorFirstReadyRoot)
        XCTAssertEqual(vendorFirstReadyRoot, vendorFirstReadyStore)
        XCTAssertEqual(vendorBlocked, vendorFirstBlockedRoot)
        XCTAssertEqual(vendorFirstBlockedRoot, vendorFirstBlockedStore)
        XCTAssertEqual(dispatchReady, dispatchFirstReadyRoot)
        XCTAssertEqual(dispatchFirstReadyRoot, dispatchFirstReadyStore)
        XCTAssertEqual(dispatchBlocked, dispatchFirstBlockedRoot)
        XCTAssertEqual(dispatchFirstBlockedRoot, dispatchFirstBlockedStore)
        XCTAssertEqual(authorizationReady, authorizationFirstReadyRoot)
