    func test_compositionRoot_chatStoreReadsSearchAPITransportLeaseStatusForRenderedRecommendationOnly() throws {
        let issuedObject = RecommendationFixtures.placeRoute
        let rejectedObject = RecommendationFixtures.searchResult
        let hiddenRecommendationID = "a114-transport-lease-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
