        )
        let hiddenLease = searchAPITransportLeaseIssued(
            id: "a114-hidden-lease",
            vendorID: "a114-hidden-vendor",
            budgetID: "a114-hidden-budget"
        )
        let leaseSource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(recommendationID: issuedObject.id, lease: issuedLease),
                    .init(recommendationID: rejectedObject.id, lease: rejectedLease),
                    .init(recommendationID: hiddenRecommendationID, lease: hiddenLease),
                ],
                renderedRecommendationIDs: [issuedObject.id, rejectedObject.id]
            )

        XCTAssertEqual(
            leaseSource.renderedRecommendationIDs,
            [issuedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertNil(leaseSource.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(leaseSource.providerStatusPresentation(for: "a114-transport-lease-missing"))
        let preBootstrapIssued = try XCTUnwrap(
            leaseSource.providerStatusPresentation(for: issuedObject.id)
        )
        let preBootstrapRejected = try XCTUnwrap(
            leaseSource.providerStatusPresentation(for: rejectedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [leaseSource]
        )
        let bootstrapIssued = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: issuedObject.id)
        )
        let bootstrapRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: "a114-transport-lease-missing")
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
