        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let selectedStatusText = [
            providerStatusSearchText(storeIssued),
            providerStatusSearchText(storeRejected),
        ].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [issuedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapIssued, bootstrapIssued)
        XCTAssertEqual(bootstrapIssued, storeIssued)
        XCTAssertEqual(preBootstrapRejected, bootstrapRejected)
        XCTAssertEqual(bootstrapRejected, storeRejected)

        XCTAssertEqual(storeIssued.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeIssued)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeIssued)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeIssued)?.tone, .positive)
        XCTAssertTrue(storeIssued.statusLine.contains("transport lease ready"))
        XCTAssertTrue(storeIssued.statusLine.contains("a114-issued-lease"))
        XCTAssertTrue(storeIssued.statusLine.contains("a114-issued-vendor"))
        XCTAssertTrue(storeIssued.statusLine.contains("a114-budget-metered"))

        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: storeRejected)?.tone, .warning)
        XCTAssertTrue(storeRejected.statusLine.contains("meteredEligibilityMissing"))
        XCTAssertTrue(storeRejected.statusLine.contains("payloadDecisionRejected"))
        XCTAssertTrue(storeRejected.statusLine.contains("dispatchNotEligible"))
        XCTAssertTrue(storeRejected.statusLine.contains("a114-budget-metered-denied"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "a114-transport-lease-missing"))
        XCTAssertTrue(selectedStatusText.contains("metadata"))
        XCTAssertTrue(selectedStatusText.contains("no transport or provider runtime has run"))
        XCTAssertFalse(selectedStatusText.contains("public coffee"))
        XCTAssertFalse(selectedStatusText.contains("a114-hidden-vendor"))
        XCTAssertFalse(selectedStatusText.contains("a114-hidden-budget"))
        for forbidden in searchAPITransportLeaseStatusForbiddenFragments() {
            XCTAssertFalse(selectedStatusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPITransportLeaseStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let firstSource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(
                        recommendationID: renderedObject.id,
                        lease: searchAPITransportLeaseIssued(
                            id: "a114-first-lease",
                            vendorID: "a114-first-vendor",
                            budgetID: "a114-first-budget",
                            costClass: .includedQuota,
                            freshness: .cachedOK
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let secondSource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(
                        recommendationID: renderedObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a114-second-lease",
                            reason: .explicitBudgetDenied,
                            vendorID: "a114-second-vendor",
                            budgetID: "a114-second-budget"
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let firstThenSecond = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [firstSource, secondSource]
        )
        let secondThenFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [secondSource, firstSource]
        )

        let firstThenSecondStore = ChatStore(
            recommendationProvider: firstThenSecond.recommendationProvider,
            providerStatusProvider: firstThenSecond.providerStatusProvider,
            feedbackRuntime: firstThenSecond.feedbackRuntime,
            completedRecommendationHandoff: firstThenSecond.completedRecommendationHandoff,
            telemetryEmitter: firstThenSecond.telemetryEmitter,
            capabilityRegistry: firstThenSecond.capabilityRegistry
        )
        let secondThenFirstStore = ChatStore(
            recommendationProvider: secondThenFirst.recommendationProvider,
            providerStatusProvider: secondThenFirst.providerStatusProvider,
            feedbackRuntime: secondThenFirst.feedbackRuntime,
            completedRecommendationHandoff: secondThenFirst.completedRecommendationHandoff,
            telemetryEmitter: secondThenFirst.telemetryEmitter,
            capabilityRegistry: secondThenFirst.capabilityRegistry
        )
        let firstSelected = try XCTUnwrap(
            firstThenSecondStore.providerStatusPresentation(for: renderedObject.id)
        )
        let secondSelected = try XCTUnwrap(
            secondThenFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let firstText = providerStatusSearchText(firstSelected)
        let secondText = providerStatusSearchText(secondSelected)

        XCTAssertEqual(firstThenSecondStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(secondThenFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(firstSelected.cardHint, .normal)
        XCTAssertEqual(badge(.includedQuota, in: firstSelected)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: firstSelected))
        XCTAssertTrue(firstText.contains("a114-first-lease"))
        XCTAssertTrue(firstText.contains("a114-first-vendor"))
        XCTAssertTrue(firstText.contains("a114-first-budget"))
        XCTAssertFalse(firstText.contains("a114-second-lease"))
        XCTAssertFalse(firstText.contains("a114-second-vendor"))
        XCTAssertFalse(firstText.contains("a114-second-budget"))
        XCTAssertFalse(firstText.contains("explicitbudgetdenied"))

        XCTAssertEqual(secondSelected.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: secondSelected)?.tone, .warning)
        XCTAssertTrue(secondText.contains("a114-second-lease"))
        XCTAssertTrue(secondText.contains("a114-second-vendor"))
        XCTAssertTrue(secondText.contains("a114-second-budget"))
        XCTAssertTrue(secondText.contains("explicitbudgetdenied"))
        XCTAssertFalse(secondText.contains("a114-first-lease"))
        XCTAssertFalse(secondText.contains("a114-first-vendor"))
        XCTAssertFalse(secondText.contains("a114-first-budget"))
        XCTAssertFalse(secondText.contains("transport lease ready"))
    }

    func test_compositionRoot_meteredEntitlementTransportLeaseStatusSourceOrderIsDeterministic() throws {
        let issuedObject = RecommendationFixtures.placeRoute
        let missingObject = RecommendationFixtures.searchResult
        let vendorObject = RecommendationFixtures.routeBay
        let hiddenID = "a123-lease-hidden"
        let missingID = "a123-lease-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [issuedObject, missingObject, vendorObject]
        )
        let primarySource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(
                        recommendationID: issuedObject.id,
                        lease: searchAPITransportLeaseIssued(
                            id: "a123-issued-lease",
                            vendorID: "a123-issued-vendor",
                            budgetID: "a123-issued-budget",
                            costClass: .meteredPremium,
                            freshness: .livePreferred
                        )
                    ),
                    .init(
                        recommendationID: missingObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a123-missing-lease",
                            reason: .meteredEntitlementMissing,
                            vendorID: "a123-runtime-vendor",
                            budgetID: "a123-generic-budget"
                        )
                    ),
                    .init(
                        recommendationID: vendorObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a123-vendor-lease",
                            reason: .vendorMismatch,
                            vendorID: "a123-runtime-vendor",
                            budgetID: "a123-vendor-budget"
                        )
                    ),
                    .init(
                        recommendationID: hiddenID,
                        lease: searchAPITransportLeaseIssued(
                            id: "a123-hidden-lease",
                            vendorID: "a123-hidden-vendor",
                            budgetID: "a123-hidden-budget"
                        )
                    ),
                ],
                renderedRecommendationIDs: [
                    issuedObject.id,
                    missingObject.id,
                    vendorObject.id,
                ]
            )
        let fallbackSource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(
                        recommendationID: issuedObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a123-fallback-issued-lease",
                            reason: .explicitBudgetDenied,
                            vendorID: "a123-fallback-issued-vendor",
                            budgetID: "a123-fallback-issued-budget"
                        )
                    ),
                    .init(
                        recommendationID: missingObject.id,
                        lease: searchAPITransportLeaseIssued(
                            id: "a123-fallback-missing-lease",
                            vendorID: "a123-fallback-missing-vendor",
                            budgetID: "a123-fallback-missing-budget"
                        )
                    ),
                    .init(
                        recommendationID: vendorObject.id,
                        lease: searchAPITransportLeaseIssued(
                            id: "a123-fallback-vendor-lease",
                            vendorID: "a123-fallback-vendor",
                            budgetID: "a123-fallback-vendor-budget"
                        )
                    ),
                ],
                renderedRecommendationIDs: [
                    issuedObject.id,
                    missingObject.id,
                    vendorObject.id,
                ]
            )

        XCTAssertNil(primarySource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(primarySource.providerStatusPresentation(for: missingID))

        let primaryFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [primarySource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, primarySource]
        )
        let primaryFirstStore = ChatStore(
            recommendationProvider: primaryFirst.recommendationProvider,
            providerStatusProvider: primaryFirst.providerStatusProvider,
            feedbackRuntime: primaryFirst.feedbackRuntime,
            completedRecommendationHandoff: primaryFirst.completedRecommendationHandoff,
            telemetryEmitter: primaryFirst.telemetryEmitter,
            capabilityRegistry: primaryFirst.capabilityRegistry
        )
        let fallbackFirstStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )

        XCTAssertNil(
            primaryFirst.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(primaryFirstStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(primaryFirstStore.providerStatusPresentation(for: missingID))

        let issuedStatus = try XCTUnwrap(
            primaryFirstStore.providerStatusPresentation(for: issuedObject.id)
        )
        let missingStatus = try XCTUnwrap(
            primaryFirstStore.providerStatusPresentation(for: missingObject.id)
        )
        let vendorStatus = try XCTUnwrap(
            primaryFirstStore.providerStatusPresentation(for: vendorObject.id)
        )
        let fallbackIssuedStatus = try XCTUnwrap(
            fallbackFirstStore.providerStatusPresentation(for: issuedObject.id)
        )
        let selectedText = [
            providerStatusSearchText(issuedStatus),
            providerStatusSearchText(missingStatus),
            providerStatusSearchText(vendorStatus),
        ].joined(separator: "\n")
        let fallbackIssuedText = providerStatusSearchText(fallbackIssuedStatus)

        XCTAssertEqual(
            primaryFirstStore.recommendedMatches,
            [issuedObject, missingObject, vendorObject]
        )
        XCTAssertEqual(primaryFirstStore.session.messages.count, 0)

        XCTAssertEqual(issuedStatus.cardHint, .warning)
        XCTAssertEqual(badge(.meteredPremium, in: issuedStatus)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: issuedStatus)?.tone, .positive)
        XCTAssertTrue(selectedText.contains("a123-issued-lease"))
        XCTAssertTrue(selectedText.contains("a123-issued-vendor"))
        XCTAssertTrue(selectedText.contains("a123-issued-budget"))

        XCTAssertEqual(missingStatus.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: missingStatus)?.tone, .warning)
        XCTAssertTrue(selectedText.contains("meteredentitlementmissing"))
        XCTAssertTrue(selectedText.contains("a123-generic-budget"))

        XCTAssertEqual(vendorStatus.cardHint, .disabled)
        XCTAssertEqual(badge(.termsBlocked, in: vendorStatus)?.tone, .warning)
        XCTAssertTrue(selectedText.contains("vendormismatch"))
        XCTAssertTrue(selectedText.contains("a123-vendor-budget"))

        XCTAssertFalse(selectedText.contains("a123-hidden-vendor"))
        XCTAssertFalse(selectedText.contains("a123-hidden-budget"))
        XCTAssertFalse(selectedText.contains("a123-fallback-issued-vendor"))
        XCTAssertFalse(selectedText.contains("a123-fallback-missing-vendor"))
        XCTAssertFalse(selectedText.contains("a123-fallback-vendor"))
        XCTAssertTrue(fallbackIssuedText.contains("a123-fallback-issued-vendor"))
        XCTAssertFalse(fallbackIssuedText.contains("a123-issued-vendor"))
        for forbidden in searchAPITransportLeaseStatusForbiddenFragments() {
            XCTAssertFalse(selectedText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_meteredEntitlementTransportLeaseCrossStageStatusSourcesComposeFirstWins() throws {
        let readyObject = RecommendationFixtures.placeRoute
        let blockedObject = RecommendationFixtures.searchResult
        let meteredHiddenID = "a124-metered-hidden"
        let vendorHiddenID = "a124-vendor-hidden"
