                            budgetID: "a124-lease-hidden-budget"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )

        let sources = [
            meteredSource,
            vendorPolicySource,
            dispatchSource,
            authorizationSource,
            leaseSource,
        ]
        for source in sources {
            XCTAssertEqual(source.renderedRecommendationIDs, renderedIDs.sorted())
            for hiddenID in hiddenIDs {
                XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
            }
        }

        let meteredReady = try XCTUnwrap(
            meteredSource.providerStatusPresentation(for: readyObject.id)
        )
        let meteredBlocked = try XCTUnwrap(
            meteredSource.providerStatusPresentation(for: blockedObject.id)
        )
        let vendorReady = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: readyObject.id)
        )
        let vendorBlocked = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: blockedObject.id)
        )
        let dispatchReady = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: readyObject.id)
        )
        let dispatchBlocked = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: blockedObject.id)
        )
        let authorizationReady = try XCTUnwrap(
            authorizationSource.providerStatusPresentation(for: readyObject.id)
        )
        let authorizationBlocked = try XCTUnwrap(
            authorizationSource.providerStatusPresentation(for: blockedObject.id)
        )
        let leaseReady = try XCTUnwrap(
            leaseSource.providerStatusPresentation(for: readyObject.id)
        )
        let leaseBlocked = try XCTUnwrap(
            leaseSource.providerStatusPresentation(for: blockedObject.id)
        )
        let selectionCases: [
            (
                name: String,
                sources: [any ProviderStatusProviding],
                expectedReady: ProviderStatusPresentation,
                expectedBlocked: ProviderStatusPresentation,
                expectedMarkers: [String],
                forbiddenMarkers: [String]
            )
        ] = [
            (
                name: "metered",
                sources: [meteredSource, vendorPolicySource, dispatchSource, authorizationSource, leaseSource],
                expectedReady: meteredReady,
                expectedBlocked: meteredBlocked,
                expectedMarkers: [
                    "a124-metered-vendor",
                    "a124-metered-quota",
                    "overquota",
                ],
                forbiddenMarkers: [
                    "a124-vendor-ready-vendor",
                    "a124-vendor-private-vendor",
                    "a124-dispatch-ready.example.com",
                    "a124-dispatch-blocked",
                    "a124-authorization-vendor",
                    "a124-authorization-private-vendor",
                    "a124-lease-vendor",
                    "a124-lease-generic-budget",
                    "meteredentitlementmissing",
                ]
            ),
            (
                name: "vendor",
                sources: [vendorPolicySource, dispatchSource, authorizationSource, leaseSource, meteredSource],
                expectedReady: vendorReady,
                expectedBlocked: vendorBlocked,
                expectedMarkers: [
                    "a124-vendor-ready-vendor",
                    "a124-vendor-private-vendor",
                    "privacyblocked",
                ],
                forbiddenMarkers: [
                    "a124-metered-vendor",
                    "a124-metered-quota",
                    "overquota",
                    "a124-dispatch-ready.example.com",
                    "a124-authorization-vendor",
                    "a124-lease-vendor",
                    "a124-lease-generic-budget",
                ]
            ),
            (
                name: "dispatch",
                sources: [dispatchSource, authorizationSource, leaseSource, meteredSource, vendorPolicySource],
                expectedReady: dispatchReady,
                expectedBlocked: dispatchBlocked,
                expectedMarkers: [
                    "a124-dispatch-ready.example.com",
                    "payloaddecisionrejected",
                    "requestdecisionrejected",
                ],
                forbiddenMarkers: [
                    "a124-metered-vendor",
                    "a124-metered-quota",
                    "a124-vendor-ready-vendor",
                    "a124-authorization-vendor",
                    "a124-lease-vendor",
                    "a124-lease-generic-budget",
                ]
            ),
            (
                name: "authorization",
                sources: [authorizationSource, leaseSource, meteredSource, vendorPolicySource, dispatchSource],
                expectedReady: authorizationReady,
                expectedBlocked: authorizationBlocked,
                expectedMarkers: [
                    "a124-authorization-vendor",
                    "a124-authorization-private-vendor",
                    "vendorpolicynotaccepted",
                ],
                forbiddenMarkers: [
                    "a124-metered-vendor",
                    "a124-metered-quota",
                    "a124-vendor-ready-vendor",
                    "a124-dispatch-ready.example.com",
                    "a124-lease-vendor",
                    "a124-lease-generic-budget",
                ]
            ),
            (
                name: "lease",
                sources: [leaseSource, meteredSource, vendorPolicySource, dispatchSource, authorizationSource],
                expectedReady: leaseReady,
                expectedBlocked: leaseBlocked,
                expectedMarkers: [
                    "a124-lease-vendor",
                    "a124-metered-lease-budget",
                    "a124-lease-generic-budget",
                    "meteredentitlementmissing",
                ],
                forbiddenMarkers: [
                    "a124-metered-vendor",
                    "a124-metered-quota",
                    "overquota",
                    "a124-vendor-ready-vendor",
                    "a124-dispatch-ready.example.com",
                    "a124-authorization-vendor",
                ]
            ),
        ]

        for selectionCase in selectionCases {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: selectionCase.sources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )

            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
            }

            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectionCase.name)
            XCTAssertEqual(store.session.messages.count, 0, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedReady, rootReady, selectionCase.name)
            XCTAssertEqual(rootReady, storeReady, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedBlocked, rootBlocked, selectionCase.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectionCase.name)
            for marker in selectionCase.expectedMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for marker in selectionCase.forbiddenMarkers {
                XCTAssertFalse(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for forbidden in meteredEntitlementCrossStageForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectionCase.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_chatStoreReadsMeteredEntitlementStatusForRenderedRecommendationOnly() throws {
        let includedObject = RecommendationFixtures.placeRoute
