            expectedReason: .overQuota
        )
        let privacyDecision = meteredEntitlementRejectedDecision(
            request: meteredEntitlementUsageRequest(
                id: "a119-private",
                privacyClass: .private
            ),
            expectedReason: .privacyBlocked
        )
        let providerMismatchDecision = meteredEntitlementRejectedDecision(
            request: meteredEntitlementUsageRequest(id: "a119-provider-mismatch"),
            snapshot: meteredEntitlementSnapshot(providerFamily: .googleMaps),
            expectedReason: .providerFamilyMismatch
        )
        let hiddenDecision = meteredEntitlementAcceptedDecision(
            id: "a119-hidden",
            request: meteredEntitlementUsageRequest(
