        )
        let preBootstrapOverBudget = try XCTUnwrap(
            source.providerStatusPresentation(for: overBudgetObject.id)
        )
        let preBootstrapPrivacy = try XCTUnwrap(
            source.providerStatusPresentation(for: privacyObject.id)
        )
        let preBootstrapProviderMismatch = try XCTUnwrap(
