                .providerStatusPresentation(for: includedObject.id)
        )
        let bootstrapMetered = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: meteredObject.id)
        )
        let bootstrapOverBudget = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: overBudgetObject.id)
        )
        let bootstrapPrivacy = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: privacyObject.id)
        )
        let bootstrapProviderMismatch = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: providerMismatchObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeIncluded = try XCTUnwrap(
            store.providerStatusPresentation(for: includedObject.id)
        )
        let storeMetered = try XCTUnwrap(
            store.providerStatusPresentation(for: meteredObject.id)
        )
        let storeOverBudget = try XCTUnwrap(
            store.providerStatusPresentation(for: overBudgetObject.id)
        )
        let storePrivacy = try XCTUnwrap(
            store.providerStatusPresentation(for: privacyObject.id)
        )
        let storeProviderMismatch = try XCTUnwrap(
            store.providerStatusPresentation(for: providerMismatchObject.id)
        )
        let selectedStatusText = [
            providerStatusSearchText(storeIncluded),
            providerStatusSearchText(storeMetered),
            providerStatusSearchText(storeOverBudget),
            providerStatusSearchText(storePrivacy),
            providerStatusSearchText(storeProviderMismatch),
        ].joined(separator: "\n")

        XCTAssertEqual(
            store.recommendedMatches,
            [
                includedObject,
                meteredObject,
                overBudgetObject,
                privacyObject,
                providerMismatchObject,
            ]
        )
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapIncluded, bootstrapIncluded)
        XCTAssertEqual(bootstrapIncluded, storeIncluded)
        XCTAssertEqual(preBootstrapMetered, bootstrapMetered)
        XCTAssertEqual(bootstrapMetered, storeMetered)
        XCTAssertEqual(preBootstrapOverBudget, bootstrapOverBudget)
        XCTAssertEqual(bootstrapOverBudget, storeOverBudget)
        XCTAssertEqual(preBootstrapPrivacy, bootstrapPrivacy)
        XCTAssertEqual(bootstrapPrivacy, storePrivacy)
        XCTAssertEqual(preBootstrapProviderMismatch, bootstrapProviderMismatch)
        XCTAssertEqual(bootstrapProviderMismatch, storeProviderMismatch)

        XCTAssertEqual(storeIncluded.cardHint, .normal)
        XCTAssertEqual(badge(.remoteProvider, in: storeIncluded)?.tone, .neutral)
        XCTAssertEqual(badge(.includedQuota, in: storeIncluded)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: storeIncluded))
        XCTAssertEqual(badge(.liveFreshness, in: storeIncluded)?.tone, .positive)
        XCTAssertTrue(storeIncluded.statusLine.contains("budget metadata only"))
        XCTAssertTrue(storeIncluded.statusLine.contains("Provider: searchAPI"))
        XCTAssertTrue(storeIncluded.statusLine.contains("Vendor: a119-search-vendor"))
        XCTAssertTrue(storeIncluded.statusLine.contains("Quota period: a119-2026-05"))
        XCTAssertTrue(storeIncluded.statusLine.contains("25 remaining"))
        XCTAssertTrue(storeIncluded.statusLine.contains("9 reserved"))
        XCTAssertTrue(storeIncluded.statusLine.contains("Cost: includedQuota"))

        XCTAssertEqual(storeMetered.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeMetered)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeMetered)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeMetered)?.tone, .positive)
        XCTAssertTrue(storeMetered.statusLine.contains("34 remaining"))
        XCTAssertTrue(storeMetered.statusLine.contains("15 reserved"))
        XCTAssertTrue(storeMetered.statusLine.contains("Cost: meteredPremium"))

        XCTAssertEqual(storeOverBudget.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: storeOverBudget)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeOverBudget))
        XCTAssertNil(badge(.includedQuota, in: storeOverBudget))
        XCTAssertNil(badge(.meteredPremium, in: storeOverBudget))
        XCTAssertTrue(storeOverBudget.statusLine.contains("overQuota"))
        XCTAssertFalse(storeOverBudget.statusLine.contains("remaining"))
        XCTAssertFalse(storeOverBudget.statusLine.contains("reserved"))

        XCTAssertEqual(storePrivacy.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storePrivacy)?.tone, .warning)
        XCTAssertTrue(storePrivacy.statusLine.contains("privacyBlocked"))

        XCTAssertEqual(storeProviderMismatch.cardHint, .disabled)
        XCTAssertEqual(badge(.termsBlocked, in: storeProviderMismatch)?.tone, .warning)
        XCTAssertTrue(storeProviderMismatch.statusLine.contains("providerFamilyMismatch"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))
        XCTAssertTrue(selectedStatusText.contains("budget metadata"))
        XCTAssertTrue(selectedStatusText.contains("no transport or provider runtime has run"))
        XCTAssertFalse(selectedStatusText.contains("a119-hidden-vendor"))
        for forbidden in meteredEntitlementStatusForbiddenFragments() {
            XCTAssertFalse(selectedStatusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_meteredEntitlementStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let acceptedSource = ServerProviderMeteredEntitlementStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: meteredEntitlementAcceptedDecision(
                            id: "a119-first",
                            costClass: .includedQuota,
                            estimatedUnits: 2,
                            remainingUnits: 13,
                            reservedUnits: 3,
                            freshness: .cachedOK
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let rejectedSource = ServerProviderMeteredEntitlementStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: meteredEntitlementRejectedDecision(
                            request: meteredEntitlementUsageRequest(
                                id: "a119-second",
                                estimatedUnits: 81
                            ),
                            snapshot: meteredEntitlementSnapshot(remainingUnits: 80),
                            expectedReason: .overQuota
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let acceptedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [acceptedSource, rejectedSource]
        )
        let rejectedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [rejectedSource, acceptedSource]
        )

        let acceptedFirstRoot = try XCTUnwrap(
            acceptedFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let rejectedFirstRoot = try XCTUnwrap(
            rejectedFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let acceptedFirstStore = ChatStore(
            recommendationProvider: acceptedFirst.recommendationProvider,
            providerStatusProvider: acceptedFirst.providerStatusProvider,
            feedbackRuntime: acceptedFirst.feedbackRuntime,
            completedRecommendationHandoff: acceptedFirst.completedRecommendationHandoff,
            telemetryEmitter: acceptedFirst.telemetryEmitter,
            capabilityRegistry: acceptedFirst.capabilityRegistry
        )
        let rejectedFirstStore = ChatStore(
            recommendationProvider: rejectedFirst.recommendationProvider,
            providerStatusProvider: rejectedFirst.providerStatusProvider,
            feedbackRuntime: rejectedFirst.feedbackRuntime,
            completedRecommendationHandoff: rejectedFirst.completedRecommendationHandoff,
            telemetryEmitter: rejectedFirst.telemetryEmitter,
            capabilityRegistry: rejectedFirst.capabilityRegistry
        )
        let acceptedSelected = try XCTUnwrap(
            acceptedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let rejectedSelected = try XCTUnwrap(
            rejectedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let acceptedText = providerStatusSearchText(acceptedSelected)
        let rejectedText = providerStatusSearchText(rejectedSelected)

        XCTAssertEqual(acceptedSource.renderedRecommendationIDs, [renderedObject.id])
        XCTAssertEqual(rejectedSource.renderedRecommendationIDs, [renderedObject.id])
        XCTAssertEqual(acceptedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(rejectedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(acceptedFirstRoot, acceptedSelected)
        XCTAssertEqual(rejectedFirstRoot, rejectedSelected)

        XCTAssertEqual(acceptedSelected.cardHint, .normal)
        XCTAssertEqual(badge(.includedQuota, in: acceptedSelected)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: acceptedSelected))
        XCTAssertNil(badge(.costBlocked, in: acceptedSelected))
        XCTAssertTrue(acceptedText.contains("11 remaining"))
        XCTAssertTrue(acceptedText.contains("5 reserved"))
        XCTAssertTrue(acceptedText.contains("cost: includedquota"))
        XCTAssertFalse(acceptedText.contains("overquota"))
        XCTAssertFalse(acceptedText.contains("a119-second"))

        XCTAssertEqual(rejectedSelected.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: rejectedSelected)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: rejectedSelected))
        XCTAssertNil(badge(.includedQuota, in: rejectedSelected))
        XCTAssertTrue(rejectedText.contains("overquota"))
        XCTAssertFalse(rejectedText.contains("11 remaining"))
        XCTAssertFalse(rejectedText.contains("cost: includedquota"))
        XCTAssertFalse(rejectedText.contains("a119-first"))
    }

    func test_compositionRoot_meteredEntitlementCrossStageStatusSourcesComposeFirstWins() throws {
        let readyObject = RecommendationFixtures.placeRoute
        let blockedObject = RecommendationFixtures.searchResult
        let meteredHiddenID = "a120-metered-hidden"
        let vendorHiddenID = "a120-vendor-hidden"
        let dispatchHiddenID = "a120-dispatch-hidden"
        let authorizationHiddenID = "a120-authorization-hidden"
        let leaseHiddenID = "a120-lease-hidden"
        let missingID = "a120-cross-stage-missing"
        let renderedIDs = [readyObject.id, blockedObject.id]
        let hiddenIDs = [
            meteredHiddenID,
            vendorHiddenID,
            dispatchHiddenID,
            authorizationHiddenID,
            leaseHiddenID,
            missingID,
        ]
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [readyObject, blockedObject]
        )
        let meteredSource = ServerProviderMeteredEntitlementStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: meteredEntitlementAcceptedDecision(
                            id: "a120-metered-ready",
                            request: meteredEntitlementUsageRequest(
                                id: "a120-metered-ready",
                                vendorID: "a120-metered-vendor",
                                estimatedUnits: 4,
                                costClass: .includedQuota
                            ),
                            snapshot: meteredEntitlementSnapshot(
                                id: "a120-metered-ready-snapshot",
                                vendorID: "a120-metered-vendor",
                                costClass: .includedQuota,
                                quotaPeriodID: "a120-metered-quota",
                                reservedUnits: 3,
                                remainingUnits: 15
                            )
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        decision: meteredEntitlementRejectedDecision(
                            request: meteredEntitlementUsageRequest(
                                id: "a120-metered-blocked",
                                estimatedUnits: 81
                            ),
                            snapshot: meteredEntitlementSnapshot(remainingUnits: 80),
                            expectedReason: .overQuota
                        )
                    ),
                    .init(
                        recommendationID: meteredHiddenID,
                        decision: meteredEntitlementAcceptedDecision(
                            id: "a120-metered-hidden",
                            request: meteredEntitlementUsageRequest(
                                id: "a120-metered-hidden",
                                vendorID: "a120-metered-hidden-vendor"
                            ),
                            snapshot: meteredEntitlementSnapshot(
                                id: "a120-metered-hidden-snapshot",
                                vendorID: "a120-metered-hidden-vendor"
                            )
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let vendorPolicySource = ServerProviderSearchAPIVendorPolicyStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: searchAPIVendorPolicyAcceptedDecision(
                            vendorID: "a120-vendor-ready-vendor"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        decision: searchAPIVendorPolicyRejectedDecision(
                            vendorID: "a120-vendor-private-vendor",
                            context: searchAPIVendorPolicyContext(privacyClass: .private),
                            vendor: searchAPIVendorPolicyDescriptor(
                                id: "a120-vendor-private-vendor"
                            )
                        )
                    ),
                    .init(
                        recommendationID: vendorHiddenID,
                        decision: searchAPIVendorPolicyAcceptedDecision(
                            vendorID: "a120-vendor-hidden-vendor"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let dispatchSource = ServerProviderSearchAPIAdapterPayloadDispatchStatusSourceProducer()
            .statusSource(
                receipts: [
                    .init(
                        recommendationID: readyObject.id,
                        receipt: try searchAPIAdapterPayloadDispatchEligibleReceipt(
                            traceID: "a120-dispatch-ready",
                            sourceHost: "a120-dispatch-ready.example.com"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        receipt: try searchAPIAdapterPayloadDispatchBlockedReceipt(
                            traceID: "a120-dispatch-blocked"
                        )
                    ),
                    .init(
                        recommendationID: dispatchHiddenID,
                        receipt: try searchAPIAdapterPayloadDispatchEligibleReceipt(
                            traceID: "a120-dispatch-hidden",
                            sourceHost: "a120-dispatch-hidden.example.com"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let authorizationSource = ServerProviderSearchAPIVendorPolicyDispatchAuthorizationStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        authorization: try searchAPIVendorDispatchAuthorizationAccepted(
                            traceID: "a120-authorization-ready",
                            vendorID: "a120-authorization-vendor"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        authorization: try searchAPIVendorDispatchAuthorizationVendorBlocked(
                            traceID: "a120-authorization-blocked",
                            vendorID: "a120-authorization-private-vendor"
                        )
                    ),
                    .init(
                        recommendationID: authorizationHiddenID,
                        authorization: try searchAPIVendorDispatchAuthorizationAccepted(
                            traceID: "a120-authorization-hidden",
                            vendorID: "a120-authorization-hidden-vendor"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let leaseSource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(
                        recommendationID: readyObject.id,
                        lease: searchAPITransportLeaseIssued(
                            id: "a120-lease-ready",
                            vendorID: "a120-lease-vendor",
                            budgetID: "a120-lease-budget"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a120-lease-blocked",
                            reason: .explicitBudgetDenied,
                            vendorID: "a120-lease-private-vendor",
                            budgetID: "a120-lease-denied-budget"
                        )
                    ),
                    .init(
                        recommendationID: leaseHiddenID,
                        lease: searchAPITransportLeaseIssued(
                            id: "a120-lease-hidden",
                            vendorID: "a120-lease-hidden-vendor",
                            budgetID: "a120-lease-hidden-budget"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )

        let sources = [
            meteredSource,
            vendorPolicySource,
            dispatchSource,
            authorizationSource,
            leaseSource,
        ]
        for source in sources {
            XCTAssertEqual(source.renderedRecommendationIDs, renderedIDs.sorted())
            for hiddenID in hiddenIDs {
                XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
            }
        }

        let meteredReady = try XCTUnwrap(
            meteredSource.providerStatusPresentation(for: readyObject.id)
        )
        let meteredBlocked = try XCTUnwrap(
            meteredSource.providerStatusPresentation(for: blockedObject.id)
        )
        let vendorReady = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: readyObject.id)
        )
        let vendorBlocked = try XCTUnwrap(
            vendorPolicySource.providerStatusPresentation(for: blockedObject.id)
        )
        let dispatchReady = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: readyObject.id)
        )
        let dispatchBlocked = try XCTUnwrap(
            dispatchSource.providerStatusPresentation(for: blockedObject.id)
        )
        let authorizationReady = try XCTUnwrap(
            authorizationSource.providerStatusPresentation(for: readyObject.id)
        )
        let authorizationBlocked = try XCTUnwrap(
            authorizationSource.providerStatusPresentation(for: blockedObject.id)
        )
        let leaseReady = try XCTUnwrap(
            leaseSource.providerStatusPresentation(for: readyObject.id)
        )
        let leaseBlocked = try XCTUnwrap(
            leaseSource.providerStatusPresentation(for: blockedObject.id)
        )
        let selectionCases: [
            (
                name: String,
                sources: [any ProviderStatusProviding],
                expectedReady: ProviderStatusPresentation,
                expectedBlocked: ProviderStatusPresentation,
                expectedMarkers: [String],
                forbiddenMarkers: [String]
            )
        ] = [
            (
                name: "metered",
                sources: [meteredSource, vendorPolicySource, dispatchSource, authorizationSource, leaseSource],
                expectedReady: meteredReady,
                expectedBlocked: meteredBlocked,
                expectedMarkers: [
                    "a120-metered-vendor",
                    "a120-metered-quota",
                    "overquota",
                ],
                forbiddenMarkers: [
                    "a120-vendor-ready-vendor",
                    "a120-vendor-private-vendor",
                    "a120-dispatch-ready.example.com",
                    "a120-dispatch-blocked",
                    "a120-authorization-vendor",
                    "a120-authorization-private-vendor",
                    "a120-lease-vendor",
                    "a120-lease-denied-budget",
                ]
            ),
            (
                name: "vendor",
                sources: [vendorPolicySource, dispatchSource, authorizationSource, leaseSource, meteredSource],
                expectedReady: vendorReady,
                expectedBlocked: vendorBlocked,
                expectedMarkers: [
                    "a120-vendor-ready-vendor",
                    "a120-vendor-private-vendor",
                    "privacyblocked",
                ],
                forbiddenMarkers: [
                    "a120-metered-vendor",
                    "a120-metered-quota",
                    "overquota",
                    "a120-dispatch-ready.example.com",
                    "a120-authorization-vendor",
                    "a120-lease-vendor",
                    "a120-lease-denied-budget",
                ]
            ),
            (
                name: "dispatch",
                sources: [dispatchSource, authorizationSource, leaseSource, meteredSource, vendorPolicySource],
                expectedReady: dispatchReady,
                expectedBlocked: dispatchBlocked,
                expectedMarkers: [
                    "a120-dispatch-ready.example.com",
                    "payloaddecisionrejected",
                    "requestdecisionrejected",
                ],
                forbiddenMarkers: [
                    "a120-metered-vendor",
                    "a120-metered-quota",
                    "a120-vendor-ready-vendor",
                    "a120-authorization-vendor",
                    "a120-lease-vendor",
                    "a120-lease-denied-budget",
                ]
            ),
            (
                name: "authorization",
                sources: [authorizationSource, leaseSource, meteredSource, vendorPolicySource, dispatchSource],
                expectedReady: authorizationReady,
                expectedBlocked: authorizationBlocked,
                expectedMarkers: [
                    "a120-authorization-vendor",
                    "a120-authorization-private-vendor",
                    "vendorpolicynotaccepted",
                ],
                forbiddenMarkers: [
                    "a120-metered-vendor",
                    "a120-metered-quota",
                    "a120-vendor-ready-vendor",
                    "a120-dispatch-ready.example.com",
                    "a120-lease-vendor",
                    "a120-lease-denied-budget",
                ]
            ),
            (
                name: "lease",
                sources: [leaseSource, meteredSource, vendorPolicySource, dispatchSource, authorizationSource],
                expectedReady: leaseReady,
                expectedBlocked: leaseBlocked,
                expectedMarkers: [
                    "a120-lease-vendor",
                    "a120-lease-budget",
                    "a120-lease-denied-budget",
                    "explicitbudgetdenied",
                ],
                forbiddenMarkers: [
                    "a120-metered-vendor",
                    "a120-metered-quota",
                    "overquota",
                    "a120-vendor-ready-vendor",
                    "a120-dispatch-ready.example.com",
                    "a120-authorization-vendor",
                ]
            ),
        ]

        for selectionCase in selectionCases {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: selectionCase.sources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )

            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
            }

            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectionCase.name)
            XCTAssertEqual(store.session.messages.count, 0, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedReady, rootReady, selectionCase.name)
            XCTAssertEqual(rootReady, storeReady, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedBlocked, rootBlocked, selectionCase.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectionCase.name)
            for marker in selectionCase.expectedMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for marker in selectionCase.forbiddenMarkers {
                XCTAssertFalse(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for forbidden in meteredEntitlementCrossStageForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectionCase.name): \(forbidden)")
            }
        }
    }

