        XCTAssertTrue(leaseFirstBlockedText.contains("explicitbudgetdenied"))
        XCTAssertTrue(leaseFirstBlockedText.contains("a115-lease-private-vendor"))
        XCTAssertTrue(leaseFirstBlockedText.contains("a115-lease-denied-budget"))
        XCTAssertFalse(leaseFirstBlockedText.contains("a115-vendor-private-vendor"))
        XCTAssertFalse(leaseFirstBlockedText.contains("payloaddecisionrejected"))
        XCTAssertFalse(leaseFirstBlockedText.contains("vendorpolicynotaccepted"))
        XCTAssertFalse(leaseFirstBlockedText.contains("a115-authorization-private-vendor"))

        XCTAssertFalse(selectedStatusText.contains("public coffee"))
        XCTAssertFalse(selectedStatusText.contains("a115-vendor-hidden-vendor"))
        XCTAssertFalse(selectedStatusText.contains("a115-dispatch-hidden.example.com"))
        XCTAssertFalse(selectedStatusText.contains("a115-authorization-hidden-vendor"))
        XCTAssertFalse(selectedStatusText.contains("a115-lease-hidden-vendor"))
        XCTAssertFalse(selectedStatusText.contains("a115-lease-hidden-budget"))
        for forbidden in searchAPITransportLeaseStatusForbiddenFragments() {
            XCTAssertFalse(selectedStatusText.contains(forbidden), forbidden)
        }
    }

