        XCTAssertFalse(dispatchFirstResultText.contains("a95-result.example.com"))

        XCTAssertFalse(selectedStatusText.contains("public coffee"))
        XCTAssertFalse(selectedStatusText.contains("a95-hidden.example.com"))
        XCTAssertFalse(selectedStatusText.contains("a95-dispatch-hidden.example.com"))
    }

    func test_compositionRoot_chatStoreReadsSearchAPIAdapterFixtureBridgeStatusForRenderedRecommendationOnly() throws {
        let readyObject = RecommendationFixtures.placeRoute
        let rejectedObject = RecommendationFixtures.searchResult
        let hiddenRecommendationID = "search-api-fixture-bridge-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [readyObject, rejectedObject]
        )
        let readyResponse = try searchAPIAdapterFixtureBridgeReadyResponse(
            traceID: "a98-search-api-fixture-ready",
            sourceHost: "fixture-rendered.example.com"
        )
        let rejectedResponse = try searchAPIAdapterFixtureBridgeRejectedPrivateResponse(
            traceID: "a98-search-api-fixture-rejected"
        )
        let hiddenResponse = try searchAPIAdapterFixtureBridgeReadyResponse(
            traceID: "a98-search-api-fixture-hidden",
            sourceHost: "fixture-hidden.example.com"
        )
        let source = ServerProviderSearchAPIAdapterFixtureTransportStatusSourceProducer()
            .statusSource(
                responses: [
                    .init(recommendationID: readyObject.id, response: readyResponse),
                    .init(recommendationID: rejectedObject.id, response: rejectedResponse),
                    .init(recommendationID: hiddenRecommendationID, response: hiddenResponse),
                ],
                renderedRecommendationIDs: [
                    readyObject.id,
                    rejectedObject.id,
                ]
            )

        XCTAssertEqual(source.renderedRecommendationIDs, [
            readyObject.id,
            rejectedObject.id,
        ].sorted())
        XCTAssertEqual(readyResponse.state, .fixtureReady)
        XCTAssertTrue(readyResponse.isFixtureReady)
        XCTAssertEqual(rejectedResponse.state, .rejected)
        XCTAssertEqual(rejectedResponse.rejection, .requestDecisionRejected)
        XCTAssertEqual(rejectedResponse.requestDecisionRejection, .privacyBlocked)
        XCTAssertNil(source.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(source.providerStatusPresentation(for: "search-api-fixture-bridge-missing"))
        let preBootstrapReady = try XCTUnwrap(
            source.providerStatusPresentation(for: readyObject.id)
        )
        let preBootstrapRejected = try XCTUnwrap(
            source.providerStatusPresentation(for: rejectedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootReady = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: readyObject.id)
        )
        let rootRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeReady = try XCTUnwrap(
            store.providerStatusPresentation(for: readyObject.id)
        )
        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )

        XCTAssertEqual(store.recommendedMatches, [readyObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapReady.statusLine, rootReady.statusLine)
        XCTAssertEqual(preBootstrapRejected.statusLine, rootRejected.statusLine)
        XCTAssertEqual(rootReady.statusLine, storeReady.statusLine)
        XCTAssertEqual(rootRejected.statusLine, storeRejected.statusLine)
        XCTAssertEqual(storeReady.recommendationID, readyObject.id)
        XCTAssertEqual(storeRejected.recommendationID, rejectedObject.id)
        XCTAssertEqual(storeReady.cardHint, .warning)
        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.remoteProvider, in: storeReady)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeReady)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeReady)?.tone, .positive)
        XCTAssertEqual(badge(.privacyBlocked, in: storeRejected)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeRejected))
        XCTAssertNil(badge(.meteredPremium, in: storeRejected))
        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "search-api-fixture-bridge-missing"))

        let statusText = [
            providerStatusSearchText(storeReady),
            providerStatusSearchText(storeRejected),
        ].joined(separator: "\n")

        XCTAssertTrue(statusText.contains("fixture bridge audit metadata"))
        XCTAssertTrue(statusText.contains("fixture-rendered.example.com"))
        XCTAssertTrue(statusText.contains("no transport or provider runtime has run"))
        XCTAssertTrue(statusText.contains("requestdecisionrejected"))
        XCTAssertTrue(statusText.contains("privacyblocked"))
        XCTAssertFalse(statusText.contains("public coffee"))
        XCTAssertFalse(statusText.contains("fixture-hidden.example.com"))
        for forbidden in searchAPIAdapterFixtureBridgeStatusForbiddenFragments() {
            XCTAssertFalse(statusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPIAdapterFixtureBridgeStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let source = ServerProviderSearchAPIAdapterFixtureTransportStatusSourceProducer()
            .statusSource(
                responses: [
                    .init(
                        recommendationID: renderedObject.id,
                        response: try searchAPIAdapterFixtureBridgeReadyResponse(
                            traceID: "a98-search-api-fixture-order",
                            sourceHost: "fixture-source-order.example.com",
                            costClass: .includedQuota,
                            freshness: .cachedOK
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallback = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "Fallback app-root",
                    statusLine: "Fallback app-root status source selected.",
                    cardHint: .disabled
                ),
            ]
        )

        let fixtureFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source, fallback]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallback, source]
        )
        let fixtureFirstStore = ChatStore(
            recommendationProvider: fixtureFirst.recommendationProvider,
            providerStatusProvider: fixtureFirst.providerStatusProvider,
            feedbackRuntime: fixtureFirst.feedbackRuntime,
            completedRecommendationHandoff: fixtureFirst.completedRecommendationHandoff,
            telemetryEmitter: fixtureFirst.telemetryEmitter,
            capabilityRegistry: fixtureFirst.capabilityRegistry
        )
        let fallbackFirstStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let fixtureFirstStatus = try XCTUnwrap(
            fixtureFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackFirstStatus = try XCTUnwrap(
            fallbackFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fixtureFirstText = providerStatusSearchText(fixtureFirstStatus)
        let fallbackFirstText = providerStatusSearchText(fallbackFirstStatus)

        XCTAssertEqual(source.renderedRecommendationIDs, [renderedObject.id])
        XCTAssertEqual(fixtureFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fixtureFirstStore.session.messages.count, 0)
        XCTAssertEqual(fallbackFirstStore.session.messages.count, 0)
        XCTAssertEqual(fixtureFirstStatus.cardHint, .normal)
        XCTAssertEqual(fallbackFirstStatus.cardHint, .disabled)
        XCTAssertEqual(badge(.includedQuota, in: fixtureFirstStatus)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: fixtureFirstStatus))
        XCTAssertNil(badge(.liveFreshness, in: fixtureFirstStatus))
        XCTAssertTrue(fixtureFirstText.contains("fixture bridge audit metadata"))
        XCTAssertTrue(fixtureFirstText.contains("fixture-source-order.example.com"))
        XCTAssertFalse(fixtureFirstText.contains("fallback app-root"))
        XCTAssertTrue(fallbackFirstText.contains("fallback app-root"))
        XCTAssertFalse(fallbackFirstText.contains("fixture bridge audit metadata"))
        XCTAssertFalse(fallbackFirstText.contains("fixture-source-order.example.com"))
    }

    func test_compositionRoot_searchAPIAdapterFixtureBridgeCrossStageStatusSourcesComposeFirstWins() throws {
        let requestObject = RecommendationFixtures.placeRoute
        let resultObject = RecommendationFixtures.searchResult
        let fixtureHiddenID = "a99-search-api-fixture-hidden"
