    func test_compositionRoot_searchAPIAdapterResultStatusMatrixPassesThroughRenderedRecommendationOnly() throws {
        let freshObject = RecommendationFixtures.placeRoute
        let cachedObject = RecommendationFixtures.searchResult
        let staleObject = RecommendationFixtures.routeBay
        let missingContentObject = RecommendationFixtures.videoTutorial
        let hiddenRecommendationID = "a103-search-api-result-hidden"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [
                freshObject,
                cachedObject,
                staleObject,
                missingContentObject,
            ]
        )
        let freshReceipt = try searchAPIAdapterResultReceipt(
            traceID: "a103-search-api-fresh",
            sourceHost: "a103-fresh.example.com",
            freshness: .livePreferred,
            limitations: [
                "Read-only public information.",
                "Hidden host a103-limitation-hidden.example.com.",
            ]
        )
        let cachedReceipt = try searchAPIAdapterResultReceipt(
            traceID: "a103-search-api-cached",
            sourceHost: "a103-cached.example.com",
            freshness: .cachedOK
        )
        let staleReceipt = try searchAPIAdapterResultReceipt(
            traceID: "a103-search-api-stale",
            sourceHost: "a103-stale.example.com",
            freshness: .cachedOK,
            requestFreshness: .liveRequired
        )
        let missingContentReceipt = try searchAPIAdapterResultReceipt(
            traceID: "a103-search-api-missing-content",
            sourceHost: "a103-missing-content.example.com",
            title: " ",
            snippet: " "
        )
        let hiddenReceipt = try searchAPIAdapterResultReceipt(
            traceID: "a103-search-api-hidden",
            sourceHost: "a103-hidden.example.com"
        )
        let source = ServerProviderSearchAPIAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .resultReceipt(
                        .init(recommendationID: freshObject.id, receipt: freshReceipt)
                    ),
                    .resultReceipt(
                        .init(recommendationID: cachedObject.id, receipt: cachedReceipt)
                    ),
                    .resultReceipt(
                        .init(recommendationID: staleObject.id, receipt: staleReceipt)
                    ),
                    .resultReceipt(
                        .init(
                            recommendationID: missingContentObject.id,
                            receipt: missingContentReceipt
                        )
                    ),
                    .resultReceipt(
                        .init(recommendationID: hiddenRecommendationID, receipt: hiddenReceipt)
                    ),
                ],
                renderedRecommendationIDs: [
                    freshObject.id,
                    cachedObject.id,
                    staleObject.id,
                    missingContentObject.id,
                ]
            )

        XCTAssertEqual(freshReceipt.state, .resultNormalized)
        XCTAssertEqual(freshReceipt.result?.freshness, .livePreferred)
        XCTAssertEqual(cachedReceipt.state, .resultNormalized)
        XCTAssertEqual(cachedReceipt.result?.freshness, .cachedOK)
        XCTAssertEqual(staleReceipt.state, .rejected)
        XCTAssertEqual(staleReceipt.rejection, .resultStaleForLiveRequired)
        XCTAssertEqual(missingContentReceipt.state, .rejected)
        XCTAssertEqual(missingContentReceipt.rejection, .resultContentMissing)
        XCTAssertEqual(source.renderedRecommendationIDs, [
            cachedObject.id,
            freshObject.id,
            missingContentObject.id,
            staleObject.id,
        ].sorted())
        XCTAssertNil(source.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(source.providerStatusPresentation(for: "a103-search-api-result-missing"))

        let preFresh = try XCTUnwrap(source.providerStatusPresentation(for: freshObject.id))
        let preCached = try XCTUnwrap(source.providerStatusPresentation(for: cachedObject.id))
        let preStale = try XCTUnwrap(source.providerStatusPresentation(for: staleObject.id))
        let preMissingContent = try XCTUnwrap(
            source.providerStatusPresentation(for: missingContentObject.id)
        )
        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootFresh = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: freshObject.id)
        )
        let rootCached = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: cachedObject.id)
        )
        let rootStale = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: staleObject.id)
        )
        let rootMissingContent = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingContentObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeFresh = try XCTUnwrap(store.providerStatusPresentation(for: freshObject.id))
        let storeCached = try XCTUnwrap(store.providerStatusPresentation(for: cachedObject.id))
        let storeStale = try XCTUnwrap(store.providerStatusPresentation(for: staleObject.id))
        let storeMissingContent = try XCTUnwrap(
            store.providerStatusPresentation(for: missingContentObject.id)
        )

        XCTAssertEqual(store.recommendedMatches, [
            freshObject,
            cachedObject,
            staleObject,
            missingContentObject,
        ])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preFresh, rootFresh)
        XCTAssertEqual(rootFresh, storeFresh)
        XCTAssertEqual(preCached, rootCached)
        XCTAssertEqual(rootCached, storeCached)
        XCTAssertEqual(preStale, rootStale)
        XCTAssertEqual(rootStale, storeStale)
        XCTAssertEqual(preMissingContent, rootMissingContent)
        XCTAssertEqual(rootMissingContent, storeMissingContent)

        XCTAssertEqual(storeFresh.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeFresh)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeFresh)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeFresh)?.tone, .positive)
        XCTAssertEqual(storeCached.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeCached)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeCached)?.tone, .neutral)
        XCTAssertNil(badge(.liveFreshness, in: storeCached))
        XCTAssertEqual(storeStale.cardHint, .disabled)
        XCTAssertEqual(badge(.staleCache, in: storeStale)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeStale))
        XCTAssertNil(badge(.meteredPremium, in: storeStale))
        XCTAssertEqual(storeMissingContent.cardHint, .disabled)
        XCTAssertEqual(badge(.termsBlocked, in: storeMissingContent)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeMissingContent))
        XCTAssertNil(badge(.meteredPremium, in: storeMissingContent))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: "a103-search-api-result-missing"))
        let freshText = providerStatusSearchText(storeFresh)
        let cachedText = providerStatusSearchText(storeCached)
        let staleText = providerStatusSearchText(storeStale)
        let missingContentText = providerStatusSearchText(storeMissingContent)
        let selectedStatusText = [
            freshText,
            cachedText,
            staleText,
            missingContentText,
        ].joined(separator: "\n")

        XCTAssertTrue(freshText.contains("normalized from cited metadata"))
        XCTAssertTrue(freshText.contains("freshness: livepreferred"))
        XCTAssertTrue(freshText.contains("a103-fresh.example.com"))
        XCTAssertFalse(freshText.contains("a103-limitation-hidden.example.com"))
        XCTAssertTrue(cachedText.contains("normalized from cited metadata"))
        XCTAssertTrue(cachedText.contains("freshness: cachedok"))
        XCTAssertTrue(cachedText.contains("a103-cached.example.com"))
        XCTAssertFalse(cachedText.contains("freshness: livepreferred"))
        XCTAssertTrue(staleText.contains("resultstaleforliverequired"))
        XCTAssertTrue(missingContentText.contains("resultcontentmissing"))
        XCTAssertFalse(selectedStatusText.contains("public coffee"))
        XCTAssertFalse(selectedStatusText.contains("a103-hidden.example.com"))
        XCTAssertFalse(selectedStatusText.contains("a103-limitation-hidden.example.com"))
        XCTAssertTrue(selectedStatusText.contains("no provider runtime has run"))
        for forbidden in searchAPIAdapterStatusForbiddenFragments() {
            XCTAssertFalse(selectedStatusText.contains(forbidden), forbidden)
        }

        let fallback = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                freshObject.id: providerStatusPresentation(
                    for: freshObject.id,
                    label: "A103 fallback",
                    statusLine: "A103 fallback app-root status source selected.",
                    cardHint: .disabled
                ),
            ]
        )
        let sourceFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source, fallback]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallback, source]
        )
        let sourceFirstStore = ChatStore(
            recommendationProvider: sourceFirst.recommendationProvider,
            providerStatusProvider: sourceFirst.providerStatusProvider,
            feedbackRuntime: sourceFirst.feedbackRuntime,
            completedRecommendationHandoff: sourceFirst.completedRecommendationHandoff,
            telemetryEmitter: sourceFirst.telemetryEmitter,
            capabilityRegistry: sourceFirst.capabilityRegistry
        )
        let fallbackFirstStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let sourceFirstText = providerStatusSearchText(
            try XCTUnwrap(sourceFirstStore.providerStatusPresentation(for: freshObject.id))
        )
        let fallbackFirstText = providerStatusSearchText(
            try XCTUnwrap(fallbackFirstStore.providerStatusPresentation(for: freshObject.id))
        )

        XCTAssertTrue(sourceFirstText.contains("normalized from cited metadata"))
        XCTAssertTrue(sourceFirstText.contains("a103-fresh.example.com"))
        XCTAssertFalse(sourceFirstText.contains("a103 fallback"))
        XCTAssertTrue(fallbackFirstText.contains("a103 fallback"))
        XCTAssertFalse(fallbackFirstText.contains("normalized from cited metadata"))
        XCTAssertFalse(fallbackFirstText.contains("a103-fresh.example.com"))
    }

    func test_compositionRoot_chatStoreReadsSearchAPITransportRequestStatusForRenderedRecommendationOnly() throws {
        let preparedObject = RecommendationFixtures.placeRoute
        let rejectedObject = RecommendationFixtures.searchResult
        let hiddenRecommendationID = "a128-transport-request-hidden"
