            costClass: .meteredPremium,
            freshness: .livePreferred,
            resultShape: .organicLinks,
            resultLimit: 5
        )
        let rejectedDecision = searchAPITransportRequestRejectedDecision(
            id: "a128-rejected-authorization",
            reason: .authorizationNotAccepted,
            authorizationRejection: .vendorPolicyNotAccepted,
            leaseRejection: .authorizationNotAccepted
        )
        let hiddenDecision = searchAPITransportRequestPreparedDecision(
            traceID: "a128-hidden",
            vendorID: "a128-hidden-vendor",
            costClass: .includedQuota,
            freshness: .cachedOK,
            resultShape: .answerSummary,
            resultLimit: 2
        )
        let source = ServerProviderSearchAPITransportRequestStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: preparedObject.id, decision: preparedDecision),
                    .init(recommendationID: rejectedObject.id, decision: rejectedDecision),
                    .init(recommendationID: hiddenRecommendationID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [preparedObject.id, rejectedObject.id]
            )

        XCTAssertEqual(
            source.renderedRecommendationIDs,
            [preparedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertNil(source.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        let preBootstrapPrepared = try XCTUnwrap(
            source.providerStatusPresentation(for: preparedObject.id)
        )
        let preBootstrapRejected = try XCTUnwrap(
            source.providerStatusPresentation(for: rejectedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let bootstrapPrepared = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: preparedObject.id)
        )
        let bootstrapRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenRecommendationID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storePrepared = try XCTUnwrap(
            store.providerStatusPresentation(for: preparedObject.id)
        )
        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let selectedStatusText = [
            providerStatusSearchText(storePrepared),
            providerStatusSearchText(storeRejected),
        ].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [preparedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapPrepared, bootstrapPrepared)
        XCTAssertEqual(bootstrapPrepared, storePrepared)
        XCTAssertEqual(preBootstrapRejected, bootstrapRejected)
        XCTAssertEqual(bootstrapRejected, storeRejected)

        XCTAssertEqual(storePrepared.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storePrepared)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storePrepared)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storePrepared)?.tone, .positive)
        XCTAssertTrue(storePrepared.statusLine.contains("transport request prepared"))
        XCTAssertTrue(storePrepared.statusLine.contains("a128-prepared-vendor"))
        XCTAssertTrue(storePrepared.statusLine.contains("a128-prepared-lease"))
        XCTAssertTrue(storePrepared.statusLine.contains("a128-prepared-budget"))
        XCTAssertTrue(storePrepared.statusLine.contains("a128-prepared-metered"))
        XCTAssertTrue(storePrepared.statusLine.contains("Result limit: 5"))
        XCTAssertTrue(storePrepared.statusLine.contains("Source policy: passed"))

        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.unavailable, in: storeRejected)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeRejected))
        XCTAssertNil(badge(.meteredPremium, in: storeRejected))
        XCTAssertTrue(storeRejected.statusLine.contains("authorizationNotAccepted"))
        XCTAssertTrue(storeRejected.statusLine.contains("vendorPolicyNotAccepted"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))
        XCTAssertTrue(selectedStatusText.contains("metadata"))
        XCTAssertTrue(selectedStatusText.contains("no transport or provider runtime has run"))
        XCTAssertFalse(selectedStatusText.contains("public coffee"))
        XCTAssertFalse(selectedStatusText.contains("a128-hidden-vendor"))
        XCTAssertFalse(selectedStatusText.contains("a128-hidden-lease"))
        XCTAssertFalse(selectedStatusText.contains("a128-hidden-budget"))
        XCTAssertFalse(selectedStatusText.contains("a128-hidden-metered"))
        XCTAssertFalse(selectedStatusText.contains("a128-hidden.example.com"))
        for forbidden in searchAPITransportRequestStatusForbiddenFragments() {
            XCTAssertFalse(selectedStatusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPITransportRequestStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let preparedSource = ServerProviderSearchAPITransportRequestStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: searchAPITransportRequestPreparedDecision(
                            traceID: "a128-first",
                            vendorID: "a128-first-vendor",
                            costClass: .includedQuota,
                            freshness: .cachedOK,
                            resultShape: .answerSummary,
                            resultLimit: 3
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let rejectedSource = ServerProviderSearchAPITransportRequestStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: searchAPITransportRequestRejectedDecision(
                            id: "a128-second-rejected",
                            reason: .budgetContextMismatch,
                            requestDecisionRejection: .quotaBlocked,
                            leaseRejection: .explicitBudgetDenied
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let preparedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [preparedSource, rejectedSource]
        )
        let rejectedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [rejectedSource, preparedSource]
        )

        let preparedFirstStore = ChatStore(
            recommendationProvider: preparedFirst.recommendationProvider,
            providerStatusProvider: preparedFirst.providerStatusProvider,
            feedbackRuntime: preparedFirst.feedbackRuntime,
            completedRecommendationHandoff: preparedFirst.completedRecommendationHandoff,
            telemetryEmitter: preparedFirst.telemetryEmitter,
            capabilityRegistry: preparedFirst.capabilityRegistry
        )
        let rejectedFirstStore = ChatStore(
            recommendationProvider: rejectedFirst.recommendationProvider,
            providerStatusProvider: rejectedFirst.providerStatusProvider,
            feedbackRuntime: rejectedFirst.feedbackRuntime,
            completedRecommendationHandoff: rejectedFirst.completedRecommendationHandoff,
            telemetryEmitter: rejectedFirst.telemetryEmitter,
            capabilityRegistry: rejectedFirst.capabilityRegistry
        )
        let preparedSelected = try XCTUnwrap(
            preparedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let rejectedSelected = try XCTUnwrap(
            rejectedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let preparedText = providerStatusSearchText(preparedSelected)
        let rejectedText = providerStatusSearchText(rejectedSelected)

        XCTAssertEqual(preparedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(rejectedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(preparedSelected.cardHint, .normal)
        XCTAssertEqual(badge(.includedQuota, in: preparedSelected)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: preparedSelected))
        XCTAssertNil(badge(.liveFreshness, in: preparedSelected))
        XCTAssertTrue(preparedText.contains("a128-first-vendor"))
        XCTAssertTrue(preparedText.contains("a128-first-lease"))
        XCTAssertTrue(preparedText.contains("a128-first-budget"))
        XCTAssertTrue(preparedText.contains("a128-first-metered"))
        XCTAssertFalse(preparedText.contains("a128-second-rejected"))
        XCTAssertFalse(preparedText.contains("budgetcontextmismatch"))
        XCTAssertFalse(preparedText.contains("explicitbudgetdenied"))

        XCTAssertEqual(rejectedSelected.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: rejectedSelected)?.tone, .warning)
        XCTAssertTrue(rejectedText.contains("a128-second-rejected"))
        XCTAssertTrue(rejectedText.contains("budgetcontextmismatch"))
        XCTAssertTrue(rejectedText.contains("quotablocked"))
        XCTAssertTrue(rejectedText.contains("explicitbudgetdenied"))
        XCTAssertFalse(rejectedText.contains("a128-first-vendor"))
        XCTAssertFalse(rejectedText.contains("a128-first-lease"))
        XCTAssertFalse(rejectedText.contains("a128-first-budget"))
        XCTAssertFalse(rejectedText.contains("a128-first-metered"))
        XCTAssertFalse(rejectedText.contains("transport request prepared"))
    }

    func test_compositionRoot_chatStoreReadsSearchAPITransportResponseStatusForRenderedRecommendationOnly() throws {
