        XCTAssertEqual(
            source.renderedRecommendationIDs,
            [acceptedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertNil(source.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        let preBootstrapAccepted = try XCTUnwrap(
            source.providerStatusPresentation(for: acceptedObject.id)
        )
        let preBootstrapRejected = try XCTUnwrap(
