                .providerStatusPresentation(for: missingID)
        )

        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeAccepted = try XCTUnwrap(
            store.providerStatusPresentation(for: acceptedObject.id)
        )
        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let selectedStatusText = [
            providerStatusSearchText(storeAccepted),
            providerStatusSearchText(storeRejected),
        ].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [acceptedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(preBootstrapAccepted, bootstrapAccepted)
        XCTAssertEqual(bootstrapAccepted, storeAccepted)
        XCTAssertEqual(preBootstrapRejected, bootstrapRejected)
        XCTAssertEqual(bootstrapRejected, storeRejected)

        XCTAssertEqual(storeAccepted.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeAccepted)?.tone, .neutral)
        XCTAssertEqual(badge(.meteredPremium, in: storeAccepted)?.tone, .neutral)
        XCTAssertEqual(badge(.liveFreshness, in: storeAccepted)?.tone, .positive)
        XCTAssertTrue(storeAccepted.statusLine.contains("transport response accepted"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a133-accepted-vendor"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a133-accepted-response"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a133-accepted-transport-request"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a133-accepted-lease"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a133-accepted-budget"))
        XCTAssertTrue(storeAccepted.statusLine.contains("a133-accepted-metered"))
        XCTAssertTrue(storeAccepted.statusLine.contains("Requested result limit: 5"))
        XCTAssertTrue(storeAccepted.statusLine.contains("Returned results: 2"))
        XCTAssertTrue(storeAccepted.statusLine.contains("Citations: 3"))
        XCTAssertTrue(storeAccepted.statusLine.contains("Source policy: passed"))

        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.unavailable, in: storeRejected)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeRejected))
        XCTAssertNil(badge(.meteredPremium, in: storeRejected))
        XCTAssertTrue(storeRejected.statusLine.contains("adapterResultRejected"))
        XCTAssertTrue(storeRejected.statusLine.contains("resultLimitMismatch"))
        XCTAssertTrue(storeRejected.statusLine.contains("resultCitationMissing"))

        XCTAssertNil(store.providerStatusPresentation(for: hiddenRecommendationID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))
        XCTAssertTrue(selectedStatusText.contains("metadata"))
        XCTAssertTrue(selectedStatusText.contains("no transport or provider runtime has run"))
        XCTAssertFalse(selectedStatusText.contains("public coffee"))
        XCTAssertFalse(selectedStatusText.contains("a133-hidden-vendor"))
        XCTAssertFalse(selectedStatusText.contains("a133-hidden-response"))
        XCTAssertFalse(selectedStatusText.contains("a133-hidden-lease"))
        XCTAssertFalse(selectedStatusText.contains("a133-hidden-budget"))
        XCTAssertFalse(selectedStatusText.contains("a133-hidden-metered"))
        XCTAssertFalse(selectedStatusText.contains("a133-hidden.example.com"))
        XCTAssertFalse(selectedStatusText.contains("a133-accepted.example.com"))
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(selectedStatusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPITransportResponseStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let acceptedSource = ServerProviderSearchAPITransportResponseStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: searchAPITransportResponseAcceptedDecision(
                            traceID: "a133-first",
                            vendorID: "a133-first-vendor",
                            costClass: .includedQuota,
                            freshness: .cachedOK,
                            resultShape: .answerSummary,
                            requestedResultLimit: 3,
                            returnedResultCount: 1,
                            citationCount: 1
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let rejectedSource = ServerProviderSearchAPITransportResponseStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: searchAPITransportResponseRejectedDecision(
                            id: "a133-second-rejected",
                            reason: .budgetMetadataMissing,
                            transportRequestRejection: .citationPolicyMissing,
                            adapterResultRejection: .resultCitationMissing
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let acceptedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [acceptedSource, rejectedSource]
        )
        let rejectedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [rejectedSource, acceptedSource]
        )

        let acceptedFirstStore = ChatStore(
            recommendationProvider: acceptedFirst.recommendationProvider,
            providerStatusProvider: acceptedFirst.providerStatusProvider,
            feedbackRuntime: acceptedFirst.feedbackRuntime,
            completedRecommendationHandoff: acceptedFirst.completedRecommendationHandoff,
            telemetryEmitter: acceptedFirst.telemetryEmitter,
            capabilityRegistry: acceptedFirst.capabilityRegistry
        )
        let rejectedFirstStore = ChatStore(
            recommendationProvider: rejectedFirst.recommendationProvider,
            providerStatusProvider: rejectedFirst.providerStatusProvider,
            feedbackRuntime: rejectedFirst.feedbackRuntime,
            completedRecommendationHandoff: rejectedFirst.completedRecommendationHandoff,
            telemetryEmitter: rejectedFirst.telemetryEmitter,
            capabilityRegistry: rejectedFirst.capabilityRegistry
        )
        let acceptedRootSelected = try XCTUnwrap(
            acceptedFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let rejectedRootSelected = try XCTUnwrap(
            rejectedFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let acceptedSelected = try XCTUnwrap(
            acceptedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let rejectedSelected = try XCTUnwrap(
            rejectedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let acceptedText = providerStatusSearchText(acceptedSelected)
        let rejectedText = providerStatusSearchText(rejectedSelected)

        XCTAssertEqual(acceptedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(rejectedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(acceptedRootSelected, acceptedSelected)
        XCTAssertEqual(rejectedRootSelected, rejectedSelected)
        XCTAssertEqual(acceptedSelected.cardHint, .normal)
        XCTAssertEqual(badge(.includedQuota, in: acceptedSelected)?.tone, .neutral)
        XCTAssertNil(badge(.meteredPremium, in: acceptedSelected))
        XCTAssertNil(badge(.liveFreshness, in: acceptedSelected))
        XCTAssertTrue(acceptedText.contains("a133-first-vendor"))
        XCTAssertTrue(acceptedText.contains("a133-first-response"))
        XCTAssertTrue(acceptedText.contains("a133-first-transport-request"))
        XCTAssertTrue(acceptedText.contains("a133-first-lease"))
        XCTAssertTrue(acceptedText.contains("a133-first-budget"))
        XCTAssertTrue(acceptedText.contains("a133-first-metered"))
        XCTAssertFalse(acceptedText.contains("a133-second-rejected"))
        XCTAssertFalse(acceptedText.contains("budgetmetadatamissing"))
        XCTAssertFalse(acceptedText.contains("citationpolicymissing"))
        XCTAssertFalse(acceptedText.contains("resultcitationmissing"))

        XCTAssertEqual(rejectedSelected.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: rejectedSelected)?.tone, .warning)
        XCTAssertTrue(rejectedText.contains("a133-second-rejected"))
        XCTAssertTrue(rejectedText.contains("budgetmetadatamissing"))
        XCTAssertTrue(rejectedText.contains("citationpolicymissing"))
        XCTAssertTrue(rejectedText.contains("resultcitationmissing"))
        XCTAssertFalse(rejectedText.contains("a133-first-vendor"))
        XCTAssertFalse(rejectedText.contains("a133-first-response"))
        XCTAssertFalse(rejectedText.contains("a133-first-transport-request"))
        XCTAssertFalse(rejectedText.contains("a133-first-lease"))
        XCTAssertFalse(rejectedText.contains("a133-first-budget"))
        XCTAssertFalse(rejectedText.contains("a133-first-metered"))
        XCTAssertFalse(rejectedText.contains("transport response accepted"))
    }

    func test_compositionRoot_searchAPITransportResponseCrossStageStatusSourcesComposeFirstWins() throws {
