                    "overquota",
                    "a134-vendor-ready-vendor",
                    "a134-vendor-private-vendor",
                    "a134-dispatch-ready-request",
                    "a134-authorization-vendor",
                    "a134-lease-vendor",
                    "a134-lease-denied-budget",
                    "a134-request-vendor",
                    "a134-request-blocked",
                ]
            ),
        ]

        for selectionCase in selectionCases {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: selectionCase.sources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )

            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
            }

            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectionCase.name)
            XCTAssertEqual(store.session.messages.count, 0, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedReady, rootReady, selectionCase.name)
            XCTAssertEqual(rootReady, storeReady, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedBlocked, rootBlocked, selectionCase.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectionCase.name)
            for marker in selectionCase.expectedMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for marker in selectionCase.forbiddenMarkers {
                XCTAssertFalse(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for hiddenMarker in [
                "a134-metered-hidden-vendor",
                "a134-vendor-hidden-vendor",
                "a134-dispatch-hidden",
                "a134-authorization-hidden-vendor",
                "a134-lease-hidden-vendor",
                "a134-request-hidden-vendor",
                "a134-request-hidden.example.com",
                "a134-response-hidden-vendor",
                "a134-response-hidden-response",
                "a134-response-hidden-lease",
                "a134-response-hidden-budget",
                "a134-response-hidden-metered",
                "a134-response-hidden.example.com",
            ] {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectionCase.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectionCase.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_searchAPITransportRequestCrossStageStatusSourcesComposeFirstWins() throws {
        let readyObject = RecommendationFixtures.placeRoute
        let blockedObject = RecommendationFixtures.searchResult
        let meteredHiddenID = "a129-metered-hidden"
        let vendorHiddenID = "a129-vendor-hidden"
        let dispatchHiddenID = "a129-dispatch-hidden"
        let authorizationHiddenID = "a129-authorization-hidden"
        let leaseHiddenID = "a129-lease-hidden"
        let requestHiddenID = "a129-request-hidden"
        let missingID = "a129-cross-stage-missing"
        let renderedIDs = [readyObject.id, blockedObject.id]
        let hiddenIDs = [
            meteredHiddenID,
            vendorHiddenID,
            dispatchHiddenID,
            authorizationHiddenID,
            leaseHiddenID,
            requestHiddenID,
            missingID,
        ]
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [readyObject, blockedObject]
        )
        let meteredSource = ServerProviderMeteredEntitlementStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: meteredEntitlementAcceptedDecision(
                            id: "a129-metered-ready",
                            request: meteredEntitlementUsageRequest(
                                id: "a129-metered-ready",
                                vendorID: "a129-metered-vendor",
                                estimatedUnits: 6,
                                costClass: .meteredPremium
                            ),
                            snapshot: meteredEntitlementSnapshot(
                                id: "a129-metered-ready-snapshot",
                                vendorID: "a129-metered-vendor",
                                costClass: .meteredPremium,
                                quotaPeriodID: "a129-metered-quota",
                                reservedUnits: 5,
                                remainingUnits: 55
                            )
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        decision: meteredEntitlementRejectedDecision(
                            request: meteredEntitlementUsageRequest(
                                id: "a129-metered-blocked",
                                estimatedUnits: 91
                            ),
                            snapshot: meteredEntitlementSnapshot(remainingUnits: 90),
                            expectedReason: .overQuota
                        )
                    ),
                    .init(
                        recommendationID: meteredHiddenID,
                        decision: meteredEntitlementAcceptedDecision(
                            id: "a129-metered-hidden",
                            request: meteredEntitlementUsageRequest(
                                id: "a129-metered-hidden",
                                vendorID: "a129-metered-hidden-vendor"
                            ),
                            snapshot: meteredEntitlementSnapshot(
                                id: "a129-metered-hidden-snapshot",
                                vendorID: "a129-metered-hidden-vendor"
                            )
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let vendorPolicySource = ServerProviderSearchAPIVendorPolicyStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: searchAPIVendorPolicyAcceptedDecision(
                            vendorID: "a129-vendor-ready-vendor"
