                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        decision: searchAPIVendorPolicyRejectedDecision(
                            vendorID: "a129-vendor-private-vendor",
                            context: searchAPIVendorPolicyContext(privacyClass: .private),
                            vendor: searchAPIVendorPolicyDescriptor(
                                id: "a129-vendor-private-vendor"
                            )
                        )
                    ),
                    .init(
                        recommendationID: vendorHiddenID,
                        decision: searchAPIVendorPolicyAcceptedDecision(
                            vendorID: "a129-vendor-hidden-vendor"
