                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let dispatchSource = ServerProviderSearchAPIAdapterPayloadDispatchStatusSourceProducer()
            .statusSource(
                receipts: [
                    .init(
                        recommendationID: readyObject.id,
                        receipt: searchAPIAdapterPayloadDispatchEligibleReceiptWithoutSourceHost(
                            traceID: "a129-dispatch-ready"
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        receipt: try searchAPIAdapterPayloadDispatchBlockedReceipt(
                            traceID: "a129-dispatch-blocked"
                        )
                    ),
                    .init(
                        recommendationID: dispatchHiddenID,
                        receipt: searchAPIAdapterPayloadDispatchEligibleReceiptWithoutSourceHost(
                            traceID: "a129-dispatch-hidden"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let authorizationSource = ServerProviderSearchAPIVendorPolicyDispatchAuthorizationStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        authorization: try searchAPIVendorDispatchAuthorizationAccepted(
