                ),
                expectedBadge: .privacyBlocked,
                expectedHint: .disabled,
                expectedMarkers: [
                    "blocked by metadata policy",
                    "a137-google-rejected-adapter",
                    "privacyblocked",
                ],
                forbiddenMarkers: [
                    "preflight accepted",
                    "a137-google-adapter",
                ]
            ),
            (
                name: "crawler rejected",
                recommendationID: crawlerRejectedObject.id,
                decision: transportAdapterRejectedDecision(
                    id: "a137-crawler-rejected",
                    adapterID: "a137-crawler-rejected-adapter",
                    providerFamily: .crawler,
                    capability: .crawlerFetch,
                    costClass: .meteredPremium,
                    membershipTier: .pro,
                    reason: .experimentalProviderDisabled
                ),
                expectedBadge: .unavailable,
                expectedHint: .disabled,
                expectedMarkers: [
                    "blocked by metadata policy",
                    "a137-crawler-rejected-adapter",
                    "experimentalproviderdisabled",
                ],
                forbiddenMarkers: [
                    "preflight accepted",
                    "a137-crawler-adapter",
                ]
            ),
            (
                name: "mcp rejected",
                recommendationID: mcpRejectedObject.id,
                decision: transportAdapterRejectedDecision(
                    id: "a137-mcp-rejected",
                    adapterID: "a137-mcp-rejected-adapter",
                    providerFamily: .mcp,
                    capability: .mcpTool,
                    costClass: .includedQuota,
                    membershipTier: .pro,
                    reason: .confirmationMissing
                ),
                expectedBadge: .termsBlocked,
                expectedHint: .disabled,
                expectedMarkers: [
                    "blocked by metadata policy",
                    "a137-mcp-rejected-adapter",
                    "confirmationmissing",
                ],
                forbiddenMarkers: [
                    "preflight accepted",
                    "a137-mcp-adapter",
                ]
            ),
        ]
        let hiddenDecision = transportAdapterAcceptedDecision(
            id: "a137-hidden",
            adapterID: "a137-hidden-adapter",
            providerFamily: .searchAPI,
            capability: .webSearch,
            costClass: .meteredPremium,
            membershipTier: .plus,
            meteredDecisionID: "a137-hidden-metered",
            transportLeaseID: "a137-hidden-lease"
        )
        let source = ServerProviderTransportAdapterStatusSourceProducer()
            .statusSource(
                inputs: cases.map { entry in
                    .init(
                        recommendationID: entry.recommendationID,
                        decision: entry.decision
                    )
                } + [
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: renderedIDs
            )

        XCTAssertEqual(source.renderedRecommendationIDs, renderedIDs.sorted())
        XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )

        XCTAssertEqual(store.recommendedMatches, renderedObjects)
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )
        XCTAssertNil(store.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))

        var selectedStatusText: [String] = []
        for entry in cases {
            let sourcePresentation = try XCTUnwrap(
                source.providerStatusPresentation(for: entry.recommendationID),
                entry.name
            )
            let rootPresentation = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: entry.recommendationID),
                entry.name
            )
            let storePresentation = try XCTUnwrap(
                store.providerStatusPresentation(for: entry.recommendationID),
                entry.name
            )
            let text = providerStatusSearchText(storePresentation)

            XCTAssertEqual(sourcePresentation, rootPresentation, entry.name)
            XCTAssertEqual(rootPresentation, storePresentation, entry.name)
            XCTAssertEqual(storePresentation.cardHint, entry.expectedHint, entry.name)
            XCTAssertEqual(
                badge(entry.expectedBadge, in: storePresentation)?.tone,
                entry.expectedHint == .disabled ? .warning : .neutral,
                entry.name
            )
            XCTAssertTrue(text.contains("value-only metadata") || text.contains("metadata policy"), entry.name)
            XCTAssertTrue(text.contains("no provider transport has run"), entry.name)
            for marker in entry.expectedMarkers {
                XCTAssertTrue(text.contains(marker), "\(entry.name): \(marker)")
            }
            for marker in entry.forbiddenMarkers {
                XCTAssertFalse(text.contains(marker), "\(entry.name): \(marker)")
            }
            selectedStatusText.append(text)
        }

        let allText = selectedStatusText.joined(separator: "\n")
        for hiddenMarker in [
            "a137-hidden-adapter",
            "a137-hidden-request",
            "a137-hidden-metered",
            "a137-hidden-lease",
        ] {
            XCTAssertFalse(allText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in transportAdapterStatusForbiddenFragments() {
            XCTAssertFalse(allText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_transportAdapterPreflightStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.searchResult
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let acceptedSource = ServerProviderTransportAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: transportAdapterAcceptedDecision(
                            id: "a137-first",
                            adapterID: "a137-first-adapter",
                            providerFamily: .searchAPI,
                            capability: .webSearch,
                            costClass: .meteredPremium,
                            membershipTier: .plus,
                            meteredDecisionID: "a137-first-metered",
                            transportLeaseID: "a137-first-lease"
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let staleSource = ServerProviderTransportAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: transportAdapterRejectedDecision(
                            id: "a137-second",
                            adapterID: "a137-second-stale-adapter",
                            providerFamily: .crawler,
                            capability: .crawlerFetch,
                            costClass: .includedQuota,
                            membershipTier: .pro,
                            reason: .experimentalProviderDisabled,
                            meteredDecisionID: "a137-second-metered",
                            transportLeaseID: "a137-second-lease"
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let acceptedFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [acceptedSource, staleSource]
        )
        let staleFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [staleSource, acceptedSource]
        )
        let acceptedFirstStore = ChatStore(
            recommendationProvider: acceptedFirst.recommendationProvider,
            providerStatusProvider: acceptedFirst.providerStatusProvider,
            feedbackRuntime: acceptedFirst.feedbackRuntime,
            completedRecommendationHandoff: acceptedFirst.completedRecommendationHandoff,
            telemetryEmitter: acceptedFirst.telemetryEmitter,
            capabilityRegistry: acceptedFirst.capabilityRegistry
        )
        let staleFirstStore = ChatStore(
            recommendationProvider: staleFirst.recommendationProvider,
            providerStatusProvider: staleFirst.providerStatusProvider,
            feedbackRuntime: staleFirst.feedbackRuntime,
            completedRecommendationHandoff: staleFirst.completedRecommendationHandoff,
            telemetryEmitter: staleFirst.telemetryEmitter,
            capabilityRegistry: staleFirst.capabilityRegistry
        )
        let acceptedRootSelected = try XCTUnwrap(
            acceptedFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let staleRootSelected = try XCTUnwrap(
            staleFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let acceptedSelected = try XCTUnwrap(
            acceptedFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let staleSelected = try XCTUnwrap(
            staleFirstStore.providerStatusPresentation(for: renderedObject.id)
        )
        let acceptedText = providerStatusSearchText(acceptedSelected)
        let staleText = providerStatusSearchText(staleSelected)

        XCTAssertEqual(acceptedFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(staleFirstStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(acceptedRootSelected, acceptedSelected)
        XCTAssertEqual(staleRootSelected, staleSelected)
        XCTAssertEqual(acceptedSelected.cardHint, .warning)
        XCTAssertEqual(staleSelected.cardHint, .disabled)
        XCTAssertEqual(badge(.meteredPremium, in: acceptedSelected)?.tone, .neutral)
        XCTAssertEqual(badge(.unavailable, in: staleSelected)?.tone, .warning)

        for marker in [
            "preflight accepted",
            "a137-first-adapter",
            "a137-first-request",
            "searchapi",
            "websearch",
            "meteredpremium",
            "a137-first-metered",
            "a137-first-lease",
        ] {
            XCTAssertTrue(acceptedText.contains(marker), marker)
        }
        for staleMarker in [
            "a137-second-stale-adapter",
            "a137-second-request",
            "crawler",
            "crawlerfetch",
            "includedquota",
            "experimentalproviderdisabled",
            "a137-second-metered",
            "a137-second-lease",
            "blocked by metadata policy",
        ] {
            XCTAssertFalse(acceptedText.contains(staleMarker), staleMarker)
        }

        for marker in [
            "blocked by metadata policy",
            "a137-second-stale-adapter",
            "a137-second-request",
            "crawler",
            "crawlerfetch",
            "includedquota",
            "experimentalproviderdisabled",
            "a137-second-metered",
            "a137-second-lease",
        ] {
            XCTAssertTrue(staleText.contains(marker), marker)
        }
        for earlierMarker in [
            "a137-first-adapter",
            "a137-first-request",
            "searchapi",
            "websearch",
            "meteredpremium",
            "a137-first-metered",
            "a137-first-lease",
            "preflight accepted",
        ] {
            XCTAssertFalse(staleText.contains(earlierMarker), earlierMarker)
        }
        for forbidden in transportAdapterStatusForbiddenFragments() {
            XCTAssertFalse(acceptedText.contains(forbidden), forbidden)
            XCTAssertFalse(staleText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_transportAdapterPreflightComposesWithSearchAPIStatusStackFirstWins() throws {
        let readyObject = RecommendationFixtures.placeRoute
        let blockedObject = RecommendationFixtures.searchResult
