        let preflightSource = ServerProviderTransportAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: transportAdapterAcceptedDecision(
                            id: "a138-preflight-ready",
