        let dispatchReady = try XCTUnwrap(dispatchSource.providerStatusPresentation(for: readyObject.id))
        let dispatchBlocked = try XCTUnwrap(dispatchSource.providerStatusPresentation(for: blockedObject.id))
        let authorizationReady = try XCTUnwrap(authorizationSource.providerStatusPresentation(for: readyObject.id))
        let authorizationBlocked = try XCTUnwrap(authorizationSource.providerStatusPresentation(for: blockedObject.id))
        let leaseReady = try XCTUnwrap(leaseSource.providerStatusPresentation(for: readyObject.id))
        let leaseBlocked = try XCTUnwrap(leaseSource.providerStatusPresentation(for: blockedObject.id))
        let requestReady = try XCTUnwrap(requestSource.providerStatusPresentation(for: readyObject.id))
        let requestBlocked = try XCTUnwrap(requestSource.providerStatusPresentation(for: blockedObject.id))
        let responseReady = try XCTUnwrap(responseSource.providerStatusPresentation(for: readyObject.id))
        let responseBlocked = try XCTUnwrap(responseSource.providerStatusPresentation(for: blockedObject.id))
        let preflightReady = try XCTUnwrap(preflightSource.providerStatusPresentation(for: readyObject.id))
        let preflightBlocked = try XCTUnwrap(preflightSource.providerStatusPresentation(for: blockedObject.id))
        let fallbackReady = try XCTUnwrap(fallbackSource.providerStatusPresentation(for: readyObject.id))
        let fallbackBlocked = try XCTUnwrap(fallbackSource.providerStatusPresentation(for: blockedObject.id))
        let selectionCases: [
            (
                name: String,
                sources: [any ProviderStatusProviding],
                expectedReady: ProviderStatusPresentation,
                expectedBlocked: ProviderStatusPresentation,
                expectedMarkers: [String],
