                    "a138-authorization-vendor",
                    "a138-lease-vendor",
                    "a138-request-vendor",
                    "a138-response-vendor",
                    "a138-fallback-ready",
                ]
            ),
            (
                name: "fallback",
                sources: [
                    fallbackSource,
                    preflightSource,
                    responseSource,
                    requestSource,
                    leaseSource,
                    authorizationSource,
                    dispatchSource,
                    vendorPolicySource,
                    meteredSource,
                ],
                expectedReady: fallbackReady,
                expectedBlocked: fallbackBlocked,
                expectedMarkers: [
                    "a138 fallback ready",
                    "a138 fallback blocked",
                ],
                forbiddenMarkers: [
                    "a138-metered-vendor",
                    "a138-vendor-ready-vendor",
                    "a138-dispatch-ready-request",
                    "a138-authorization-vendor",
                    "a138-lease-vendor",
                    "a138-request-vendor",
                    "a138-response-vendor",
                    "a138-preflight-ready-adapter",
                ]
            ),
        ]

        for selectionCase in selectionCases {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: selectionCase.sources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )

            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
            }

            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectionCase.name)
            XCTAssertEqual(store.session.messages.count, 0, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedReady, rootReady, selectionCase.name)
            XCTAssertEqual(rootReady, storeReady, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedBlocked, rootBlocked, selectionCase.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectionCase.name)
            for marker in selectionCase.expectedMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for marker in selectionCase.forbiddenMarkers {
                XCTAssertFalse(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for hiddenMarker in [
                "a138-metered-hidden-vendor",
                "a138-vendor-hidden-vendor",
                "a138-dispatch-hidden",
                "a138-authorization-hidden-vendor",
                "a138-lease-hidden-vendor",
                "a138-request-hidden-vendor",
                "a138-response-hidden-vendor",
                "a138-response-hidden-response",
                "a138-preflight-hidden-adapter",
                "a138-preflight-hidden-metered",
                "a138-preflight-hidden-lease",
            ] {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectionCase.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectionCase.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_nonSearchTransportAdapterPreflightComposesWithFallbackFirstWins() throws {
        let renderedObject = RecommendationFixtures.placeRoute
        let hiddenID = "a138-gaode-hidden"
        let missingID = "a138-gaode-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let preflightSource = ServerProviderTransportAdapterStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        decision: transportAdapterAcceptedDecision(
                            id: "a138-gaode-ready",
                            adapterID: "a138-gaode-ready-adapter",
                            providerFamily: .gaode,
                            capability: .localServiceSearch,
                            costClass: .includedQuota,
                            membershipTier: .plus
                        )
                    ),
                    .init(
                        recommendationID: hiddenID,
                        decision: transportAdapterRejectedDecision(
                            id: "a138-gaode-hidden",
                            adapterID: "a138-gaode-hidden-adapter",
                            providerFamily: .gaode,
                            capability: .localServiceSearch,
                            costClass: .includedQuota,
                            membershipTier: .plus,
                            reason: .includedQuotaExhausted
                        )
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "A138 gaode fallback",
                    statusLine: "A138 stale non-search fallback selected."
                ),
            ]
        )
        let preflightFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [preflightSource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, preflightSource]
        )
        let preflightStore = ChatStore(
            recommendationProvider: preflightFirst.recommendationProvider,
            providerStatusProvider: preflightFirst.providerStatusProvider,
            feedbackRuntime: preflightFirst.feedbackRuntime,
            completedRecommendationHandoff: preflightFirst.completedRecommendationHandoff,
            telemetryEmitter: preflightFirst.telemetryEmitter,
            capabilityRegistry: preflightFirst.capabilityRegistry
        )
        let fallbackStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let preflightRoot = try XCTUnwrap(
            preflightFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackRoot = try XCTUnwrap(
            fallbackFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let preflightSelected = try XCTUnwrap(
            preflightStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackSelected = try XCTUnwrap(
            fallbackStore.providerStatusPresentation(for: renderedObject.id)
        )
        let preflightText = providerStatusSearchText(preflightSelected)
        let fallbackText = providerStatusSearchText(fallbackSelected)

        XCTAssertEqual(preflightSource.renderedRecommendationIDs, [renderedObject.id])
        XCTAssertNil(preflightSource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(preflightSource.providerStatusPresentation(for: missingID))
        XCTAssertNil(
            preflightFirst.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(preflightStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(preflightStore.providerStatusPresentation(for: missingID))
        XCTAssertNil(fallbackStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(fallbackStore.providerStatusPresentation(for: missingID))
        XCTAssertEqual(preflightStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(preflightRoot, preflightSelected)
        XCTAssertEqual(fallbackRoot, fallbackSelected)

        XCTAssertTrue(preflightText.contains("preflight accepted"))
        XCTAssertTrue(preflightText.contains("a138-gaode-ready-adapter"))
        XCTAssertTrue(preflightText.contains("a138-gaode-ready-request"))
        XCTAssertTrue(preflightText.contains("gaode"))
        XCTAssertTrue(preflightText.contains("localservicesearch"))
        XCTAssertTrue(preflightText.contains("includedquota"))
        XCTAssertFalse(preflightText.contains("a138 gaode fallback"))
        XCTAssertFalse(preflightText.contains("stale non-search fallback"))
        XCTAssertFalse(preflightText.contains("a138-gaode-hidden-adapter"))
        XCTAssertFalse(preflightText.contains("includedquotaexhausted"))

        XCTAssertTrue(fallbackText.contains("a138 gaode fallback"))
        XCTAssertTrue(fallbackText.contains("stale non-search fallback"))
        XCTAssertFalse(fallbackText.contains("a138-gaode-ready-adapter"))
        XCTAssertFalse(fallbackText.contains("a138-gaode-ready-request"))
        XCTAssertFalse(fallbackText.contains("includedquotaexhausted"))
        for forbidden in transportAdapterStatusForbiddenFragments() {
            XCTAssertFalse(preflightText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_chatStoreReadsTransportAuditStatusForRenderedRecommendationOnly() throws {
        let searchObject = RecommendationFixtures.placeRoute
        let modelObject = RecommendationFixtures.answerCard
        let blockedObject = RecommendationFixtures.searchResult
        let hiddenID = "a142-audit-hidden"
        let missingID = "a142-audit-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [searchObject, modelObject, blockedObject]
        )
        let source = ServerProviderTransportAuditTraceStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: searchObject.id,
                        event: transportAuditAcceptedEvent(
                            renderedRecommendationID: searchObject.id,
                            family: .searchAPI,
                            capability: .webSearch,
                            costClass: .meteredPremium,
                            sourcePolicySummary: transportAuditSourcePolicy(
                                id: "a142-search-source-policy"
                            ),
                            statusSourceID: "a142-search-status-source"
                        )
                    ),
                    .init(
                        recommendationID: modelObject.id,
                        event: transportAuditAcceptedEvent(
                            renderedRecommendationID: modelObject.id,
                            family: .remoteModel,
                            capability: .remoteModelCompletion,
                            costClass: .meteredPremium,
                            statusSourceID: "a142-model-status-source",
                            confirmationState: .confirmed(artifactID: "a142-model-confirmed"),
                            requiresUserConfirmation: true
                        )
                    ),
                    .init(
                        recommendationID: blockedObject.id,
                        event: transportAuditRejectedEvent(
                            renderedRecommendationID: blockedObject.id,
                            family: .searchAPI,
                            capability: .webSearch,
                            costClass: .meteredPremium,
                            privacyClass: .health,
                            sourcePolicySummary: transportAuditSourcePolicy(
                                id: "a142-blocked-source-policy"
                            ),
                            statusSourceID: "a142-blocked-status-source"
                        )
                    ),
                    .init(
                        recommendationID: hiddenID,
                        event: transportAuditAcceptedEvent(
                            renderedRecommendationID: hiddenID,
                            family: .mcp,
                            capability: .mcpTool,
                            costClass: .includedQuota,
                            statusSourceID: "a142-hidden-status-source",
                            confirmationState: .confirmed(artifactID: "a142-hidden-confirmed"),
                            enabledReservedProviderFamilies: [.mcp]
                        )
                    ),
                ],
                renderedRecommendationIDs: [
                    searchObject.id,
                    modelObject.id,
                    blockedObject.id,
                ]
            )
        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )

        let rootSearch = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: searchObject.id)
        )
        let rootModel = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: modelObject.id)
        )
        let rootBlocked = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        let storeSearch = try XCTUnwrap(
            store.providerStatusPresentation(for: searchObject.id)
        )
        let storeModel = try XCTUnwrap(
            store.providerStatusPresentation(for: modelObject.id)
        )
        let storeBlocked = try XCTUnwrap(
            store.providerStatusPresentation(for: blockedObject.id)
        )
        let searchText = providerStatusSearchText(storeSearch)
        let modelText = providerStatusSearchText(storeModel)
        let blockedText = providerStatusSearchText(storeBlocked)

        XCTAssertEqual(store.recommendedMatches, [searchObject, modelObject, blockedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(rootSearch, storeSearch)
        XCTAssertEqual(rootModel, storeModel)
        XCTAssertEqual(rootBlocked, storeBlocked)
        XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(store.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))

        XCTAssertEqual(storeSearch.cardHint, .warning)
        XCTAssertEqual(storeModel.cardHint, .warning)
        XCTAssertEqual(storeBlocked.cardHint, .disabled)
        XCTAssertEqual(badge(.meteredPremium, in: storeSearch)?.tone, .neutral)
        XCTAssertEqual(badge(.remoteProvider, in: storeModel)?.label, "Remote model")
        XCTAssertEqual(badge(.privacyBlocked, in: storeBlocked)?.tone, .warning)

        for marker in [
            "provider transport audit accepted",
            "recommendation: \(searchObject.id.lowercased())",
            "searchapi",
            "websearch",
            "meteredpremium",
            "a142-search-source-policy",
            "a142-search-status-source",
            "evaluation:",
        ] {
            XCTAssertTrue(searchText.contains(marker), marker)
        }
        for marker in [
            "provider transport audit accepted",
            "recommendation: \(modelObject.id.lowercased())",
            "remotemodel",
            "remotemodelcompletion",
            "a142-model-status-source",
            "confirmation: confirmed",
            "audit review",
        ] {
            XCTAssertTrue(modelText.contains(marker), marker)
        }
        for marker in [
            "blocked by value-only policy",
            "recommendation: \(blockedObject.id.lowercased())",
            "blockedprivacyclass",
            "privacy blocked",
            "a142-blocked-status-source",
        ] {
            XCTAssertTrue(blockedText.contains(marker), marker)
        }
        for hiddenMarker in [
            "a142-hidden-status-source",
            "a142-hidden-confirmed",
            "mcptool",
        ] {
            XCTAssertFalse(searchText.contains(hiddenMarker), hiddenMarker)
            XCTAssertFalse(modelText.contains(hiddenMarker), hiddenMarker)
            XCTAssertFalse(blockedText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in transportAdapterStatusForbiddenFragments() {
            XCTAssertFalse(searchText.contains(forbidden), forbidden)
            XCTAssertFalse(modelText.contains(forbidden), forbidden)
            XCTAssertFalse(blockedText.contains(forbidden), forbidden)
        }
    }

