        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "A142 fallback",
                    statusLine: "A142 fallback provider status selected."
                ),
            ]
        )
        let auditFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [auditSource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, auditSource]
        )
        let auditStore = ChatStore(
            recommendationProvider: auditFirst.recommendationProvider,
            providerStatusProvider: auditFirst.providerStatusProvider,
            feedbackRuntime: auditFirst.feedbackRuntime,
            completedRecommendationHandoff: auditFirst.completedRecommendationHandoff,
            telemetryEmitter: auditFirst.telemetryEmitter,
            capabilityRegistry: auditFirst.capabilityRegistry
        )
        let fallbackStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let auditRoot = try XCTUnwrap(
            auditFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackRoot = try XCTUnwrap(
            fallbackFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let auditSelected = try XCTUnwrap(
            auditStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackSelected = try XCTUnwrap(
            fallbackStore.providerStatusPresentation(for: renderedObject.id)
        )
        let auditText = providerStatusSearchText(auditSelected)
        let fallbackText = providerStatusSearchText(fallbackSelected)

        XCTAssertNil(auditSource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(auditSource.providerStatusPresentation(for: missingID))
        XCTAssertNil(auditStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(auditStore.providerStatusPresentation(for: missingID))
        XCTAssertEqual(auditStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(auditRoot, auditSelected)
        XCTAssertEqual(fallbackRoot, fallbackSelected)

        XCTAssertTrue(auditText.contains("provider transport audit accepted"))
        XCTAssertTrue(auditText.contains("a142-first-status-source"))
        XCTAssertTrue(auditText.contains("a142-first-source-policy"))
        XCTAssertTrue(auditText.contains("searchapi"))
        XCTAssertTrue(auditText.contains("websearch"))
        XCTAssertFalse(auditText.contains("a142 fallback"))
        XCTAssertFalse(auditText.contains("fallback provider status"))
        XCTAssertFalse(auditText.contains("a142-hidden-rejected-source"))
        XCTAssertFalse(auditText.contains("missingsourcepolicy"))

        XCTAssertTrue(fallbackText.contains("a142 fallback"))
        XCTAssertTrue(fallbackText.contains("fallback provider status"))
        XCTAssertFalse(fallbackText.contains("a142-first-status-source"))
        XCTAssertFalse(fallbackText.contains("a142-first-source-policy"))
        XCTAssertFalse(fallbackText.contains("missingsourcepolicy"))
        for forbidden in transportAdapterStatusForbiddenFragments() {
            XCTAssertFalse(auditText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
        }
    }

