                    "a143-audit-blocked-status-source",
                    "a143-metered-vendor",
                    "a143-vendor-ready-vendor",
                    "a143-preflight-ready-adapter",
                    "a143 fallback ready",
                ]
            ),
            (
                name: "fallback first",
                sources: [fallbackSource, auditSource, meteredSource, vendorPolicySource,
                          dispatchSource, authorizationSource, leaseSource, requestSource,
                          responseSource, preflightSource],
                expectedReady: fallbackReady,
                expectedBlocked: fallbackBlocked,
                expectedModel: fallbackModel,
                expectedMarkers: [
                    "a143 fallback ready",
                    "a143 fallback blocked",
                    "a143 fallback model",
                ],
                forbiddenMarkers: [
                    "a143-audit-ready-status-source",
                    "a143-audit-blocked-status-source",
                    "a143-audit-model-status-source",
                    "a143-metered-vendor",
                    "a143-response-vendor",
                    "a143-preflight-ready-adapter",
                ]
            ),
        ]

        for selectionCase in selectionCases {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: selectionCase.sources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )

            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    selectionCase.name
                )
                XCTAssertNil(store.providerStatusPresentation(for: hiddenID), selectionCase.name)
            }

            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let rootModel = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: modelObject.id),
                selectionCase.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let storeModel = try XCTUnwrap(
                store.providerStatusPresentation(for: modelObject.id),
                selectionCase.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
                providerStatusSearchText(storeModel),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject, modelObject], selectionCase.name)
            XCTAssertEqual(store.session.messages.count, 0, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedReady, rootReady, selectionCase.name)
            XCTAssertEqual(rootReady, storeReady, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedBlocked, rootBlocked, selectionCase.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedModel, rootModel, selectionCase.name)
            XCTAssertEqual(rootModel, storeModel, selectionCase.name)
            for marker in selectionCase.expectedMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for marker in selectionCase.forbiddenMarkers {
                XCTAssertFalse(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for hiddenMarker in [
                "a143-metered-hidden-vendor",
                "a143-vendor-hidden-vendor",
                "a143-dispatch-hidden",
                "a143-authorization-hidden-vendor",
                "a143-lease-hidden-vendor",
                "a143-request-hidden-vendor",
                "a143-response-hidden-vendor",
                "a143-preflight-hidden-adapter",
                "a143-audit-hidden-status-source",
                "a143-audit-hidden-confirmed",
            ] {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectionCase.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectionCase.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_chatStoreReadsSearchAPILiveTransportReadinessStatusForRenderedRecommendationOnly() throws {
        let readyObject = RecommendationFixtures.searchResult
        let blockedObject = RecommendationFixtures.placeRoute
        let hiddenID = "a147-readiness-hidden"
        let missingID = "a147-readiness-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [readyObject, blockedObject]
        )
        let acceptedDecision = ServerProviderSearchAPILiveTransportReadinessGate.decision(
            request: ServerProviderSearchAPILiveTransportReadinessRequest(
                evidence: ServerProviderSearchAPILiveTransportReadinessGate.requiredEvidence(
                    idPrefix: "a147-ready"
                )
            )
        )
        let rejectedDecision = ServerProviderSearchAPILiveTransportReadinessGate.decision(
            request: ServerProviderSearchAPILiveTransportReadinessRequest(evidence: [])
        )
        let hiddenDecision = ServerProviderSearchAPILiveTransportReadinessGate.decision(
            request: ServerProviderSearchAPILiveTransportReadinessRequest(
                evidence: ServerProviderSearchAPILiveTransportReadinessGate.requiredEvidence(
                    idPrefix: "a147-hidden"
                )
            )
        )
        let source = ServerProviderSearchAPILiveTransportReadinessStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: readyObject.id, decision: acceptedDecision),
                    .init(recommendationID: blockedObject.id, decision: rejectedDecision),
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [readyObject.id, blockedObject.id]
            )

        XCTAssertTrue(acceptedDecision.isReadyForPlanning)
        XCTAssertEqual(rejectedDecision.rejection, .missingEvidence)
        XCTAssertEqual(
            source.renderedRecommendationIDs,
            [readyObject.id, blockedObject.id].sorted()
        )
        XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        let sourceReady = try XCTUnwrap(source.providerStatusPresentation(for: readyObject.id))
        let sourceBlocked = try XCTUnwrap(source.providerStatusPresentation(for: blockedObject.id))

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootReady = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: readyObject.id)
        )
        let rootBlocked = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeReady = try XCTUnwrap(store.providerStatusPresentation(for: readyObject.id))
        let storeBlocked = try XCTUnwrap(store.providerStatusPresentation(for: blockedObject.id))
        let readyText = providerStatusSearchText(storeReady)
        let blockedText = providerStatusSearchText(storeBlocked)
        let selectedText = [readyText, blockedText].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(sourceReady, rootReady)
        XCTAssertEqual(rootReady, storeReady)
        XCTAssertEqual(sourceBlocked, rootBlocked)
        XCTAssertEqual(rootBlocked, storeBlocked)
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )
        XCTAssertNil(store.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))

        XCTAssertEqual(storeReady.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeReady)?.tone, .neutral)
        XCTAssertEqual(badge(.includedQuota, in: storeReady)?.label, "Planning evidence")
        XCTAssertEqual(badge(.liveFreshness, in: storeReady)?.label, "Provider path disabled")
        XCTAssertTrue(readyText.contains("planning evidence is ready"))
        XCTAssertTrue(readyText.contains("provider path remains disabled"))
        XCTAssertFalse(readyText.contains("value-only policy"))

        XCTAssertEqual(storeBlocked.cardHint, .disabled)
        XCTAssertEqual(badge(.unavailable, in: storeBlocked)?.label, "Planning unavailable")
        XCTAssertTrue(blockedText.contains("planning evidence is blocked"))
        XCTAssertTrue(blockedText.contains("value-only policy"))
        XCTAssertTrue(blockedText.contains("provider path remains disabled"))
        XCTAssertNil(badge(.remoteProvider, in: storeBlocked))

        for hiddenMarker in [
            "a147-hidden",
            hiddenID,
            "a147-readiness-missing",
        ] {
            XCTAssertFalse(selectedText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(selectedText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPILiveTransportReadinessStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.searchResult
        let hiddenID = "a147-source-order-hidden"
        let missingID = "a147-source-order-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let acceptedDecision = ServerProviderSearchAPILiveTransportReadinessGate.decision(
            request: ServerProviderSearchAPILiveTransportReadinessRequest(
                evidence: ServerProviderSearchAPILiveTransportReadinessGate.requiredEvidence(
                    idPrefix: "a147-order"
                )
            )
        )
        let hiddenDecision = ServerProviderSearchAPILiveTransportReadinessGate.decision(
            request: ServerProviderSearchAPILiveTransportReadinessRequest(
                evidence: ServerProviderSearchAPILiveTransportReadinessGate.requiredEvidence(
                    idPrefix: "a147-order-hidden"
                )
            )
        )
        let readinessSource = ServerProviderSearchAPILiveTransportReadinessStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: renderedObject.id, decision: acceptedDecision),
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "A147 fallback",
                    statusLine: "A147 fallback provider status selected."
                ),
            ]
        )
        let readinessFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [readinessSource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, readinessSource]
        )
        let readinessStore = ChatStore(
            recommendationProvider: readinessFirst.recommendationProvider,
            providerStatusProvider: readinessFirst.providerStatusProvider,
            feedbackRuntime: readinessFirst.feedbackRuntime,
            completedRecommendationHandoff: readinessFirst.completedRecommendationHandoff,
            telemetryEmitter: readinessFirst.telemetryEmitter,
            capabilityRegistry: readinessFirst.capabilityRegistry
        )
        let fallbackStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let readinessRoot = try XCTUnwrap(
            readinessFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackRoot = try XCTUnwrap(
            fallbackFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let readinessSelected = try XCTUnwrap(
            readinessStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackSelected = try XCTUnwrap(
            fallbackStore.providerStatusPresentation(for: renderedObject.id)
        )
        let readinessText = providerStatusSearchText(readinessSelected)
        let fallbackText = providerStatusSearchText(fallbackSelected)

        XCTAssertNil(readinessSource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(readinessSource.providerStatusPresentation(for: missingID))
        XCTAssertNil(readinessStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(readinessStore.providerStatusPresentation(for: missingID))
        XCTAssertEqual(readinessStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(readinessRoot, readinessSelected)
        XCTAssertEqual(fallbackRoot, fallbackSelected)

        XCTAssertTrue(readinessText.contains("planning evidence is ready"))
        XCTAssertTrue(readinessText.contains("provider path remains disabled"))
        XCTAssertTrue(readinessText.contains("planning evidence"))
        XCTAssertFalse(readinessText.contains("a147 fallback"))
        XCTAssertFalse(readinessText.contains("fallback provider status"))
        XCTAssertFalse(readinessText.contains("a147-order-hidden"))

        XCTAssertTrue(fallbackText.contains("a147 fallback"))
        XCTAssertTrue(fallbackText.contains("fallback provider status"))
        XCTAssertFalse(fallbackText.contains("planning evidence is ready"))
        XCTAssertFalse(fallbackText.contains("provider path remains disabled"))
        XCTAssertFalse(fallbackText.contains("a147-order-hidden"))
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(readinessText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
        }
    }

