        let selectionCases: [
            (
                name: String,
                sources: [any ProviderStatusProviding],
                expectedReady: ProviderStatusPresentation,
                expectedBlocked: ProviderStatusPresentation,
                expectedMarkers: [String],
                forbiddenMarkers: [String]
