        ] = [
            (
                name: "readiness first",
                sources: [readinessSource, responseSource]
                    + searchAPIStatusStackAfterResponse
                    + [fallbackSource],
                expectedReady: readinessReady,
                expectedBlocked: readinessBlocked,
                expectedMarkers: [
                    "planning evidence is ready",
                    "planning evidence is blocked",
                    "provider path remains disabled",
                ],
                forbiddenMarkers: [
                    "a148 fallback ready",
                    "a148-metered-vendor",
                    "a148-vendor-ready-vendor",
                    "a148-dispatch-ready-request",
                    "a148-authorization-vendor",
                    "a148-lease-vendor",
                    "a148-request-vendor",
                    "a148-response-vendor",
                    "a148-preflight-ready-adapter",
                    "a148-audit-ready-status-source",
                ]
            ),
            (
                name: "earlier search stack first",
                sources: [responseSource, readinessSource]
                    + searchAPIStatusStackAfterResponse
                    + [fallbackSource],
                expectedReady: responseReady,
                expectedBlocked: responseBlocked,
                expectedMarkers: [
                    "transport response accepted",
                    "a148-response-vendor",
                    "a148-response-ready-response",
                    "adapterresultrejected",
                    "resultlimitmismatch",
                ],
                forbiddenMarkers: [
                    "planning evidence is ready",
                    "planning evidence is blocked",
                    "provider path remains disabled",
                    "a148 fallback ready",
                    "a148-metered-vendor",
                    "a148-vendor-ready-vendor",
                    "a148-preflight-ready-adapter",
                    "a148-audit-ready-status-source",
                ]
            ),
            (
                name: "fallback first",
                sources: [fallbackSource, readinessSource, responseSource]
                    + searchAPIStatusStackAfterResponse,
                expectedReady: fallbackReady,
                expectedBlocked: fallbackBlocked,
                expectedMarkers: [
                    "a148 fallback ready",
                    "a148 fallback blocked",
                ],
                forbiddenMarkers: [
                    "planning evidence is ready",
                    "planning evidence is blocked",
                    "provider path remains disabled",
                    "a148-response-vendor",
                    "a148-metered-vendor",
                    "a148-audit-ready-status-source",
                ]
            ),
        ]

        for source in allSources {
            for suppressedID in hiddenIDs + [missingID] {
                XCTAssertNil(
                    source.providerStatusPresentation(for: suppressedID),
                    suppressedID
                )
            }
        }

        for selectionCase in selectionCases {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: selectionCase.sources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )

            for suppressedID in hiddenIDs + [missingID] {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: suppressedID),
                    "\(selectionCase.name): \(suppressedID)"
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: suppressedID),
                    "\(selectionCase.name): \(suppressedID)"
                )
            }

            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectionCase.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectionCase.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectionCase.name)
            XCTAssertEqual(store.session.messages.count, 0, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedReady, rootReady, selectionCase.name)
            XCTAssertEqual(rootReady, storeReady, selectionCase.name)
            XCTAssertEqual(selectionCase.expectedBlocked, rootBlocked, selectionCase.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectionCase.name)
            for marker in selectionCase.expectedMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for marker in selectionCase.forbiddenMarkers {
                XCTAssertFalse(selectedText.contains(marker), "\(selectionCase.name): \(marker)")
            }
            for hiddenMarker in [
                "a148-readiness-hidden",
                "a148-metered-hidden-vendor",
                "a148-vendor-hidden-vendor",
                "a148-dispatch-hidden",
                "a148-authorization-hidden-vendor",
                "a148-lease-hidden-vendor",
                "a148-request-hidden-vendor",
                "a148-response-hidden-vendor",
                "a148-preflight-hidden-adapter",
                "a148-audit-hidden-status-source",
                "a148-audit-hidden-confirmed",
            ] {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectionCase.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectionCase.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_chatStoreReadsSearchAPILiveVendorSelectionStatusForRenderedRecommendationOnly() throws {
        let selectedObject = RecommendationFixtures.searchResult
        let blockedObject = RecommendationFixtures.placeRoute
        let hiddenID = "a152-live-vendor-hidden"
        let missingID = "a152-live-vendor-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [selectedObject, blockedObject]
        )
        let selectedDecision = searchAPILiveVendorSelectionSelectedDecision(
            vendorID: "a152-selected-vendor"
        )
        let rejectedDecision = searchAPILiveVendorSelectionRejectedDecision(
            request: searchAPILiveVendorSelectionRequest(privacyClass: .private),
            candidates: [
                searchAPILiveVendorSelectionCandidate(id: "a152-blocked-vendor"),
            ]
        )
        let hiddenDecision = searchAPILiveVendorSelectionSelectedDecision(
            vendorID: "a152-hidden-vendor"
        )
        let source = ServerProviderSearchAPILiveVendorSelectionStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: selectedObject.id, decision: selectedDecision),
                    .init(recommendationID: blockedObject.id, decision: rejectedDecision),
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [selectedObject.id, blockedObject.id]
            )

        XCTAssertEqual(selectedDecision.state, .selected)
        XCTAssertEqual(selectedDecision.selectedCandidateID, "a152-selected-vendor")
        XCTAssertEqual(rejectedDecision.state, .rejected)
        XCTAssertTrue(rejectedDecision.rejectionReasons.contains(.privacyBlocked))
        XCTAssertEqual(
            source.renderedRecommendationIDs,
            [selectedObject.id, blockedObject.id].sorted()
        )
        XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        let sourceSelected = try XCTUnwrap(
            source.providerStatusPresentation(for: selectedObject.id)
        )
        let sourceBlocked = try XCTUnwrap(
            source.providerStatusPresentation(for: blockedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootSelected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: selectedObject.id)
        )
        let rootBlocked = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: blockedObject.id)
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeSelected = try XCTUnwrap(
            store.providerStatusPresentation(for: selectedObject.id)
        )
        let storeBlocked = try XCTUnwrap(
            store.providerStatusPresentation(for: blockedObject.id)
        )
        let selectedText = providerStatusSearchText(storeSelected)
        let blockedText = providerStatusSearchText(storeBlocked)
        let statusText = [selectedText, blockedText].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [selectedObject, blockedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(sourceSelected, rootSelected)
        XCTAssertEqual(rootSelected, storeSelected)
        XCTAssertEqual(sourceBlocked, rootBlocked)
        XCTAssertEqual(rootBlocked, storeBlocked)
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )
        XCTAssertNil(store.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))

        XCTAssertEqual(storeSelected.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeSelected)?.label, "Search API")
        XCTAssertEqual(badge(.includedQuota, in: storeSelected)?.label, "Candidate policy")
        XCTAssertEqual(badge(.meteredPremium, in: storeSelected)?.tone, .neutral)
        XCTAssertTrue(selectedText.contains("policy planning only"))
        XCTAssertTrue(selectedText.contains("a152-selected-vendor"))
        XCTAssertTrue(selectedText.contains("meteredpremium"))
        XCTAssertTrue(selectedText.contains("no transport or provider runtime has run"))

        XCTAssertEqual(storeBlocked.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storeBlocked)?.tone, .warning)
        XCTAssertNil(badge(.remoteProvider, in: storeBlocked))
        XCTAssertNil(badge(.meteredPremium, in: storeBlocked))
        XCTAssertTrue(blockedText.contains("blocked by metadata policy"))
        XCTAssertTrue(blockedText.contains("privacyblocked"))
        XCTAssertTrue(blockedText.contains("no candidate is eligible"))
        XCTAssertTrue(blockedText.contains("no transport or provider runtime has run"))

        for hiddenMarker in [
            hiddenID,
            missingID,
            "a152-hidden-vendor",
        ] {
            XCTAssertFalse(statusText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(statusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPILiveVendorSelectionStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.searchResult
        let hiddenID = "a152-source-order-hidden"
        let missingID = "a152-source-order-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let selectedDecision = searchAPILiveVendorSelectionSelectedDecision(
            vendorID: "a152-order-vendor",
            costClass: .includedQuota,
            quotaClass: .includedQuota,
            quotaSnapshot: searchAPIVendorPolicyIncludedQuotaSnapshot(remaining: 2)
        )
        let hiddenDecision = searchAPILiveVendorSelectionSelectedDecision(
            vendorID: "a152-order-hidden-vendor"
        )
        let vendorSelectionSource = ServerProviderSearchAPILiveVendorSelectionStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: renderedObject.id, decision: selectedDecision),
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "A152 fallback",
                    statusLine: "A152 fallback provider status selected."
                ),
            ]
        )
        let vendorSelectionFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [vendorSelectionSource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, vendorSelectionSource]
        )
        let vendorSelectionStore = ChatStore(
            recommendationProvider: vendorSelectionFirst.recommendationProvider,
            providerStatusProvider: vendorSelectionFirst.providerStatusProvider,
            feedbackRuntime: vendorSelectionFirst.feedbackRuntime,
            completedRecommendationHandoff: vendorSelectionFirst.completedRecommendationHandoff,
            telemetryEmitter: vendorSelectionFirst.telemetryEmitter,
            capabilityRegistry: vendorSelectionFirst.capabilityRegistry
        )
        let fallbackStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let vendorSelectionRoot = try XCTUnwrap(
            vendorSelectionFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackRoot = try XCTUnwrap(
            fallbackFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let vendorSelectionSelected = try XCTUnwrap(
            vendorSelectionStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackSelected = try XCTUnwrap(
            fallbackStore.providerStatusPresentation(for: renderedObject.id)
        )
        let vendorSelectionText = providerStatusSearchText(vendorSelectionSelected)
        let fallbackText = providerStatusSearchText(fallbackSelected)

        XCTAssertNil(vendorSelectionSource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(vendorSelectionSource.providerStatusPresentation(for: missingID))
        XCTAssertNil(vendorSelectionStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(vendorSelectionStore.providerStatusPresentation(for: missingID))
        XCTAssertEqual(vendorSelectionStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(vendorSelectionRoot, vendorSelectionSelected)
        XCTAssertEqual(fallbackRoot, fallbackSelected)

        XCTAssertTrue(vendorSelectionText.contains("policy planning only"))
        XCTAssertTrue(vendorSelectionText.contains("a152-order-vendor"))
        XCTAssertTrue(vendorSelectionText.contains("candidate policy"))
        XCTAssertTrue(vendorSelectionText.contains("includedquota"))
        XCTAssertFalse(vendorSelectionText.contains("a152 fallback"))
        XCTAssertFalse(vendorSelectionText.contains("fallback provider status"))
        XCTAssertFalse(vendorSelectionText.contains("a152-order-hidden-vendor"))

        XCTAssertTrue(fallbackText.contains("a152 fallback"))
        XCTAssertTrue(fallbackText.contains("fallback provider status"))
        XCTAssertFalse(fallbackText.contains("policy planning only"))
        XCTAssertFalse(fallbackText.contains("a152-order-vendor"))
        XCTAssertFalse(fallbackText.contains("a152-order-hidden-vendor"))
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(vendorSelectionText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
        }
    }

