            ),
            (
                name: "vendor policy",
                source: vendorPolicySource,
                expectedReady: try XCTUnwrap(
                    vendorPolicySource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    vendorPolicySource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-vendor-ready-vendor"]
            ),
            (
                name: "dispatch",
                source: dispatchSource,
                expectedReady: try XCTUnwrap(
                    dispatchSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    dispatchSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-dispatch-ready-request"]
            ),
            (
                name: "authorization",
                source: authorizationSource,
                expectedReady: try XCTUnwrap(
                    authorizationSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    authorizationSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-authorization-vendor"]
            ),
            (
                name: "lease",
                source: leaseSource,
                expectedReady: try XCTUnwrap(
                    leaseSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    leaseSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-lease-vendor"]
            ),
            (
                name: "request",
                source: requestSource,
                expectedReady: try XCTUnwrap(
                    requestSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    requestSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-request-vendor"]
            ),
            (
                name: "response",
                source: responseSource,
                expectedReady: try XCTUnwrap(
                    responseSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    responseSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-response-vendor"]
            ),
            (
                name: "preflight",
                source: preflightSource,
                expectedReady: try XCTUnwrap(
                    preflightSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    preflightSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-preflight-ready-adapter"]
            ),
            (
                name: "audit",
                source: auditSource,
                expectedReady: try XCTUnwrap(
                    auditSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    auditSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153-audit-ready-status-source"]
            ),
            (
                name: "fallback",
                source: fallbackSource,
                expectedReady: try XCTUnwrap(
                    fallbackSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    fallbackSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["a153 fallback ready", "a153 fallback blocked"]
            ),
        ]
        let hiddenLeakMarkers = [
            "a153-live-vendor-hidden-vendor",
            "a153-metered-hidden-vendor",
            "a153-vendor-hidden-vendor",
            "a153-dispatch-hidden",
            "a153-authorization-hidden-vendor",
            "a153-lease-hidden-vendor",
            "a153-request-hidden-vendor",
            "a153-response-hidden-vendor",
            "a153-preflight-hidden-adapter",
            "a153-audit-hidden-status-source",
            "a153-audit-hidden-confirmed",
        ]

        for item in sourceItems {
            let itemText = [
                providerStatusSearchText(item.expectedReady),
                providerStatusSearchText(item.expectedBlocked),
            ].joined(separator: "\n")
            for marker in item.leakMarkers {
                XCTAssertTrue(itemText.contains(marker), "\(item.name): \(marker)")
            }
            for suppressedID in hiddenIDs + [missingID] {
                XCTAssertNil(
                    item.source.providerStatusPresentation(for: suppressedID),
                    "\(item.name): \(suppressedID)"
                )
            }
        }

        for (selectedIndex, selectedItem) in sourceItems.enumerated() {
            let trailingSources = sourceItems.enumerated().compactMap { index, item in
                index == selectedIndex ? nil : item.source
            }
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [selectedItem.source] + trailingSources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectedItem.name)
            XCTAssertEqual(store.session.messages.count, 0, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedReady, rootReady, selectedItem.name)
            XCTAssertEqual(rootReady, storeReady, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedBlocked, rootBlocked, selectedItem.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectedItem.name)
            XCTAssertNil(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: missingID),
                selectedItem.name
            )
            XCTAssertNil(store.providerStatusPresentation(for: missingID), selectedItem.name)
            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
            }
            for marker in selectedItem.leakMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectedItem.name): \(marker)")
            }
            for otherItem in sourceItems where otherItem.name != selectedItem.name {
                for marker in otherItem.leakMarkers {
                    XCTAssertFalse(
                        selectedText.contains(marker),
                        "\(selectedItem.name) leaked \(otherItem.name): \(marker)"
                    )
                }
            }
            for hiddenMarker in hiddenLeakMarkers {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectedItem.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectedItem.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_chatStoreReadsSearchAPILiveTransportAdapterInterfaceStatusForRenderedRecommendationOnly() throws {
        let acceptedObject = RecommendationFixtures.searchResult
        let rejectedObject = RecommendationFixtures.placeRoute
        let hiddenID = "a157-adapter-interface-hidden"
        let missingID = "a157-adapter-interface-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [acceptedObject, rejectedObject]
        )
        let acceptedDecision = searchAPILiveTransportAdapterInterfaceAcceptedDecision(
            descriptorID: "a157-accepted-adapter"
        )
        let rejectedDecision = searchAPILiveTransportAdapterInterfaceRejectedDecision(
            request: searchAPILiveTransportAdapterInterfaceRequest(privacyClass: .private),
            descriptors: [
                searchAPILiveTransportAdapterDescriptor(id: "a157-blocked-adapter"),
            ],
            expectedReason: .privacyBlocked
        )
        let hiddenDecision = searchAPILiveTransportAdapterInterfaceAcceptedDecision(
            descriptorID: "a157-hidden-adapter"
        )
        let source = ServerProviderSearchAPILiveTransportAdapterInterfaceStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: acceptedObject.id, decision: acceptedDecision),
                    .init(recommendationID: rejectedObject.id, decision: rejectedDecision),
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [acceptedObject.id, rejectedObject.id]
            )

        XCTAssertEqual(acceptedDecision.state, .accepted)
        XCTAssertEqual(acceptedDecision.selectedDescriptorID, "a157-accepted-adapter")
        XCTAssertFalse(acceptedDecision.isRuntimeCallable)
        XCTAssertEqual(rejectedDecision.state, .rejected)
        XCTAssertTrue(rejectedDecision.rejectionReasons.contains(.privacyBlocked))
        XCTAssertFalse(rejectedDecision.isRuntimeCallable)
        XCTAssertEqual(
            source.renderedRecommendationIDs,
            [acceptedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        let sourceAccepted = try XCTUnwrap(
            source.providerStatusPresentation(for: acceptedObject.id)
        )
        let sourceRejected = try XCTUnwrap(
            source.providerStatusPresentation(for: rejectedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootAccepted = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: acceptedObject.id)
        )
        let rootRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storeAccepted = try XCTUnwrap(
            store.providerStatusPresentation(for: acceptedObject.id)
        )
        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let acceptedText = providerStatusSearchText(storeAccepted)
        let rejectedText = providerStatusSearchText(storeRejected)
        let statusText = [acceptedText, rejectedText].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [acceptedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(sourceAccepted, rootAccepted)
        XCTAssertEqual(rootAccepted, storeAccepted)
        XCTAssertEqual(sourceRejected, rootRejected)
        XCTAssertEqual(rootRejected, storeRejected)
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )
        XCTAssertNil(store.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))

        XCTAssertEqual(storeAccepted.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storeAccepted)?.label, "Search API interface")
        XCTAssertEqual(badge(.includedQuota, in: storeAccepted)?.label, "Adapter policy")
        XCTAssertEqual(badge(.meteredPremium, in: storeAccepted)?.label, "Premium metered")
        XCTAssertEqual(badge(.liveFreshness, in: storeAccepted)?.label, "Source required")
        XCTAssertTrue(acceptedText.contains("candidate adapter policy is advisory only"))
        XCTAssertTrue(acceptedText.contains("descriptor: a157-accepted-adapter"))
        XCTAssertTrue(acceptedText.contains("vendor: a157-vendor"))
        XCTAssertTrue(acceptedText.contains("source state"))
        XCTAssertTrue(acceptedText.contains("isruntimecallable false"))
        XCTAssertTrue(acceptedText.contains("no transport or provider runtime has run"))

        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.privacyBlocked, in: storeRejected)?.label, "Privacy blocked")
        XCTAssertNil(badge(.remoteProvider, in: storeRejected))
        XCTAssertNil(badge(.meteredPremium, in: storeRejected))
        XCTAssertTrue(rejectedText.contains("disabled by metadata policy"))
        XCTAssertTrue(rejectedText.contains("privacyblocked"))
        XCTAssertTrue(rejectedText.contains("isruntimecallable false"))
        XCTAssertTrue(rejectedText.contains("no transport or provider runtime has run"))

        for hiddenMarker in [
            hiddenID,
            missingID,
            "a157-hidden-adapter",
        ] {
            XCTAssertFalse(statusText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(statusText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPILiveTransportAdapterInterfaceStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.searchResult
        let hiddenID = "a157-source-order-hidden"
        let missingID = "a157-source-order-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject]
        )
        let acceptedDecision = searchAPILiveTransportAdapterInterfaceAcceptedDecision(
            descriptorID: "a157-order-adapter",
            searchContextClass: .searchOnly
        )
        let hiddenDecision = searchAPILiveTransportAdapterInterfaceAcceptedDecision(
            descriptorID: "a157-order-hidden-adapter"
        )
        let adapterInterfaceSource = ServerProviderSearchAPILiveTransportAdapterInterfaceStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(recommendationID: renderedObject.id, decision: acceptedDecision),
                    .init(recommendationID: hiddenID, decision: hiddenDecision),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "A157 fallback",
                    statusLine: "A157 fallback provider status selected."
                ),
            ]
        )
        let adapterFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [adapterInterfaceSource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, adapterInterfaceSource]
        )
        let adapterStore = ChatStore(
            recommendationProvider: adapterFirst.recommendationProvider,
            providerStatusProvider: adapterFirst.providerStatusProvider,
            feedbackRuntime: adapterFirst.feedbackRuntime,
            completedRecommendationHandoff: adapterFirst.completedRecommendationHandoff,
            telemetryEmitter: adapterFirst.telemetryEmitter,
            capabilityRegistry: adapterFirst.capabilityRegistry
        )
        let fallbackStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            completedRecommendationHandoff: fallbackFirst.completedRecommendationHandoff,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let adapterRoot = try XCTUnwrap(
            adapterFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackRoot = try XCTUnwrap(
            fallbackFirst.providerStatusProvider?
                .providerStatusPresentation(for: renderedObject.id)
        )
        let adapterSelected = try XCTUnwrap(
            adapterStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackSelected = try XCTUnwrap(
            fallbackStore.providerStatusPresentation(for: renderedObject.id)
        )
        let adapterText = providerStatusSearchText(adapterSelected)
        let fallbackText = providerStatusSearchText(fallbackSelected)

        XCTAssertNil(adapterInterfaceSource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(adapterInterfaceSource.providerStatusPresentation(for: missingID))
        XCTAssertNil(adapterStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(adapterStore.providerStatusPresentation(for: missingID))
        XCTAssertNil(fallbackStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(fallbackStore.providerStatusPresentation(for: missingID))
        XCTAssertEqual(adapterStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(fallbackStore.recommendedMatches, [renderedObject])
        XCTAssertEqual(adapterRoot, adapterSelected)
        XCTAssertEqual(fallbackRoot, fallbackSelected)

        XCTAssertTrue(adapterText.contains("candidate adapter policy is advisory only"))
        XCTAssertTrue(adapterText.contains("descriptor: a157-order-adapter"))
        XCTAssertTrue(adapterText.contains("context: searchonly"))
        XCTAssertTrue(adapterText.contains("isruntimecallable false"))
        XCTAssertFalse(adapterText.contains("a157 fallback"))
        XCTAssertFalse(adapterText.contains("fallback provider status"))
        XCTAssertFalse(adapterText.contains("a157-order-hidden-adapter"))

        XCTAssertTrue(fallbackText.contains("a157 fallback"))
        XCTAssertTrue(fallbackText.contains("fallback provider status"))
        XCTAssertFalse(fallbackText.contains("candidate adapter policy is advisory only"))
        XCTAssertFalse(fallbackText.contains("a157-order-adapter"))
        XCTAssertFalse(fallbackText.contains("a157-order-hidden-adapter"))
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(adapterText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPILiveTransportAdapterInterfaceStatusComposesWithSearchAPIStatusStackFirstWins() throws {
