                name: "readiness",
                source: readinessSource,
                expectedReady: try XCTUnwrap(
                    readinessSource.providerStatusPresentation(for: readyObject.id)
                ),
                expectedBlocked: try XCTUnwrap(
                    readinessSource.providerStatusPresentation(for: blockedObject.id)
                ),
                leakMarkers: ["planning evidence is ready", "planning evidence is blocked"]
