    func test_compositionRoot_chatStoreReadsSearchAPILiveProviderInvocationEnvelopeStatusForRenderedRecommendationOnly() throws {
        let preparedObject = RecommendationFixtures.searchResult
        let rejectedObject = RecommendationFixtures.placeRoute
        let hiddenID = "a167-envelope-hidden"
        let missingID = "a167-envelope-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [preparedObject, rejectedObject]
        )
