            adapterID: "a167-prepared-adapter",
            vendorID: "a167-prepared-vendor"
        )
        let rejectedDecision = searchAPILiveProviderInvocationEnvelopeRejectedDecision(
            envelopeID: "a167-rejected-envelope",
            preflightID: "a167-rejected-preflight",
            adapterID: "a167-rejected-adapter",
            vendorID: "a167-rejected-vendor"
        )
        let hiddenDecision = searchAPILiveProviderInvocationEnvelopePreparedDecision(
            envelopeID: "a167-hidden-envelope",
            preflightID: "a167-hidden-preflight",
            adapterID: "a167-hidden-adapter",
            vendorID: "a167-hidden-vendor"
        )
        let source = ServerProviderSearchAPILiveProviderInvocationEnvelopeStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: preparedObject.id,
                        statusSourceID: "a167-envelope-source",
                        statusSourceRank: 167,
                        decision: preparedDecision
                    ),
                    .init(
                        recommendationID: rejectedObject.id,
                        statusSourceID: "a167-envelope-source",
                        statusSourceRank: 167,
                        decision: rejectedDecision
                    ),
                    .init(
                        recommendationID: hiddenID,
                        statusSourceID: "a167-hidden-source",
                        statusSourceRank: 999,
                        isVisible: false,
                        decision: hiddenDecision
                    ),
                ],
                renderedRecommendationIDs: [preparedObject.id, rejectedObject.id]
            )

        XCTAssertEqual(
            source.renderedRecommendationIDs,
            [preparedObject.id, rejectedObject.id].sorted()
        )
        XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(source.providerStatusPresentation(for: missingID))
        let sourcePrepared = try XCTUnwrap(
            source.providerStatusPresentation(for: preparedObject.id)
        )
        let sourceRejected = try XCTUnwrap(
            source.providerStatusPresentation(for: rejectedObject.id)
        )

        let bootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [source]
        )
        let rootPrepared = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: preparedObject.id)
        )
        let rootRejected = try XCTUnwrap(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        let store = ChatStore(
            recommendationProvider: bootstrap.recommendationProvider,
            providerStatusProvider: bootstrap.providerStatusProvider,
            feedbackRuntime: bootstrap.feedbackRuntime,
            telemetryEmitter: bootstrap.telemetryEmitter,
            capabilityRegistry: bootstrap.capabilityRegistry
        )
        let storePrepared = try XCTUnwrap(
            store.providerStatusPresentation(for: preparedObject.id)
        )
        let storeRejected = try XCTUnwrap(
            store.providerStatusPresentation(for: rejectedObject.id)
        )
        let preparedText = providerStatusSearchText(storePrepared)
        let rejectedText = providerStatusSearchText(storeRejected)
        let statusText = [preparedText, rejectedText].joined(separator: "\n")

        XCTAssertEqual(store.recommendedMatches, [preparedObject, rejectedObject])
        XCTAssertEqual(store.session.messages.count, 0)
        XCTAssertEqual(sourcePrepared, rootPrepared)
        XCTAssertEqual(rootPrepared, storePrepared)
        XCTAssertEqual(sourceRejected, rootRejected)
        XCTAssertEqual(rootRejected, storeRejected)
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: hiddenID)
        )
        XCTAssertNil(
            bootstrap.providerStatusProvider?
                .providerStatusPresentation(for: missingID)
        )
        XCTAssertNil(store.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(store.providerStatusPresentation(for: missingID))

        XCTAssertEqual(storePrepared.cardHint, .warning)
        XCTAssertEqual(badge(.remoteProvider, in: storePrepared)?.label, "Search API envelope")
        XCTAssertEqual(badge(.meteredPremium, in: storePrepared)?.label, "Cost unit request")
        XCTAssertEqual(badge(.includedQuota, in: storePrepared)?.label, "Envelope policy")
        XCTAssertEqual(badge(.liveFreshness, in: storePrepared)?.label, "Source retained")
        XCTAssertTrue(preparedText.contains("invocation envelope is advisory only"))
        XCTAssertTrue(preparedText.contains("envelope: a167-prepared-envelope"))
        XCTAssertTrue(preparedText.contains("preflight: a167-prepared-preflight"))
        XCTAssertTrue(preparedText.contains("adapter: a167-prepared-adapter"))
        XCTAssertTrue(preparedText.contains("vendor: a167-prepared-vendor"))
        XCTAssertTrue(preparedText.contains("budget: a167-prepared-preflight-budget"))
        XCTAssertTrue(preparedText.contains("status source: a167-envelope-source"))
        XCTAssertTrue(preparedText.contains("rank: 167"))
        XCTAssertTrue(preparedText.contains("isruntimecallable false"))
        XCTAssertTrue(preparedText.contains("isexecutable false"))
        XCTAssertTrue(preparedText.contains("no transport or provider runtime has run"))

        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertEqual(badge(.costBlocked, in: storeRejected)?.label, "Premium locked")
        XCTAssertTrue(rejectedText.contains("disabled by envelope policy"))
        XCTAssertTrue(rejectedText.contains("quotarateunavailable"))
        XCTAssertTrue(rejectedText.contains("envelope: a167-rejected-envelope"))
        XCTAssertTrue(rejectedText.contains("status source: a167-envelope-source"))
        XCTAssertTrue(rejectedText.contains("isruntimecallable false"))
        XCTAssertTrue(rejectedText.contains("isexecutable false"))
        XCTAssertTrue(rejectedText.contains("no transport or provider runtime has run"))

        for hiddenMarker in [
            hiddenID,
            missingID,
            "a167-hidden-envelope",
            "a167-hidden-preflight",
            "a167-hidden-adapter",
            "a167-hidden-vendor",
        ] {
            XCTAssertFalse(statusText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(statusText.contains(forbidden), forbidden)
        }
    }

