                requiresEnvelopeMarkers: false,
                leakMarkers: ["a168-preflight-ready-adapter"]
            ),
            (
                name: "audit",
                source: auditSource,
                expectedReady: try XCTUnwrap(
                    auditSource.providerStatusPresentation(for: readyObject.id)
