                ),
                expectedBlocked: try XCTUnwrap(
                    fallbackSource.providerStatusPresentation(for: blockedObject.id)
                ),
                requiresEnvelopeMarkers: false,
                leakMarkers: ["a168 fallback ready", "a168 fallback blocked"]
            ),
        ]
        let hiddenLeakMarkers = [
            "a168-envelope-hidden-envelope",
            "a168-envelope-hidden-preflight",
            "a168-envelope-hidden-adapter",
            "a168-envelope-hidden-vendor",
            "a168-invocation-hidden-preflight",
            "a168-invocation-hidden-adapter",
            "a168-invocation-hidden-vendor",
            "a168-interface-hidden-adapter",
            "a168-interface-hidden-vendor",
            "a168-live-vendor-hidden-vendor",
            "a168-readiness-hidden",
            "a168-metered-hidden-vendor",
            "a168-vendor-hidden-vendor",
            "a168-dispatch-hidden",
            "a168-authorization-hidden-vendor",
            "a168-lease-hidden-vendor",
            "a168-request-hidden-vendor",
            "a168-response-hidden-vendor",
            "a168-preflight-hidden-adapter",
            "a168-audit-hidden-status-source",
            "a168-envelope-miss-hidden",
        ]

        for item in sourceItems {
            let itemText = [
                providerStatusSearchText(item.expectedReady),
                providerStatusSearchText(item.expectedBlocked),
            ].joined(separator: "\n")
            for marker in item.leakMarkers {
                XCTAssertTrue(itemText.contains(marker), "\(item.name): \(marker)")
            }
            if item.requiresEnvelopeMarkers {
                XCTAssertTrue(itemText.contains("isruntimecallable false"), item.name)
                XCTAssertTrue(itemText.contains("isexecutable false"), item.name)
            }
            for suppressedID in hiddenIDs + [missingID] {
                XCTAssertNil(
                    item.source.providerStatusPresentation(for: suppressedID),
                    "\(item.name): \(suppressedID)"
                )
            }
        }

        for (selectedIndex, selectedItem) in sourceItems.enumerated() {
            let trailingSources = sourceItems.enumerated().compactMap { index, item in
                index == selectedIndex ? nil : item.source
            }
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [selectedItem.source] + trailingSources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectedItem.name)
            XCTAssertEqual(store.session.messages.count, 0, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedReady, rootReady, selectedItem.name)
            XCTAssertEqual(rootReady, storeReady, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedBlocked, rootBlocked, selectedItem.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectedItem.name)
            XCTAssertNil(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: missingID),
                selectedItem.name
            )
            XCTAssertNil(store.providerStatusPresentation(for: missingID), selectedItem.name)
            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
            }
            for marker in selectedItem.leakMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectedItem.name): \(marker)")
            }
            if selectedItem.requiresEnvelopeMarkers {
                XCTAssertTrue(
                    selectedText.contains("isruntimecallable false"),
                    selectedItem.name
                )
                XCTAssertTrue(
                    selectedText.contains("isexecutable false"),
                    selectedItem.name
                )
            }
            for otherItem in sourceItems where otherItem.name != selectedItem.name {
                for marker in otherItem.leakMarkers {
                    XCTAssertFalse(
                        selectedText.contains(marker),
                        "\(selectedItem.name) leaked \(otherItem.name): \(marker)"
                    )
                }
            }
            for hiddenMarker in hiddenLeakMarkers {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectedItem.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectedItem.name): \(forbidden)")
            }
        }

        let fallbackAfterEnvelopeMiss = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [envelopeMissSource, fallbackSource]
        )
        let fallbackAfterMissStore = ChatStore(
            recommendationProvider: fallbackAfterEnvelopeMiss.recommendationProvider,
            providerStatusProvider: fallbackAfterEnvelopeMiss.providerStatusProvider,
            feedbackRuntime: fallbackAfterEnvelopeMiss.feedbackRuntime,
            telemetryEmitter: fallbackAfterEnvelopeMiss.telemetryEmitter,
            capabilityRegistry: fallbackAfterEnvelopeMiss.capabilityRegistry
        )
        XCTAssertNil(envelopeMissSource.providerStatusPresentation(for: readyObject.id))
        XCTAssertNil(envelopeMissSource.providerStatusPresentation(for: blockedObject.id))
        XCTAssertEqual(
            fallbackSource.providerStatusPresentation(for: readyObject.id),
            fallbackAfterMissStore.providerStatusPresentation(for: readyObject.id)
        )
        XCTAssertEqual(
            fallbackSource.providerStatusPresentation(for: blockedObject.id),
            fallbackAfterMissStore.providerStatusPresentation(for: blockedObject.id)
        )
    }

    func test_compositionRoot_searchAPILiveProviderInvocationPreflightStatusComposesWithSearchAPIStatusStackFirstWins() throws {
        let readyObject = RecommendationFixtures.searchResult
        let blockedObject = RecommendationFixtures.placeRoute
        let renderedIDs = [readyObject.id, blockedObject.id]
        let hiddenIDs = [
            "a163-invocation-hidden",
            "a163-interface-hidden",
            "a163-live-vendor-hidden",
            "a163-readiness-hidden",
            "a163-metered-hidden",
            "a163-vendor-hidden",
            "a163-dispatch-hidden",
            "a163-authorization-hidden",
            "a163-lease-hidden",
            "a163-request-hidden",
            "a163-response-hidden",
            "a163-preflight-hidden",
            "a163-audit-hidden",
        ]
        let missingID = "a163-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [readyObject, blockedObject]
        )
        let invocationPreflightSource =
            ServerProviderSearchAPILiveProviderInvocationPreflightStatusSourceProducer()
                .statusSource(
                    inputs: [
                        .init(
                            recommendationID: readyObject.id,
                            decision: searchAPILiveProviderInvocationPreflightAcceptedDecision(
                                preflightID: "a163-invocation-ready-preflight",
                                descriptorID: "a163-invocation-ready-adapter",
                                vendorID: "a163-invocation-vendor"
                            )
                        ),
                        .init(
                            recommendationID: blockedObject.id,
                            decision: searchAPILiveProviderInvocationPreflightRejectedDecision(
                                preflightID: "a163-invocation-blocked-preflight",
                                descriptorID: "a163-invocation-blocked-adapter",
                                vendorID: "a163-invocation-vendor",
                                privacyClass: .private,
                                expectedReason: .privacyBlocked
                            )
                        ),
                        .init(
                            recommendationID: hiddenIDs[0],
                            decision: searchAPILiveProviderInvocationPreflightAcceptedDecision(
                                preflightID: "a163-invocation-hidden-preflight",
                                descriptorID: "a163-invocation-hidden-adapter",
                                vendorID: "a163-invocation-hidden-vendor"
                            )
                        ),
                    ],
                    renderedRecommendationIDs: renderedIDs
                )
        let adapterInterfaceSource = ServerProviderSearchAPILiveTransportAdapterInterfaceStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: readyObject.id,
                        decision: searchAPILiveTransportAdapterInterfaceAcceptedDecision(
                            descriptorID: "a163-interface-ready-adapter",
                            vendorID: "a163-interface-vendor"
                        )
                    ),
