            "a163-invocation-hidden-adapter",
            "a163-invocation-hidden-vendor",
            "a163-interface-hidden-adapter",
            "a163-interface-hidden-vendor",
            "a163-live-vendor-hidden-vendor",
            "a163-readiness-hidden",
            "a163-metered-hidden-vendor",
            "a163-vendor-hidden-vendor",
            "a163-dispatch-hidden",
            "a163-authorization-hidden-vendor",
            "a163-lease-hidden-vendor",
            "a163-request-hidden-vendor",
            "a163-response-hidden-vendor",
            "a163-preflight-hidden-adapter",
            "a163-audit-hidden-status-source",
            "a163-audit-hidden-confirmed",
        ]

        for item in sourceItems {
            let itemText = [
                providerStatusSearchText(item.expectedReady),
                providerStatusSearchText(item.expectedBlocked),
            ].joined(separator: "\n")
            for marker in item.leakMarkers {
                XCTAssertTrue(itemText.contains(marker), "\(item.name): \(marker)")
            }
            if item.requiresCallableMarker {
                XCTAssertTrue(itemText.contains("isruntimecallable false"), item.name)
            }
            for suppressedID in hiddenIDs + [missingID] {
                XCTAssertNil(
                    item.source.providerStatusPresentation(for: suppressedID),
                    "\(item.name): \(suppressedID)"
                )
            }
        }

        for (selectedIndex, selectedItem) in sourceItems.enumerated() {
            let trailingSources = sourceItems.enumerated().compactMap { index, item in
                index == selectedIndex ? nil : item.source
            }
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [selectedItem.source] + trailingSources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(store.recommendedMatches, [readyObject, blockedObject], selectedItem.name)
            XCTAssertEqual(store.session.messages.count, 0, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedReady, rootReady, selectedItem.name)
            XCTAssertEqual(rootReady, storeReady, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedBlocked, rootBlocked, selectedItem.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectedItem.name)
            XCTAssertNil(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: missingID),
                selectedItem.name
            )
            XCTAssertNil(store.providerStatusPresentation(for: missingID), selectedItem.name)
            for hiddenID in hiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
            }
            for marker in selectedItem.leakMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectedItem.name): \(marker)")
            }
            if selectedItem.requiresCallableMarker {
                XCTAssertTrue(
                    selectedText.contains("isruntimecallable false"),
                    selectedItem.name
                )
            }
            for otherItem in sourceItems where otherItem.name != selectedItem.name {
                for marker in otherItem.leakMarkers {
                    XCTAssertFalse(
                        selectedText.contains(marker),
                        "\(selectedItem.name) leaked \(otherItem.name): \(marker)"
                    )
                }
            }
            for hiddenMarker in hiddenLeakMarkers {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectedItem.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectedItem.name): \(forbidden)")
            }
        }
    }

    func test_compositionRoot_chatStoreReadsSearchAPICostMembershipRoutingStatusForRenderedRecommendationOnly() throws {
        let cases: [
            (
                object: MatchingObject,
                decision: ServerProviderSearchAPICostMembershipRoutingDecision,
                expectedHint: ProviderStatusCardHint,
                expectedBadge: ProviderStatusBadgeKind,
                expectedMarker: String
            )
        ] = [
            (
                object: RecommendationFixtures.placeRoute,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-local",
                    costClass: .freeLocal
                ),
                expectedHint: .normal,
                expectedBadge: .freeLocal,
                expectedMarker: "localfallback"
            ),
            (
                object: RecommendationFixtures.routeBay,
