                    id: "a173-metered",
                    membershipTier: .pro,
                    costClass: .meteredPremium,
                    quotaSnapshot: searchAPICostMembershipMeteredQuota()
                ),
                expectedHint: .warning,
                expectedBadge: .meteredPremium,
                expectedMarker: "meteredallowed"
            ),
            (
                object: RecommendationFixtures.videoTutorial,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-region",
                    membershipTier: .plus,
                    costClass: .includedQuota,
                    region: .china,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4)
                ),
                expectedHint: .warning,
                expectedBadge: .termsBlocked,
                expectedMarker: "regionreviewrequired"
            ),
            (
                object: RecommendationFixtures.threadPriorChat,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-cost",
                    membershipTier: .plus,
                    costClass: .blockedByCost,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4)
                ),
                expectedHint: .disabled,
                expectedBadge: .costBlocked,
                expectedMarker: "costclassblocked"
            ),
            (
                object: RecommendationFixtures.answerCard,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-privacy",
                    membershipTier: .plus,
                    costClass: .includedQuota,
                    privacyClass: .private,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4)
                ),
                expectedHint: .disabled,
                expectedBadge: .privacyBlocked,
                expectedMarker: "privacyblocksremoteposture"
            ),
            (
                object: RecommendationFixtures.songSunset,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-invalid",
                    membershipTier: .plus,
                    costClass: .includedQuota,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4),
                    plan: searchAPICostMembershipMisorderedPlan()
                ),
                expectedHint: .disabled,
                expectedBadge: .unavailable,
                expectedMarker: "invalidplan"
            ),
            (
                object: RecommendationFixtures.contactCoworker,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-quota",
                    membershipTier: .plus,
                    costClass: .includedQuota,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 0)
                ),
                expectedHint: .disabled,
                expectedBadge: .costBlocked,
                expectedMarker: "quotaunavailable"
            ),
            (
                object: RecommendationFixtures.toolEntryHealth,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-coverage",
                    membershipTier: .plus,
                    costClass: .includedQuota,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4),
                    plan: searchAPICostMembershipCoveragePlan([.free])
                ),
                expectedHint: .disabled,
                expectedBadge: .unavailable,
                expectedMarker: "membershipcoveragemissing"
            ),
            (
                object: RecommendationFixtures.placeWithTrustPills,
                decision: searchAPICostMembershipRoutingDecision(
                    id: "a173-preferred",
                    membershipTier: .plus,
                    costClass: .includedQuota,
                    quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4),
                    preferredRouteKind: .meteredAllowed
                ),
                expectedHint: .disabled,
                expectedBadge: .termsBlocked,
                expectedMarker: "preferredroutenotallowed"
            ),
        ]
        var selectedText: [String] = []
        for (index, testCase) in cases.enumerated() {
            let hiddenID = "a173-routing-hidden-\(index)"
            let missingID = "a173-routing-missing-\(index)"
            let hiddenDecision = searchAPICostMembershipRoutingDecision(
                id: "a173-hidden-\(index)",
                membershipTier: .pro,
                costClass: .meteredPremium,
                quotaSnapshot: searchAPICostMembershipMeteredQuota()
            )
            let recommendationProvider = SpyRecommendationProviderForBootstrap(
                matches: [testCase.object]
            )
            let source = ServerProviderSearchAPICostMembershipRoutingDecisionStatusSourceProducer()
                .statusSource(
                    inputs: [
                        .init(
                            recommendationID: testCase.object.id,
                            statusSourceID: "a173-routing-source-\(index)",
                            statusSourceRank: index + 1,
                            decision: testCase.decision
                        ),
                        .init(
                            recommendationID: hiddenID,
                            statusSourceID: "a173-routing-hidden-source-\(index)",
                            statusSourceRank: 999,
                            isVisible: false,
                            decision: hiddenDecision
                        ),
                    ],
                    renderedRecommendationIDs: [testCase.object.id]
                )
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [source]
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
            let sourceStatus = try XCTUnwrap(
                source.providerStatusPresentation(for: testCase.object.id),
                testCase.object.id
            )
            let rootStatus = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: testCase.object.id),
                testCase.object.id
            )
            let storeStatus = try XCTUnwrap(
                store.providerStatusPresentation(for: testCase.object.id),
                testCase.object.id
            )
            let text = providerStatusSearchText(storeStatus)

            XCTAssertEqual(store.recommendedMatches, [testCase.object], testCase.object.id)
            XCTAssertEqual(sourceStatus, rootStatus, testCase.object.id)
            XCTAssertEqual(rootStatus, storeStatus, testCase.object.id)
            XCTAssertNil(source.providerStatusPresentation(for: hiddenID), testCase.object.id)
            XCTAssertNil(source.providerStatusPresentation(for: missingID), testCase.object.id)
            XCTAssertNil(
                bootstrap.providerStatusProvider?.providerStatusPresentation(for: hiddenID),
                testCase.object.id
            )
            XCTAssertNil(
                bootstrap.providerStatusProvider?.providerStatusPresentation(for: missingID),
                testCase.object.id
            )
            XCTAssertNil(store.providerStatusPresentation(for: hiddenID), testCase.object.id)
            XCTAssertNil(store.providerStatusPresentation(for: missingID), testCase.object.id)
            XCTAssertEqual(storeStatus.cardHint, testCase.expectedHint, testCase.object.id)
            XCTAssertNotNil(badge(testCase.expectedBadge, in: storeStatus), testCase.object.id)
            XCTAssertTrue(text.contains(testCase.expectedMarker), testCase.object.id)
            XCTAssertTrue(text.contains("search api cost membership routing"), testCase.object.id)
            XCTAssertTrue(text.contains("isruntimecallable false"), testCase.object.id)
            XCTAssertTrue(text.contains("no transport or provider runtime has run"), testCase.object.id)
            selectedText.append(text)
        }

        let joinedText = selectedText.joined(separator: "\n")
        XCTAssertFalse(joinedText.contains("a173-routing-hidden-source"))
        XCTAssertFalse(joinedText.contains("a173-hidden"))
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(joinedText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPICostMembershipRoutingStatusSourceOrderIsDeterministic() throws {
        let renderedObject = RecommendationFixtures.searchResult
        let fallbackOnlyObject = RecommendationFixtures.placeRoute
        let hiddenID = "a173-order-hidden"
        let missingID = "a173-order-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [renderedObject, fallbackOnlyObject]
        )
        let firstDecision = searchAPICostMembershipRoutingDecision(
            id: "a173-order-first",
            membershipTier: .plus,
            costClass: .includedQuota,
            quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4)
        )
        let secondDecision = searchAPICostMembershipRoutingDecision(
            id: "a173-order-second",
            membershipTier: .pro,
            costClass: .meteredPremium,
            quotaSnapshot: searchAPICostMembershipMeteredQuota()
        )
        let hiddenDecision = searchAPICostMembershipRoutingDecision(
            id: "a173-order-hidden",
            membershipTier: .plus,
            costClass: .includedQuota,
            quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 4)
        )
        let routingSource = ServerProviderSearchAPICostMembershipRoutingDecisionStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: renderedObject.id,
                        statusSourceID: "a173-routing-first",
                        statusSourceRank: 1,
                        decision: firstDecision
                    ),
                    .init(
                        recommendationID: renderedObject.id,
                        statusSourceID: "a173-routing-second",
                        statusSourceRank: 2,
                        decision: secondDecision
                    ),
                    .init(
                        recommendationID: hiddenID,
                        statusSourceID: "a173-routing-hidden",
                        statusSourceRank: 3,
                        decision: hiddenDecision
                    ),
                ],
                renderedRecommendationIDs: [renderedObject.id]
            )
        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                renderedObject.id: providerStatusPresentation(
                    for: renderedObject.id,
                    label: "A173 fallback primary",
                    statusLine: "A173 fallback provider status selected.",
                    cardHint: .disabled
                ),
                fallbackOnlyObject.id: providerStatusPresentation(
                    for: fallbackOnlyObject.id,
                    label: "A173 fallback after miss",
                    statusLine: "A173 fallback after source miss.",
                    cardHint: .warning
                ),
            ]
        )
        let directFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusProvider: routingSource,
            providerStatusSources: [fallbackSource]
        )
        let routingFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [routingSource, fallbackSource]
        )
        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, routingSource]
        )
        let fallbackAfterMiss = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [routingSource, fallbackSource]
        )
        let directStore = ChatStore(
            recommendationProvider: directFirst.recommendationProvider,
            providerStatusProvider: directFirst.providerStatusProvider,
            feedbackRuntime: directFirst.feedbackRuntime,
            telemetryEmitter: directFirst.telemetryEmitter,
            capabilityRegistry: directFirst.capabilityRegistry
        )
        let routingStore = ChatStore(
            recommendationProvider: routingFirst.recommendationProvider,
            providerStatusProvider: routingFirst.providerStatusProvider,
            feedbackRuntime: routingFirst.feedbackRuntime,
            telemetryEmitter: routingFirst.telemetryEmitter,
            capabilityRegistry: routingFirst.capabilityRegistry
        )
        let fallbackStore = ChatStore(
            recommendationProvider: fallbackFirst.recommendationProvider,
            providerStatusProvider: fallbackFirst.providerStatusProvider,
            feedbackRuntime: fallbackFirst.feedbackRuntime,
            telemetryEmitter: fallbackFirst.telemetryEmitter,
            capabilityRegistry: fallbackFirst.capabilityRegistry
        )
        let fallbackAfterMissStore = ChatStore(
            recommendationProvider: fallbackAfterMiss.recommendationProvider,
            providerStatusProvider: fallbackAfterMiss.providerStatusProvider,
            feedbackRuntime: fallbackAfterMiss.feedbackRuntime,
            telemetryEmitter: fallbackAfterMiss.telemetryEmitter,
            capabilityRegistry: fallbackAfterMiss.capabilityRegistry
        )

        let sourceSelected = try XCTUnwrap(
            routingSource.providerStatusPresentation(for: renderedObject.id)
        )
        let directSelected = try XCTUnwrap(
            directStore.providerStatusPresentation(for: renderedObject.id)
        )
        let routingSelected = try XCTUnwrap(
            routingStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackSelected = try XCTUnwrap(
            fallbackStore.providerStatusPresentation(for: renderedObject.id)
        )
        let fallbackMissSelected = try XCTUnwrap(
            fallbackAfterMissStore.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let directText = providerStatusSearchText(directSelected)
        let routingText = providerStatusSearchText(routingSelected)
        let fallbackText = providerStatusSearchText(fallbackSelected)
        let fallbackAfterMissText = providerStatusSearchText(fallbackMissSelected)

        XCTAssertEqual(directStore.recommendedMatches, [renderedObject, fallbackOnlyObject])
        XCTAssertEqual(routingStore.recommendedMatches, [renderedObject, fallbackOnlyObject])
        XCTAssertEqual(fallbackStore.recommendedMatches, [renderedObject, fallbackOnlyObject])
        XCTAssertEqual(fallbackAfterMissStore.recommendedMatches, [renderedObject, fallbackOnlyObject])
        XCTAssertEqual(sourceSelected, directSelected)
        XCTAssertEqual(sourceSelected, routingSelected)
        XCTAssertNil(routingSource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routingSource.providerStatusPresentation(for: missingID))
        XCTAssertNil(directStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routingStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(fallbackStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(directStore.providerStatusPresentation(for: missingID))
        XCTAssertNil(routingStore.providerStatusPresentation(for: missingID))
        XCTAssertNil(fallbackStore.providerStatusPresentation(for: missingID))

        XCTAssertTrue(directText.contains("a173-routing-first"))
        XCTAssertTrue(directText.contains("includedquotapreferred"))
        XCTAssertFalse(directText.contains("a173-routing-second"))
        XCTAssertFalse(directText.contains("meteredallowed"))
        XCTAssertFalse(directText.contains("a173 fallback"))
        XCTAssertEqual(routingText, directText)

        XCTAssertTrue(fallbackText.contains("a173 fallback primary"))
        XCTAssertTrue(fallbackText.contains("fallback provider status"))
        XCTAssertFalse(fallbackText.contains("a173-routing-first"))
        XCTAssertFalse(fallbackText.contains("includedquotapreferred"))

        XCTAssertTrue(fallbackAfterMissText.contains("a173 fallback after miss"))
        XCTAssertTrue(fallbackAfterMissText.contains("fallback after source miss"))
        XCTAssertFalse(fallbackAfterMissText.contains("a173-routing-first"))
        XCTAssertFalse(fallbackAfterMissText.contains("includedquotapreferred"))

        for hiddenMarker in [hiddenID, missingID, "a173-routing-hidden"] {
            XCTAssertFalse(directText.contains(hiddenMarker), hiddenMarker)
            XCTAssertFalse(routingText.contains(hiddenMarker), hiddenMarker)
            XCTAssertFalse(fallbackText.contains(hiddenMarker), hiddenMarker)
            XCTAssertFalse(fallbackAfterMissText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(directText.contains(forbidden), forbidden)
            XCTAssertFalse(routingText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
            XCTAssertFalse(fallbackAfterMissText.contains(forbidden), forbidden)
        }
    }

