        for item in sourceItems {
            let itemText = [
                providerStatusSearchText(item.expectedReady),
                providerStatusSearchText(item.expectedBlocked),
            ].joined(separator: "\n")
            for marker in item.leakMarkers {
                XCTAssertTrue(itemText.contains(marker), "\(item.name): \(marker)")
            }
            if item.requiresCallableMarker {
                XCTAssertTrue(itemText.contains("isruntimecallable false"), item.name)
            }
            for suppressedID in allHiddenIDs + [missingID] {
                XCTAssertNil(
                    item.source.providerStatusPresentation(for: suppressedID),
                    "\(item.name): \(suppressedID)"
                )
            }
        }

        for (selectedIndex, selectedItem) in sourceItems.enumerated() {
            let trailingSources = sourceItems.enumerated().compactMap { index, item in
                index == selectedIndex ? nil : item.source
            }
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [selectedItem.source] + trailingSources
            )
            let store = ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
            let rootReady = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let rootBlocked = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let storeReady = try XCTUnwrap(
                store.providerStatusPresentation(for: readyObject.id),
                selectedItem.name
            )
            let storeBlocked = try XCTUnwrap(
                store.providerStatusPresentation(for: blockedObject.id),
                selectedItem.name
            )
            let selectedText = [
                providerStatusSearchText(storeReady),
                providerStatusSearchText(storeBlocked),
            ].joined(separator: "\n")

            XCTAssertEqual(
                store.recommendedMatches,
                [readyObject, blockedObject, fallbackOnlyObject],
                selectedItem.name
            )
            XCTAssertEqual(store.session.messages.count, 0, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedReady, rootReady, selectedItem.name)
            XCTAssertEqual(rootReady, storeReady, selectedItem.name)
            XCTAssertEqual(selectedItem.expectedBlocked, rootBlocked, selectedItem.name)
            XCTAssertEqual(rootBlocked, storeBlocked, selectedItem.name)
            XCTAssertNil(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: missingID),
                selectedItem.name
            )
            XCTAssertNil(store.providerStatusPresentation(for: missingID), selectedItem.name)
            for hiddenID in allHiddenIDs {
                XCTAssertNil(
                    bootstrap.providerStatusProvider?
                        .providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
                XCTAssertNil(
                    store.providerStatusPresentation(for: hiddenID),
                    "\(selectedItem.name): \(hiddenID)"
                )
            }
            for marker in selectedItem.leakMarkers {
                XCTAssertTrue(selectedText.contains(marker), "\(selectedItem.name): \(marker)")
            }
            if selectedItem.requiresCallableMarker {
                XCTAssertTrue(
                    selectedText.contains("isruntimecallable false"),
                    selectedItem.name
                )
            }
            for otherItem in sourceItems where otherItem.name != selectedItem.name {
                for marker in otherItem.leakMarkers {
                    XCTAssertFalse(
                        selectedText.contains(marker),
                        "\(selectedItem.name) leaked \(otherItem.name): \(marker)"
                    )
                }
            }
            for hiddenMarker in hiddenLeakMarkers {
                XCTAssertFalse(
                    selectedText.contains(hiddenMarker),
                    "\(selectedItem.name): \(hiddenMarker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(selectedItem.name): \(forbidden)")
            }
        }

        let fallbackAfterMissSources = sourceItems.compactMap { item -> (any ProviderStatusProviding)? in
            item.name == "fallback" ? nil : item.source
        }
        let fallbackAfterMissBootstrap = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: fallbackAfterMissSources + [fallbackSource]
        )
        let fallbackAfterMissStore = ChatStore(
            recommendationProvider: fallbackAfterMissBootstrap.recommendationProvider,
            providerStatusProvider: fallbackAfterMissBootstrap.providerStatusProvider,
            feedbackRuntime: fallbackAfterMissBootstrap.feedbackRuntime,
            completedRecommendationHandoff: fallbackAfterMissBootstrap.completedRecommendationHandoff,
            telemetryEmitter: fallbackAfterMissBootstrap.telemetryEmitter,
            capabilityRegistry: fallbackAfterMissBootstrap.capabilityRegistry
        )
        let fallbackAfterMissExpected = try XCTUnwrap(
            fallbackSource.providerStatusPresentation(for: fallbackAfterMissID)
        )
        let fallbackAfterMissRoot = try XCTUnwrap(
            fallbackAfterMissBootstrap.providerStatusProvider?
                .providerStatusPresentation(for: fallbackAfterMissID)
        )
        let fallbackAfterMissStoreCopy = try XCTUnwrap(
            fallbackAfterMissStore.providerStatusPresentation(for: fallbackAfterMissID)
        )
        let fallbackAfterMissText = providerStatusSearchText(fallbackAfterMissStoreCopy)

        XCTAssertEqual(
            fallbackAfterMissStore.recommendedMatches,
            [readyObject, blockedObject, fallbackOnlyObject]
        )
        XCTAssertEqual(fallbackAfterMissExpected, fallbackAfterMissRoot)
        XCTAssertEqual(fallbackAfterMissRoot, fallbackAfterMissStoreCopy)
        XCTAssertTrue(fallbackAfterMissText.contains("a174 fallback after miss"))
        XCTAssertTrue(fallbackAfterMissText.contains("fallback after stack miss"))
        for otherItem in sourceItems where otherItem.name != "fallback" {
            for marker in otherItem.leakMarkers {
                XCTAssertFalse(fallbackAfterMissText.contains(marker), marker)
            }
        }
        for hiddenMarker in hiddenLeakMarkers {
            XCTAssertFalse(fallbackAfterMissText.contains(hiddenMarker), hiddenMarker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(fallbackAfterMissText.contains(forbidden), forbidden)
        }
    }

    func test_compositionRoot_searchAPICostMembershipRoutingPolicyCompatibilityPreservesSelectedCopy() throws {
        let includedObject = RecommendationFixtures.searchResult
        let meteredObject = RecommendationFixtures.placeRoute
        let privacyObject = RecommendationFixtures.answerCard
        let fallbackOnlyObject = RecommendationFixtures.songSunset
        let renderedIDs = [includedObject.id, meteredObject.id, privacyObject.id]
        let hiddenIDs = [
            "a176-routing-hidden",
            "a176-metered-hidden",
            "a176-vendor-hidden",
            "a176-dispatch-hidden",
            "a176-authorization-hidden",
            "a176-lease-hidden",
        ]
        let missingID = "a176-policy-missing"
        let recommendationProvider = SpyRecommendationProviderForBootstrap(
            matches: [includedObject, meteredObject, privacyObject, fallbackOnlyObject]
        )
        let routingSource = ServerProviderSearchAPICostMembershipRoutingDecisionStatusSourceProducer()
            .statusSource(
                inputs: [
                    .init(
                        recommendationID: includedObject.id,
                        statusSourceID: "a176-routing-included-source",
                        statusSourceRank: 20,
                        decision: searchAPICostMembershipRoutingDecision(
                            id: "a176-routing-included",
                            membershipTier: .plus,
                            costClass: .includedQuota,
                            quotaSnapshot: searchAPICostMembershipIncludedQuota(remaining: 8)
                        )
                    ),
                    .init(
                        recommendationID: meteredObject.id,
                        statusSourceID: "a176-routing-metered-source",
                        statusSourceRank: 21,
                        decision: searchAPICostMembershipRoutingDecision(
                            id: "a176-routing-metered",
                            membershipTier: .pro,
                            costClass: .meteredPremium,
                            quotaSnapshot: searchAPICostMembershipMeteredQuota()
                        )
                    ),
                    .init(
                        recommendationID: privacyObject.id,
