                        authorization: try searchAPIVendorDispatchAuthorizationAccepted(
                            traceID: "a176-authorization-hidden",
                            vendorID: "a176-authorization-hidden-vendor"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
            )
        let leaseSource = ServerProviderSearchAPITransportLeaseStatusSourceProducer()
            .statusSource(
                leases: [
                    .init(
                        recommendationID: includedObject.id,
                        lease: searchAPITransportLeaseIssued(
                            id: "a176-lease-included",
                            vendorID: "a176-lease-included-vendor",
