                        )
                    ),
                    .init(
                        recommendationID: meteredObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a176-lease-metered-blocked",
                            reason: .explicitBudgetDenied,
                            vendorID: "a176-lease-metered-private-vendor",
                            budgetID: "a176-lease-metered-denied-budget"
                        )
                    ),
                    .init(
                        recommendationID: privacyObject.id,
                        lease: searchAPITransportLeaseRejected(
                            id: "a176-lease-privacy-blocked",
                            reason: .providerNotAllowed,
                            vendorID: "a176-lease-privacy-vendor",
                            budgetID: "a176-lease-privacy-denied-budget"
                        )
                    ),
                    .init(
                        recommendationID: hiddenIDs[5],
                        lease: searchAPITransportLeaseIssued(
                            id: "a176-lease-hidden",
                            vendorID: "a176-lease-hidden-vendor",
                            budgetID: "a176-lease-hidden-budget"
                        )
                    ),
                ],
                renderedRecommendationIDs: renderedIDs
