        let fallbackSource = SpyProviderStatusProviderForBootstrap(
            presentationsByRecommendationID: [
                includedObject.id: providerStatusPresentation(
                    for: includedObject.id,
                    label: "A176 fallback included",
                    statusLine: "A176 fallback included selected.",
                    cardHint: .disabled
                ),
                meteredObject.id: providerStatusPresentation(
                    for: meteredObject.id,
                    label: "A176 fallback metered",
                    statusLine: "A176 fallback metered selected.",
                    cardHint: .disabled
                ),
                privacyObject.id: providerStatusPresentation(
                    for: privacyObject.id,
                    label: "A176 fallback privacy",
                    statusLine: "A176 fallback privacy selected.",
                    cardHint: .disabled
                ),
                fallbackOnlyObject.id: providerStatusPresentation(
                    for: fallbackOnlyObject.id,
                    label: "A176 fallback after policy miss",
                    statusLine: "A176 fallback after policy stack miss selected.",
                    cardHint: .disabled
                ),
            ]
        )

        let routingExpectedIncluded = try XCTUnwrap(
            routingSource.providerStatusPresentation(for: includedObject.id)
        )
        let routingExpectedMetered = try XCTUnwrap(
            routingSource.providerStatusPresentation(for: meteredObject.id)
        )
        let routingExpectedPrivacy = try XCTUnwrap(
            routingSource.providerStatusPresentation(for: privacyObject.id)
        )
        let downstreamItems: [
            (
                name: String,
                source: any ProviderStatusProviding,
                expectedIncluded: ProviderStatusPresentation,
                expectedMetered: ProviderStatusPresentation,
                expectedPrivacy: ProviderStatusPresentation
            )
        ] = [
            (
                name: "metered entitlement",
                source: meteredSource,
                expectedIncluded: try XCTUnwrap(
                    meteredSource.providerStatusPresentation(for: includedObject.id)
                ),
                expectedMetered: try XCTUnwrap(
                    meteredSource.providerStatusPresentation(for: meteredObject.id)
                ),
                expectedPrivacy: try XCTUnwrap(
                    meteredSource.providerStatusPresentation(for: privacyObject.id)
                )
            ),
            (
                name: "vendor policy",
                source: vendorPolicySource,
                expectedIncluded: try XCTUnwrap(
                    vendorPolicySource.providerStatusPresentation(for: includedObject.id)
                ),
                expectedMetered: try XCTUnwrap(
                    vendorPolicySource.providerStatusPresentation(for: meteredObject.id)
                ),
                expectedPrivacy: try XCTUnwrap(
                    vendorPolicySource.providerStatusPresentation(for: privacyObject.id)
                )
            ),
            (
                name: "payload dispatch",
                source: dispatchSource,
                expectedIncluded: try XCTUnwrap(
                    dispatchSource.providerStatusPresentation(for: includedObject.id)
                ),
                expectedMetered: try XCTUnwrap(
                    dispatchSource.providerStatusPresentation(for: meteredObject.id)
                ),
                expectedPrivacy: try XCTUnwrap(
                    dispatchSource.providerStatusPresentation(for: privacyObject.id)
                )
            ),
            (
                name: "dispatch authorization",
                source: authorizationSource,
                expectedIncluded: try XCTUnwrap(
                    authorizationSource.providerStatusPresentation(for: includedObject.id)
                ),
                expectedMetered: try XCTUnwrap(
                    authorizationSource.providerStatusPresentation(for: meteredObject.id)
                ),
                expectedPrivacy: try XCTUnwrap(
                    authorizationSource.providerStatusPresentation(for: privacyObject.id)
                )
            ),
            (
                name: "transport lease",
                source: leaseSource,
                expectedIncluded: try XCTUnwrap(
                    leaseSource.providerStatusPresentation(for: includedObject.id)
                ),
                expectedMetered: try XCTUnwrap(
                    leaseSource.providerStatusPresentation(for: meteredObject.id)
                ),
                expectedPrivacy: try XCTUnwrap(
                    leaseSource.providerStatusPresentation(for: privacyObject.id)
                )
            ),
        ]
        let routingMarkers = [
            "a176-routing-included-source",
            "a176-routing-metered-source",
            "a176-routing-privacy-source",
            "includedquotapreferred",
            "meteredallowed",
            "privacyblocksremoteposture",
        ]
        let downstreamMarkers = [
            "a176-metered-included-vendor",
            "overquota",
            "a176-metered-privacy-vendor",
            "a176-vendor-policy-ready-vendor",
            "a176-vendor-policy-metered-private-vendor",
            "a176-vendor-policy-privacy-vendor",
            "a176-dispatch-included-request",
            "a176-dispatch-metered-blocked",
            "a176-dispatch-privacy-blocked",
            "a176-authorization-included-vendor",
            "a176-authorization-metered-private-vendor",
            "a176-authorization-privacy-vendor",
            "a176-lease-included-vendor",
            "a176-lease-metered-private-vendor",
            "a176-lease-privacy-vendor",
        ]
        let fallbackMarkers = [
            "a176 fallback included",
            "a176 fallback metered",
            "a176 fallback privacy",
            "a176 fallback after policy miss",
        ]
        let nonFallbackSources = [
            routingSource,
            meteredSource,
            vendorPolicySource,
            dispatchSource,
            authorizationSource,
            leaseSource,
        ] as [any ProviderStatusProviding]

        func makeStore(_ bootstrap: AppBootstrap) -> ChatStore {
            ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
        }

        let routingFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: nonFallbackSources + [fallbackSource]
        )
        let routingFirstStore = makeStore(routingFirst)
        let routingRootIncluded = try XCTUnwrap(
            routingFirst.providerStatusProvider?
                .providerStatusPresentation(for: includedObject.id)
        )
        let routingRootMetered = try XCTUnwrap(
            routingFirst.providerStatusProvider?
                .providerStatusPresentation(for: meteredObject.id)
        )
        let routingRootPrivacy = try XCTUnwrap(
            routingFirst.providerStatusProvider?
                .providerStatusPresentation(for: privacyObject.id)
        )
        let routingStoreIncluded = try XCTUnwrap(
            routingFirstStore.providerStatusPresentation(for: includedObject.id)
        )
        let routingStoreMetered = try XCTUnwrap(
            routingFirstStore.providerStatusPresentation(for: meteredObject.id)
        )
        let routingStorePrivacy = try XCTUnwrap(
            routingFirstStore.providerStatusPresentation(for: privacyObject.id)
        )
        let routingFirstText = [
            providerStatusSearchText(routingStoreIncluded),
            providerStatusSearchText(routingStoreMetered),
            providerStatusSearchText(routingStorePrivacy),
        ].joined(separator: "\n")

        XCTAssertEqual(
            routingFirstStore.recommendedMatches,
            [includedObject, meteredObject, privacyObject, fallbackOnlyObject]
        )
        XCTAssertEqual(routingExpectedIncluded, routingRootIncluded)
        XCTAssertEqual(routingRootIncluded, routingStoreIncluded)
        XCTAssertEqual(routingExpectedMetered, routingRootMetered)
        XCTAssertEqual(routingRootMetered, routingStoreMetered)
        XCTAssertEqual(routingExpectedPrivacy, routingRootPrivacy)
        XCTAssertEqual(routingRootPrivacy, routingStorePrivacy)
        XCTAssertEqual(routingStoreIncluded.cardHint, .normal)
        XCTAssertEqual(routingStoreMetered.cardHint, .warning)
        XCTAssertEqual(routingStorePrivacy.cardHint, .disabled)
        XCTAssertTrue(routingFirstText.contains("isruntimecallable false"))
        XCTAssertTrue(routingFirstText.contains("no transport or provider runtime has run"))
        for marker in routingMarkers {
            XCTAssertTrue(routingFirstText.contains(marker), marker)
        }
        for marker in downstreamMarkers + fallbackMarkers {
            XCTAssertFalse(routingFirstText.contains(marker), marker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(routingFirstText.contains(forbidden), forbidden)
        }

        for item in downstreamItems {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [item.source, routingSource, fallbackSource]
            )
            let store = makeStore(bootstrap)
            let rootIncluded = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: includedObject.id),
                item.name
            )
            let rootMetered = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: meteredObject.id),
                item.name
            )
            let rootPrivacy = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: privacyObject.id),
                item.name
            )
            let storeIncluded = try XCTUnwrap(
                store.providerStatusPresentation(for: includedObject.id),
                item.name
            )
            let storeMetered = try XCTUnwrap(
                store.providerStatusPresentation(for: meteredObject.id),
                item.name
            )
            let storePrivacy = try XCTUnwrap(
                store.providerStatusPresentation(for: privacyObject.id),
                item.name
            )
            let selectedText = [
                providerStatusSearchText(storeIncluded),
                providerStatusSearchText(storeMetered),
                providerStatusSearchText(storePrivacy),
            ].joined(separator: "\n")

            XCTAssertEqual(
                store.recommendedMatches,
                [includedObject, meteredObject, privacyObject, fallbackOnlyObject],
                item.name
            )
            XCTAssertEqual(item.expectedIncluded, rootIncluded, item.name)
            XCTAssertEqual(rootIncluded, storeIncluded, item.name)
            XCTAssertEqual(item.expectedMetered, rootMetered, item.name)
            XCTAssertEqual(rootMetered, storeMetered, item.name)
            XCTAssertEqual(item.expectedPrivacy, rootPrivacy, item.name)
            XCTAssertEqual(rootPrivacy, storePrivacy, item.name)
            for marker in routingMarkers {
                XCTAssertFalse(
                    selectedText.contains(marker),
                    "\(item.name) leaked routing marker: \(marker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(item.name): \(forbidden)")
            }
        }

        for source in nonFallbackSources + [fallbackSource] {
            XCTAssertNil(source.providerStatusPresentation(for: missingID))
            for hiddenID in hiddenIDs {
                XCTAssertNil(source.providerStatusPresentation(for: hiddenID), hiddenID)
            }
        }
        XCTAssertNil(routingFirst.providerStatusProvider?.providerStatusPresentation(for: missingID))
        XCTAssertNil(routingFirstStore.providerStatusPresentation(for: missingID))
        for hiddenID in hiddenIDs {
            XCTAssertNil(routingFirst.providerStatusProvider?.providerStatusPresentation(for: hiddenID))
            XCTAssertNil(routingFirstStore.providerStatusPresentation(for: hiddenID))
        }

        let fallbackAfterMiss = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: nonFallbackSources + [fallbackSource]
        )
        let fallbackAfterMissStore = makeStore(fallbackAfterMiss)
        let fallbackExpected = try XCTUnwrap(
            fallbackSource.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackRoot = try XCTUnwrap(
            fallbackAfterMiss.providerStatusProvider?
                .providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackStore = try XCTUnwrap(
            fallbackAfterMissStore.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackText = providerStatusSearchText(fallbackStore)

        XCTAssertEqual(fallbackExpected, fallbackRoot)
        XCTAssertEqual(fallbackRoot, fallbackStore)
        XCTAssertTrue(fallbackText.contains("a176 fallback after policy miss"))
        for marker in routingMarkers + downstreamMarkers {
            XCTAssertFalse(fallbackText.contains(marker), marker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(fallbackText.contains(forbidden), forbidden)
        }
    }

