                    label: "A179 fallback rejected",
                    statusLine: "A179 fallback rejected selected.",
                    cardHint: .disabled
                ),
                fallbackOnlyObject.id: providerStatusPresentation(
                    for: fallbackOnlyObject.id,
                    label: "A179 fallback after route-policy miss",
                    statusLine: "A179 fallback after route-policy source miss selected.",
                    cardHint: .disabled
                ),
            ]
        )

        let expectedIncluded = try XCTUnwrap(
            routePolicySource.providerStatusPresentation(for: includedObject.id)
        )
        let expectedMetered = try XCTUnwrap(
            routePolicySource.providerStatusPresentation(for: meteredObject.id)
        )
        let expectedRejected = try XCTUnwrap(
            routePolicySource.providerStatusPresentation(for: rejectedObject.id)
        )
        let lowerPriorityMarkers = [
            "a179-lower-included-source",
            "a179-lower-included-vendor",
            "a179-lower-metered-source",
            "a179-lower-metered-vendor",
            "a179-lower-rejected-source",
            "a179-lower-rejected-vendor",
            "payloaddispatchblocked",
        ]
        let fallbackMarkers = [
            "a179 fallback included",
            "a179 fallback metered",
            "a179 fallback rejected",
            "a179 fallback after route-policy miss",
        ]
        let selectedMarkers = [
            "a179-route-policy-included-source",
            "a179-included-vendor",
            "includedquotapreferred",
            "a179-route-policy-metered-source",
            "a179-metered-vendor",
            "meteredallowed",
            "a179-route-policy-rejected-source",
            "a179-rejected-vendor",
            "vendorpolicyrejected",
        ]
        let duplicateMarkers = [
            "a179-route-policy-duplicate-source",
            "a179-duplicate-vendor",
        ]

        func makeStore(_ bootstrap: AppBootstrap) -> ChatStore {
            ChatStore(
                recommendationProvider: bootstrap.recommendationProvider,
                providerStatusProvider: bootstrap.providerStatusProvider,
                feedbackRuntime: bootstrap.feedbackRuntime,
                completedRecommendationHandoff: bootstrap.completedRecommendationHandoff,
                telemetryEmitter: bootstrap.telemetryEmitter,
                capabilityRegistry: bootstrap.capabilityRegistry
            )
        }

        let routePolicyFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [
                routePolicySource,
                lowerPriorityRoutePolicySource,
                fallbackSource,
            ]
        )
        let routePolicyFirstStore = makeStore(routePolicyFirst)
        let rootIncluded = try XCTUnwrap(
            routePolicyFirst.providerStatusProvider?
                .providerStatusPresentation(for: includedObject.id)
        )
        let rootMetered = try XCTUnwrap(
            routePolicyFirst.providerStatusProvider?
                .providerStatusPresentation(for: meteredObject.id)
        )
        let rootRejected = try XCTUnwrap(
            routePolicyFirst.providerStatusProvider?
                .providerStatusPresentation(for: rejectedObject.id)
        )
        let storeIncluded = try XCTUnwrap(
            routePolicyFirstStore.providerStatusPresentation(for: includedObject.id)
        )
        let storeMetered = try XCTUnwrap(
            routePolicyFirstStore.providerStatusPresentation(for: meteredObject.id)
        )
        let storeRejected = try XCTUnwrap(
            routePolicyFirstStore.providerStatusPresentation(for: rejectedObject.id)
        )
        let routePolicyFirstText = [
            providerStatusSearchText(storeIncluded),
            providerStatusSearchText(storeMetered),
            providerStatusSearchText(storeRejected),
        ].joined(separator: "\n")

        XCTAssertEqual(
            routePolicyFirstStore.recommendedMatches,
            [includedObject, meteredObject, rejectedObject, fallbackOnlyObject]
        )
        XCTAssertEqual(expectedIncluded, rootIncluded)
        XCTAssertEqual(rootIncluded, storeIncluded)
        XCTAssertEqual(expectedMetered, rootMetered)
        XCTAssertEqual(rootMetered, storeMetered)
        XCTAssertEqual(expectedRejected, rootRejected)
        XCTAssertEqual(rootRejected, storeRejected)
        XCTAssertEqual(storeIncluded.cardHint, .normal)
        XCTAssertEqual(storeMetered.cardHint, .warning)
        XCTAssertEqual(storeRejected.cardHint, .disabled)
        XCTAssertTrue(routePolicyFirstText.contains("isruntimecallable false"))
        XCTAssertTrue(routePolicyFirstText.contains("isexecutable false"))
        XCTAssertTrue(routePolicyFirstText.contains("no transport or provider runtime has run"))
        for marker in selectedMarkers {
            XCTAssertTrue(routePolicyFirstText.contains(marker), marker)
        }
        for marker in duplicateMarkers + lowerPriorityMarkers + fallbackMarkers {
            XCTAssertFalse(routePolicyFirstText.contains(marker), marker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(routePolicyFirstText.contains(forbidden), forbidden)
        }

        XCTAssertNil(routePolicySource.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routePolicySource.providerStatusPresentation(for: missingID))
        XCTAssertNil(routePolicyFirst.providerStatusProvider?.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routePolicyFirst.providerStatusProvider?.providerStatusPresentation(for: missingID))
        XCTAssertNil(routePolicyFirstStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routePolicyFirstStore.providerStatusPresentation(for: missingID))

        let fallbackFirst = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [fallbackSource, routePolicySource]
        )
        let fallbackFirstStore = makeStore(fallbackFirst)
        let fallbackFirstIncluded = try XCTUnwrap(
            fallbackFirstStore.providerStatusPresentation(for: includedObject.id)
        )
        let fallbackFirstText = providerStatusSearchText(fallbackFirstIncluded)

        XCTAssertEqual(fallbackFirstStore.recommendedMatches, routePolicyFirstStore.recommendedMatches)
        XCTAssertEqual(fallbackFirstIncluded.cardHint, .disabled)
        XCTAssertTrue(fallbackFirstText.contains("a179 fallback included"))
        XCTAssertFalse(fallbackFirstText.contains("a179-route-policy-included-source"))
        XCTAssertFalse(fallbackFirstText.contains("a179-included-vendor"))
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(fallbackFirstText.contains(forbidden), forbidden)
        }

        let fallbackAfterMissExpected = try XCTUnwrap(
            fallbackSource.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackAfterMissRoot = try XCTUnwrap(
            routePolicyFirst.providerStatusProvider?
                .providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackAfterMissStore = try XCTUnwrap(
            routePolicyFirstStore.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackAfterMissText = providerStatusSearchText(fallbackAfterMissStore)

        XCTAssertEqual(fallbackAfterMissExpected, fallbackAfterMissRoot)
        XCTAssertEqual(fallbackAfterMissRoot, fallbackAfterMissStore)
        XCTAssertTrue(fallbackAfterMissText.contains("a179 fallback after route-policy miss"))
        for marker in selectedMarkers + lowerPriorityMarkers + duplicateMarkers {
            XCTAssertFalse(fallbackAfterMissText.contains(marker), marker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(fallbackAfterMissText.contains(forbidden), forbidden)
        }
    }

    private func searchAPIRoutePolicyCompatibilityDecision(
        id: String,
        membershipTier: MembershipTier,
        vendorID: String,
        costClass: ProviderCostClass,
        routeKind: ServerProviderSearchAPICostMembershipRouteKind,
        quotaPosture: ServerProviderSearchAPIRoutePolicyQuotaPosture,
        state: ServerProviderSearchAPIRoutePolicyCompatibilityState = .compatible,
        rejectionReason: ServerProviderSearchAPIRoutePolicyCompatibilityRejectionReason? = nil
    ) -> ServerProviderSearchAPIRoutePolicyCompatibilityDecision {
        let safeCopy = ServerProviderSearchAPIRoutePolicyCompatibilitySafeCopy(
            id: "\(id)-safe-copy",
            inputID: "\(id)-input",
            renderedRecommendationID: "\(id)-rendered",
            routingDecisionID: "\(id)-routing",
            meteredDecisionID: "\(id)-metered",
            vendorPolicyDecisionID: "\(id)-vendor-policy",
            payloadDispatchReceiptID: "\(id)-dispatch",
            dispatchAuthorizationID: "\(id)-authorization",
            transportLeaseID: "\(id)-lease",
            selectedStatusSourceID: "\(id)-selected-source",
            selectedStatusSourceRank: 1,
            membershipTier: membershipTier,
            providerFamily: .searchAPI,
            vendorID: vendorID,
            capability: .webSearch,
            costClass: costClass,
            routeKind: routeKind,
            quotaPosture: quotaPosture,
            sourceCitationPosture: .passedCitationRequired,
            state: state,
            rejectionReason: rejectionReason,
            isRuntimeCallable: false,
            isExecutable: false
        )
        return ServerProviderSearchAPIRoutePolicyCompatibilityDecision(
            id: "\(id)-decision",
            inputID: "\(id)-input",
            state: state,
            statusLine: "Route-policy compatibility fixture is value-only metadata.",
            rejectionReason: rejectionReason,
            safeCopy: safeCopy
        )
    }

