        )
        let routePolicyText = [
            providerStatusSearchText(routePolicyStoreIncluded),
            providerStatusSearchText(routePolicyStoreMetered),
            providerStatusSearchText(routePolicyStoreRejected),
        ].joined(separator: "\n")

        XCTAssertEqual(
            routePolicyFirstStore.recommendedMatches,
            [includedObject, meteredObject, rejectedObject, fallbackOnlyObject]
        )
        XCTAssertEqual(routePolicyExpectedIncluded, routePolicyRootIncluded)
        XCTAssertEqual(routePolicyRootIncluded, routePolicyStoreIncluded)
        XCTAssertEqual(routePolicyExpectedMetered, routePolicyRootMetered)
        XCTAssertEqual(routePolicyRootMetered, routePolicyStoreMetered)
        XCTAssertEqual(routePolicyExpectedRejected, routePolicyRootRejected)
        XCTAssertEqual(routePolicyRootRejected, routePolicyStoreRejected)
        XCTAssertEqual(routePolicyStoreIncluded.cardHint, .normal)
        XCTAssertEqual(routePolicyStoreMetered.cardHint, .warning)
        XCTAssertEqual(routePolicyStoreRejected.cardHint, .disabled)
        XCTAssertTrue(routePolicyText.contains("isruntimecallable false"))
        XCTAssertTrue(routePolicyText.contains("isexecutable false"))
        XCTAssertTrue(routePolicyText.contains("no transport or provider runtime has run"))
        for marker in routePolicyMarkers {
            XCTAssertTrue(routePolicyText.contains(marker), marker)
        }
        for marker in stageMarkers + fallbackMarkers {
            XCTAssertFalse(routePolicyText.contains(marker), marker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(routePolicyText.contains(forbidden), forbidden)
        }

        for item in stageItems {
            let bootstrap = AppBootstrap(
                recommendationProvider: recommendationProvider,
                providerStatusSources: [item.source, routePolicySource, fallbackSource]
            )
            let store = makeStore(bootstrap)
            let rootIncluded = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: includedObject.id),
                item.name
            )
            let rootMetered = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: meteredObject.id),
                item.name
            )
            let rootRejected = try XCTUnwrap(
                bootstrap.providerStatusProvider?
                    .providerStatusPresentation(for: rejectedObject.id),
                item.name
            )
            let storeIncluded = try XCTUnwrap(
                store.providerStatusPresentation(for: includedObject.id),
                item.name
            )
            let storeMetered = try XCTUnwrap(
                store.providerStatusPresentation(for: meteredObject.id),
                item.name
            )
            let storeRejected = try XCTUnwrap(
                store.providerStatusPresentation(for: rejectedObject.id),
                item.name
            )
            let selectedText = [
                providerStatusSearchText(storeIncluded),
                providerStatusSearchText(storeMetered),
                providerStatusSearchText(storeRejected),
            ].joined(separator: "\n")

            XCTAssertEqual(
                store.recommendedMatches,
                [includedObject, meteredObject, rejectedObject, fallbackOnlyObject],
                item.name
            )
            XCTAssertEqual(item.expectedIncluded, rootIncluded, item.name)
            XCTAssertEqual(rootIncluded, storeIncluded, item.name)
            XCTAssertEqual(item.expectedMetered, rootMetered, item.name)
            XCTAssertEqual(rootMetered, storeMetered, item.name)
            XCTAssertEqual(item.expectedRejected, rootRejected, item.name)
            XCTAssertEqual(rootRejected, storeRejected, item.name)
            for marker in routePolicyMarkers {
                XCTAssertFalse(
                    selectedText.contains(marker),
                    "\(item.name) leaked route-policy marker: \(marker)"
                )
            }
            for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
                XCTAssertFalse(selectedText.contains(forbidden), "\(item.name): \(forbidden)")
            }
        }

        for source in [routePolicySource] + stageSources + [fallbackSource] {
            XCTAssertNil(source.providerStatusPresentation(for: hiddenID))
            XCTAssertNil(source.providerStatusPresentation(for: missingID))
        }
        XCTAssertNil(routePolicyFirst.providerStatusProvider?.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routePolicyFirst.providerStatusProvider?.providerStatusPresentation(for: missingID))
        XCTAssertNil(routePolicyFirstStore.providerStatusPresentation(for: hiddenID))
        XCTAssertNil(routePolicyFirstStore.providerStatusPresentation(for: missingID))

        let fallbackAfterMiss = AppBootstrap(
            recommendationProvider: recommendationProvider,
            providerStatusSources: [routePolicySource] + stageSources + [fallbackSource]
        )
        let fallbackAfterMissStore = makeStore(fallbackAfterMiss)
        let fallbackAfterMissExpected = try XCTUnwrap(
            fallbackSource.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackAfterMissRoot = try XCTUnwrap(
            fallbackAfterMiss.providerStatusProvider?
                .providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackAfterMissStoreCopy = try XCTUnwrap(
            fallbackAfterMissStore.providerStatusPresentation(for: fallbackOnlyObject.id)
        )
        let fallbackAfterMissText = providerStatusSearchText(fallbackAfterMissStoreCopy)

        XCTAssertEqual(fallbackAfterMissExpected, fallbackAfterMissRoot)
        XCTAssertEqual(fallbackAfterMissRoot, fallbackAfterMissStoreCopy)
        XCTAssertTrue(fallbackAfterMissText.contains("a180 fallback after stack miss"))
        for marker in routePolicyMarkers + stageMarkers {
            XCTAssertFalse(fallbackAfterMissText.contains(marker), marker)
        }
        for forbidden in searchAPITransportResponseStatusForbiddenFragments() {
            XCTAssertFalse(fallbackAfterMissText.contains(forbidden), forbidden)
        }
    }

