    }

    private func assertLocalOnlyQuotaSnapshot(
        _ snapshot: ServerProviderQuotaSnapshot,
        file: StaticString = #filePath,
        line: UInt = #line
    ) {
        XCTAssertEqual(
            snapshot,
            ServerProviderQuotaSnapshot(providerAccessProfile: .freeLocalDefault),
            file: file,
            line: line
        )
        XCTAssertEqual(snapshot.allowedProviderFamilies, [.appleLocal, .cache], file: file, line: line)
        XCTAssertTrue(snapshot.entitledProviderFamilies.isEmpty, file: file, line: line)
        XCTAssertTrue(snapshot.remainingIncludedQuota.isEmpty, file: file, line: line)
        XCTAssertTrue(snapshot.meteredEligibleProviderFamilies.isEmpty, file: file, line: line)
        XCTAssertTrue(snapshot.disabledProviderFamilies.isEmpty, file: file, line: line)
        XCTAssertTrue(snapshot.enabledExperimentalProviderFamilies.isEmpty, file: file, line: line)
    }

    private func pipelineSearchReceipt(
        traceID: String,
        sourceHost: String = "example.com"
    ) -> ServerProviderRuntimeReceipt {
        ServerProviderRuntimePipeline.run(
            readinessDecision: runtimeSearchReadinessDecision(
                traceID: traceID,
                sourceHost: sourceHost
            )
        )
    }

    private func runtimeSearchReadinessDecision(
        traceID: String,
        sourceHost: String
    ) -> ServerProviderExecutionReadinessDecision {
        let envelope = ServerProviderEnvelope(
            traceID: traceID,
            capability: .webSearch,
            providerFamily: .searchAPI,
            privacyClass: .general,
            membershipTier: .pro,
            costClass: .meteredPremium,
            freshness: .livePreferred,
            sourcePolicy: ServerSourcePolicy(
                sourceState: .passed,
                robotsState: .notApplicable,
                attributionRequired: true,
                sourceHost: sourceHost
            ),
            meteredProviderEntitlements: [.searchAPI]
        )
        let validation = ServerProviderEnvelopeValidator.validate(envelope)
        XCTAssertTrue(validation.isAllowed)
        return ServerProviderExecutionGate.evaluate(
            .executable(envelope: envelope, validation: validation)
        )
    }

    private func searchDryRunPresentation(
        traceID: String,
        sourceHost: String
    ) -> ServerProviderDryRunPresentation {
        let envelope = ServerProviderEnvelope(
            traceID: traceID,
            capability: .webSearch,
            providerFamily: .searchAPI,
            privacyClass: .general,
            membershipTier: .pro,
            costClass: .meteredPremium,
            freshness: .livePreferred,
            sourcePolicy: ServerSourcePolicy(
                sourceState: .passed,
                robotsState: .notApplicable,
                attributionRequired: true,
                sourceHost: sourceHost
            ),
            meteredProviderEntitlements: [.searchAPI]
        )
        let validation = ServerProviderEnvelopeValidator.validate(envelope)
        XCTAssertTrue(validation.isAllowed)
        return ServerProviderDryRunPresentationProjector.project(
            ServerProviderDryRunEvaluator.evaluate(
                capabilityLabel: "Public search",
                requiredFreshness: .livePreferred,
                candidates: [
                    ServerProviderDryRunCandidate(
                        id: "search-api",
                        displayName: "Search API",
                        result: .executable(envelope: envelope, validation: validation)
                    ),
                ]
            )
        )
    }

