    private func searchAPIVendorPolicyAcceptedDecision(
        vendorID: String,
        costClass: ProviderCostClass = .meteredPremium,
        freshness: ProviderFreshness = .livePreferred,
        quotaSnapshot: ServerProviderQuotaSnapshot? = nil
    ) -> ServerProviderSearchAPIVendorPolicyDecision {
        let decision = ServerProviderSearchAPIVendorPolicy.evaluate(
            context: searchAPIVendorPolicyContext(
                costClass: costClass,
                freshness: freshness,
                quotaSnapshot: quotaSnapshot
                    ?? searchAPIVendorPolicyMeteredQuotaSnapshot()
            ),
            vendor: searchAPIVendorPolicyDescriptor(
                id: vendorID,
                costClass: costClass,
                supportedFreshness: [.cachedOK, .livePreferred, .liveRequired]
            )
        )
        XCTAssertEqual(decision.state, .accepted)
        XCTAssertNil(decision.rejection)
        return decision
    }

    private func searchAPIVendorPolicyRejectedDecision(
        vendorID: String,
        context: ServerProviderSearchAPIVendorPolicyContext? = nil,
        vendor: ServerProviderSearchAPIVendorPolicyDescriptor? = nil
    ) -> ServerProviderSearchAPIVendorPolicyDecision {
        let decision = ServerProviderSearchAPIVendorPolicy.evaluate(
            context: context ?? searchAPIVendorPolicyContext(),
            vendor: vendor ?? searchAPIVendorPolicyDescriptor(id: vendorID)
        )
        XCTAssertEqual(decision.state, .rejected)
        XCTAssertNotNil(decision.rejection)
        return decision
    }

