    private func searchAPIVendorDispatchAuthorizationAccepted(
        traceID: String,
        vendorID: String,
        costClass: ProviderCostClass = .meteredPremium,
        freshness: ProviderFreshness = .livePreferred
    ) throws -> ServerProviderSearchAPIVendorPolicyDispatchAuthorization {
        let dispatchReceipt = try searchAPIAdapterPayloadDispatchEligibleReceipt(
            traceID: traceID,
            sourceHost: "\(traceID).example.com",
            costClass: costClass,
            freshness: freshness
        )
        let authorization = ServerProviderSearchAPIVendorPolicyDispatchAuthorizationGate.authorize(
            dispatchReceipt: dispatchReceipt,
            vendorDecision: searchAPIVendorPolicyAcceptedDecision(
                vendorID: vendorID,
                costClass: costClass,
                freshness: freshness,
                quotaSnapshot: searchAPIVendorDispatchAuthorizationQuotaSnapshot(
                    for: costClass
                )
            ),
            requestedResultShape: .organicLinks
        )

        XCTAssertEqual(authorization.state, .authorized)
        XCTAssertNil(authorization.rejection)
        return authorization
    }

    private func searchAPIVendorDispatchAuthorizationDispatchBlocked(
        traceID: String,
        vendorID: String
    ) throws -> ServerProviderSearchAPIVendorPolicyDispatchAuthorization {
        let authorization = ServerProviderSearchAPIVendorPolicyDispatchAuthorizationGate.authorize(
            dispatchReceipt: try searchAPIAdapterPayloadDispatchBlockedReceipt(traceID: traceID),
            vendorDecision: searchAPIVendorPolicyAcceptedDecision(vendorID: vendorID),
            requestedResultShape: .organicLinks
        )

        XCTAssertEqual(authorization.state, .rejected)
        XCTAssertEqual(authorization.rejection, .dispatchNotEligible)
        return authorization
    }

    private func searchAPIVendorDispatchAuthorizationVendorBlocked(
        traceID: String,
        vendorID: String
    ) throws -> ServerProviderSearchAPIVendorPolicyDispatchAuthorization {
        let authorization = ServerProviderSearchAPIVendorPolicyDispatchAuthorizationGate.authorize(
            dispatchReceipt: try searchAPIAdapterPayloadDispatchEligibleReceipt(
                traceID: traceID,
                sourceHost: "\(traceID).example.com"
            ),
            vendorDecision: searchAPIVendorPolicyRejectedDecision(
                vendorID: vendorID,
                context: searchAPIVendorPolicyContext(privacyClass: .private),
                vendor: searchAPIVendorPolicyDescriptor(id: vendorID)
            ),
            requestedResultShape: .organicLinks
        )

        XCTAssertEqual(authorization.state, .rejected)
        XCTAssertEqual(authorization.rejection, .vendorPolicyNotAccepted)
        return authorization
    }

    private func searchAPIVendorDispatchAuthorizationQuotaSnapshot(
        for costClass: ProviderCostClass
    ) -> ServerProviderQuotaSnapshot? {
        switch costClass {
        case .includedQuota:
            return searchAPIVendorPolicyIncludedQuotaSnapshot(remaining: 2)
        case .meteredPremium:
            return searchAPIVendorPolicyMeteredQuotaSnapshot()
        case .freeLocal, .blockedByCost, .blockedByPrivacy, .blockedByTerms:
            return nil
        }
    }

    // A119 keeps metered entitlement handoff tests value-only: helpers below
    // build A117 decisions and avoid purchases, transport, or provider execution.
    private func meteredEntitlementAcceptedDecision(
        id: String,
        costClass: ProviderCostClass = .meteredPremium,
        estimatedUnits: Int = 8,
        remainingUnits: Int = 80,
        reservedUnits: Int = 8,
        freshness: ProviderFreshness = .livePreferred
    ) -> ServerProviderMeteredUsageDecision {
        meteredEntitlementAcceptedDecision(
            id: id,
            request: meteredEntitlementUsageRequest(
                id: id,
                estimatedUnits: estimatedUnits,
                costClass: costClass,
                freshness: freshness
            ),
            snapshot: meteredEntitlementSnapshot(
                id: "\(id)-snapshot",
                costClass: costClass,
                reservedUnits: reservedUnits,
                remainingUnits: remainingUnits
            )
        )
    }

    private func meteredEntitlementAcceptedDecision(
        id: String,
        request: ServerProviderMeteredUsageRequest,
        snapshot: ServerProviderMeteredEntitlementSnapshot
    ) -> ServerProviderMeteredUsageDecision {
        let decision = ServerProviderMeteredEntitlementLedger.evaluate(
            request: request,
            snapshot: snapshot,
            now: meteredEntitlementNow()
        )

        XCTAssertTrue(decision.isAccepted, id)
        XCTAssertNil(decision.denialReason, id)
        return decision
    }

    private func meteredEntitlementRejectedDecision(
        request: ServerProviderMeteredUsageRequest,
        snapshot: ServerProviderMeteredEntitlementSnapshot? = nil,
        expectedReason: ServerProviderMeteredUsageDenialReason
    ) -> ServerProviderMeteredUsageDecision {
        let decision = ServerProviderMeteredEntitlementLedger.evaluate(
            request: request,
            snapshot: snapshot ?? meteredEntitlementSnapshot(),
            now: meteredEntitlementNow()
        )

        XCTAssertEqual(decision.state, .rejected, request.id)
        XCTAssertEqual(decision.denialReason, expectedReason, request.id)
        return decision
    }

