    private func searchAPIAdapterPreparedRequestDecision(
        traceID: String,
        sourceHost: String,
        costClass: ProviderCostClass = .meteredPremium,
        freshness: ProviderFreshness = .livePreferred
    ) throws -> ServerProviderSearchAPIAdapterRequestDecision {
        let decision = ServerProviderSearchAPIAdapterContract.prepareRequest(
            envelope: searchAPIAdapterEnvelope(
                traceID: traceID,
                costClass: costClass,
                freshness: freshness,
                sourceHost: sourceHost
            ),
            connectorReceipt: searchAPIAdapterConnectorReceipt(
                traceID: traceID,
                costClass: costClass,
                freshness: freshness
            ),
            query: ServerProviderSearchAPIAdapterQuery(text: "public coffee"),
            resultLimit: 4
        )
        XCTAssertEqual(decision.state, .requestPrepared)
        XCTAssertNotNil(decision.request)
        return decision
    }

    private func searchAPIAdapterResultReceipt(
        traceID: String,
        sourceHost: String,
        freshness: ProviderFreshness = .livePreferred,
        requestFreshness: ProviderFreshness? = nil,
        title: String = "Coffee options",
        snippet: String = "Public summary with cited source metadata.",
        limitations: [String] = ["Read-only public information."]
    ) throws -> ServerProviderSearchAPIAdapterResultReceipt {
        let request = try XCTUnwrap(
            searchAPIAdapterPreparedRequestDecision(
                traceID: traceID,
                sourceHost: sourceHost,
                freshness: requestFreshness ?? freshness
            ).request
        )
        let receipt = ServerProviderSearchAPIAdapterContract.normalizeResult(
            request: request,
            candidate: ServerProviderSearchAPIAdapterResultCandidate(
                title: title,
                snippet: snippet,
                freshness: freshness,
                citations: [
                    ServerProviderSearchAPIAdapterCitation(
                        sourceURL: try searchAPIAdapterCitationURL(
                            sourceHost: sourceHost
                        ),
                        title: "Coffee source",
                        attribution: "Public Source"
                    ),
                ],
                limitations: limitations
            )
        )
        return receipt
    }

    private func searchAPIAdapterCitationURL(
        sourceHost: String
    ) throws -> URL {
        var components = URLComponents()
        components.scheme = "https"
        components.host = sourceHost
        components.path = "/coffee"
        return try XCTUnwrap(components.url)
    }

    private func searchAPIAdapterRejectedResultReceipt(
        traceID: String,
        sourceHost: String
    ) throws -> ServerProviderSearchAPIAdapterResultReceipt {
        let request = try XCTUnwrap(
            searchAPIAdapterPreparedRequestDecision(
                traceID: traceID,
                sourceHost: sourceHost
            ).request
        )
        let receipt = ServerProviderSearchAPIAdapterContract.normalizeResult(
            request: request,
            candidate: ServerProviderSearchAPIAdapterResultCandidate(
                title: "Coffee options",
                snippet: "Public summary.",
                freshness: .livePreferred,
                citations: []
            )
        )
        XCTAssertEqual(receipt.state, .rejected)
        XCTAssertEqual(receipt.rejection, .resultCitationMissing)
        return receipt
    }

