        traceID: String,
        costClass: ProviderCostClass = .meteredPremium,
        freshness: ProviderFreshness = .livePreferred
    ) -> ServerProviderSearchAPIAdapterPayloadDispatchReceipt {
        ServerProviderSearchAPIAdapterPayloadDispatchReceipt(
            id: "\(traceID)-dispatch",
            state: .dispatchEligible,
            statusLine: "Search API adapter dispatch-ready metadata is verified for future transport gating only. No transport or provider runtime has run.",
            payloadDecisionID: "\(traceID)-payload-decision",
            payloadID: "\(traceID)-payload",
            requestID: "\(traceID)-request",
            traceID: traceID,
            providerFamily: .searchAPI,
            capability: .webSearch,
            freshness: freshness,
            costClass: costClass,
            resultLimit: 4,
            sourcePolicy: ServerProviderSearchAPIAdapterSourcePolicySnapshot(
                sourcePolicy: ServerSourcePolicy(
                    sourceState: .passed,
                    robotsState: .notApplicable,
