                ),
                citationRequired: true
            ),
            rejection: nil,
            payloadDecisionRejection: nil,
            requestDecisionRejection: nil
        )
    }

    private func searchAPIAdapterPayloadDispatchEligibleReceipt(
        traceID: String,
        sourceHost: String,
        costClass: ProviderCostClass = .meteredPremium,
        freshness: ProviderFreshness = .livePreferred
    ) throws -> ServerProviderSearchAPIAdapterPayloadDispatchReceipt {
        let request = try XCTUnwrap(
            searchAPIAdapterPreparedRequestDecision(
                traceID: traceID,
                sourceHost: sourceHost,
                costClass: costClass,
                freshness: freshness
            ).request
        )
        let payloadDecision = ServerProviderSearchAPIAdapterPayloadBuilder.build(from: request)
        let receipt = ServerProviderSearchAPIAdapterPayloadDispatchGate.evaluate(
            payloadDecision: payloadDecision,
            request: request
        )

        XCTAssertEqual(payloadDecision.state, .payloadPrepared)
        XCTAssertEqual(receipt.state, .dispatchEligible)
        XCTAssertTrue(receipt.isDispatchEligible)
        return receipt
    }

    private func searchAPIAdapterPayloadDispatchBlockedReceipt(
        traceID: String
    ) throws -> ServerProviderSearchAPIAdapterPayloadDispatchReceipt {
        let request = try XCTUnwrap(
            searchAPIAdapterPreparedRequestDecision(
                traceID: "\(traceID)-baseline",
                sourceHost: "dispatch-blocked-baseline.example.com"
            ).request
        )
        let rejectedPayloadDecision = ServerProviderSearchAPIAdapterPayloadBuilder.build(
            from: ServerProviderSearchAPIAdapterContract.prepareRequest(
                envelope: searchAPIAdapterEnvelope(
                    traceID: traceID,
                    privacyClass: .private,
                    sourceHost: "dispatch-private.example.com"
                ),
                connectorReceipt: searchAPIAdapterConnectorReceipt(
                    traceID: traceID
                ),
                query: ServerProviderSearchAPIAdapterQuery(text: "public coffee")
            )
        )
        let receipt = ServerProviderSearchAPIAdapterPayloadDispatchGate.evaluate(
            payloadDecision: rejectedPayloadDecision,
            request: request
        )

        XCTAssertEqual(rejectedPayloadDecision.state, .rejected)
        XCTAssertEqual(rejectedPayloadDecision.rejection, .requestDecisionRejected)
        XCTAssertEqual(rejectedPayloadDecision.requestDecisionRejection, .privacyBlocked)
        XCTAssertEqual(receipt.state, .blocked)
        XCTAssertFalse(receipt.isDispatchEligible)
        return receipt
    }

    private func searchAPIAdapterFixtureBridgeReadyResponse(
        traceID: String,
        sourceHost: String,
        costClass: ProviderCostClass = .meteredPremium,
        freshness: ProviderFreshness = .livePreferred
    ) throws -> ServerProviderSearchAPIAdapterFixtureTransportBridgeResponse {
        let requestDecision = try searchAPIAdapterPreparedRequestDecision(
            traceID: traceID,
            sourceHost: sourceHost,
            costClass: costClass,
            freshness: freshness
        )
        let request = try XCTUnwrap(requestDecision.request)
        let payloadDecision = ServerProviderSearchAPIAdapterPayloadBuilder.build(
            from: requestDecision
        )
        let dispatchReceipt = ServerProviderSearchAPIAdapterPayloadDispatchGate.evaluate(
            payloadDecision: payloadDecision,
            request: request
        )
        let response = ServerProviderSearchAPIAdapterFixtureTransportBridge.evaluate(
            requestDecision: requestDecision,
            payloadDecision: payloadDecision,
            dispatchReceipt: dispatchReceipt
        )

        XCTAssertEqual(payloadDecision.state, .payloadPrepared)
        XCTAssertEqual(dispatchReceipt.state, .dispatchEligible)
        XCTAssertEqual(response.state, .fixtureReady)
        XCTAssertTrue(response.isFixtureReady)
        return response
    }

    private func searchAPIAdapterFixtureBridgeRejectedPrivateResponse(
        traceID: String
    ) throws -> ServerProviderSearchAPIAdapterFixtureTransportBridgeResponse {
        let baselineDecision = try searchAPIAdapterPreparedRequestDecision(
            traceID: "\(traceID)-baseline",
            sourceHost: "fixture-rejected-baseline.example.com"
        )
        let request = try XCTUnwrap(baselineDecision.request)
        let payloadDecision = ServerProviderSearchAPIAdapterPayloadBuilder.build(
            from: baselineDecision
        )
        let dispatchReceipt = ServerProviderSearchAPIAdapterPayloadDispatchGate.evaluate(
            payloadDecision: payloadDecision,
            request: request
        )
        let rejectedRequestDecision = ServerProviderSearchAPIAdapterContract.prepareRequest(
            envelope: searchAPIAdapterEnvelope(
                traceID: traceID,
                privacyClass: .private,
                sourceHost: "fixture-private.example.com"
            ),
            connectorReceipt: searchAPIAdapterConnectorReceipt(
                traceID: traceID
            ),
            query: ServerProviderSearchAPIAdapterQuery(text: "public coffee")
        )
        let response = ServerProviderSearchAPIAdapterFixtureTransportBridge.evaluate(
            requestDecision: rejectedRequestDecision,
            payloadDecision: payloadDecision,
            dispatchReceipt: dispatchReceipt
        )

        XCTAssertEqual(payloadDecision.state, .payloadPrepared)
        XCTAssertEqual(dispatchReceipt.state, .dispatchEligible)
        XCTAssertEqual(rejectedRequestDecision.state, .rejected)
        XCTAssertEqual(rejectedRequestDecision.rejection, .privacyBlocked)
        XCTAssertEqual(response.state, .rejected)
        XCTAssertEqual(response.rejection, .requestDecisionRejected)
        XCTAssertEqual(response.requestDecisionRejection, .privacyBlocked)
        return response
    }

