// MARK: - Test double

/// Local spy for AppBootstrap composition tests. Class identity is used
/// to verify the bootstrap stores the exact instance the caller passed
/// in (see `test_customRuntime_isStoredOnBootstrap`). A separate spy
/// type lives in `RecommendationRailIntegrationTests`; that one is
/// fileprivate, so this file declares its own to avoid coupling.
@MainActor
private final class SpyFeedbackRuntimeForBootstrap: FeedbackRuntime {
    var emittedEvents: [FeedbackEvent] = []

    func emit(_ event: FeedbackEvent) async throws {
        emittedEvents.append(event)
    }
}

/// Local spy for the `CompletedRecommendationHandoff` composition tests.
/// Same reasoning as `SpyFeedbackRuntimeForBootstrap`: a separate spy
/// lives in `RecommendationRailIntegrationTests` (fileprivate), so this
/// file declares its own to keep test files independent.
@MainActor
private final class SpyCompletedRecommendationHandoffForBootstrap:
    CompletedRecommendationHandoff
{
    var recordedRecommendations: [MatchingObject] = []

    func record(_ recommendation: MatchingObject) {
        recordedRecommendations.append(recommendation)
    }
}

private final class SpyRecommendationProviderForBootstrap: RecommendationProvider {
    private let matches: [MatchingObject]

    init(matches: [MatchingObject]) {
        self.matches = matches
    }

    func recommendedMatches() -> [MatchingObject] {
        matches
    }
}

private final class SpyProviderStatusProviderForBootstrap: ProviderStatusProviding {
    private let presentationsByRecommendationID: [String: ProviderStatusPresentation]

    init(
        presentationsByRecommendationID: [String: ProviderStatusPresentation] = [:]
    ) {
        self.presentationsByRecommendationID = presentationsByRecommendationID
    }

    func providerStatusPresentation(
        for recommendationID: String
    ) -> ProviderStatusPresentation? {
        presentationsByRecommendationID[recommendationID]
    }
}

private struct TrapServerProviderRuntimeAdapterForBootstrap: ServerProviderRuntimeAdapter {
    let providerFamily: ProviderFamily

    func resolve(
        _ boundary: ServerProviderRuntimeDispatchBoundary
    ) -> ServerProviderRuntimeAdapterResult {
        XCTFail("App-root handoff must not resolve rejected injected adapters.")
        return FixtureServerProviderRuntimeAdapter(providerFamily: providerFamily)
            .resolve(boundary)
    }
}

private struct SourceMarkingServerProviderRuntimeAdapterForBootstrap:
    ServerProviderRuntimeAdapter
{
    let providerFamily: ProviderFamily
    let marker: String

    func resolve(
        _ boundary: ServerProviderRuntimeDispatchBoundary
    ) -> ServerProviderRuntimeAdapterResult {
        let result = FixtureServerProviderRuntimeAdapter(providerFamily: providerFamily)
            .resolve(boundary)
        guard result.state == .acceptedFixture else {
            return result
        }
        return ServerProviderRuntimeAdapterResult(
            id: "\(marker)-\(result.id)",
            state: result.state,
            statusLine: result.statusLine,
            boundaryID: result.boundaryID,
            planID: result.planID,
            traceID: result.traceID,
            providerFamily: result.providerFamily,
            capability: result.capability,
            descriptorID: result.descriptorID,
            costClass: result.costClass,
            freshness: result.freshness,
            sourcePolicy: markedSourcePolicy(result.sourcePolicy),
            confirmationState: result.confirmationState,
            audit: result.audit
        )
    }

    private func markedSourcePolicy(
        _ policy: ServerSourcePolicy?
    ) -> ServerSourcePolicy? {
        guard let policy else {
            return nil
        }
        return ServerSourcePolicy(
            sourceState: policy.sourceState,
            robotsState: policy.robotsState,
            attributionRequired: policy.attributionRequired,
            sourceHost: marker
        )
    }
}
